const PARK_REVIEWS_ZH = {
  "yellowstone": [
    {name:"Sherry R",rating:5,text:"我的心已留在黄石！这里是心灵的疗愈之所。\"描述了一次12天的行程，包括大提顿和怀俄明州科迪市，建议至少游览一周，并推荐参加导游团和使用观察望远镜观看野生动物。"},
    {name:"Bill L",rating:3,text:"老忠实喷泉历史悠久，大棱镜温泉令人叹为观止。公园交通却极为拥堵……这简直让我们一天的游兴荡然无存。"},
    {name:"GeorgiaTravelers51",rating:2,text:"和许多国家公园一样，黄石在夏季已经人满为患，无法尽情享受……极度的人潮和交通拥堵使我们根本无法欣赏主要景点。"},
    {name:"Barry S",rating:1,text:"从西门到老忠实喷泉的交通极度拥堵……公园目前的状态根本无法承受如此大量的车辆涌入。"},
  ],
  "yosemite": [
    {name:"SMECM",rating:5,text:"我们非常享受约塞米蒂的一切。我们在暴风雪过后的火瀑季节到访。护林员非常友善且乐于助人。别忘了多次造访瀑布，因为它们时刻都在变化。"},
    {name:"Toblje",rating:4,text:"国家公园内的住宿非常昂贵且品质一般。在公园外可以找到更便宜、更好的住宿选择，但路程较远。根据住宿地点不同，需预留一到一个半小时的车程。"},
    {"name":"DisappointedHiker","rating":2,"text":"约塞米蒂谷在夏季绝对是人山人海。我们光是进入公园就堵了2个小时。各个登山口附近完全找不到停车位。摆渡车挤得像地铁一样。美丽的公园被过度拥挤和毫无秩序的人流管理彻底毁掉了。"},
    {"name":"Camper320","rating":1,"text":"近年来我们去过许多\"大\"国家公园，约塞米蒂在各方面都是最差的，我们再也不会回去了。到处都在修路，任何主要景点（瀑布、巨型红杉等）附近都没有停车位。当我试图带小孩子去看巨型红杉时，发现道路封闭。公园\"护林员\"（非常年轻，像十几岁的青少年）粗鲁无礼地告诉我们必须停车等待摆渡车，因为那里没有停车位。我们等了半小时的摆渡车。到达时，车已经满了，只好等下一班。下一班也几乎满员，但我们还是挤上去了，不得不和其他人一起站着挤在一起。看完树后，又等了半小时的回程摆渡车。摆渡车到来时，人们相互推搡，我甚至担心孩子的安全……人们争抢位置简直不顾一切。所有人都经历了一次糟糕的体验。如果您想要一次真正美好的国家公园体验，请去黄石吧。"},
    {"name":"Gunnerjz","rating":2,"text":"就是一堆树。绝对不需要在那里待超过一天。护林员毫无帮助，不要指望他们告诉你哪棵树或哪块岩石最值得看。如果你选择跳过，也不用觉得错过了什么。主要就是漫长的徒步、岩石和树木。"}],
  "grand-canyon": [
    {name:"Tianxingzhe",rating:5,text:"照片和视频都无法呈现亲身体验的震撼。推荐游览光明天使小径和南卡伊巴布小径。南缘是一个真正令人叹为观止的好去处。"},
    {name:"HighlandLass24",rating:5,text:"当然值得一去。这里真的令人叹为观止。亲眼目睹绝对值得，即便拍不出Instagram级别的照片。"},
    {"name":"sflbib","rating":1,"text":"火车正午到达峡谷边缘，下午4点离开——这只留给游客3个小时的观光时间。洗手间少之又少、距离遥远且难以找到，因为地图上根本没有标注。他们告诉你火车下午4点出发，却浪费所有乘客的时间等待落单的游客。每当有外地朋友想看峡谷，我都会婉言拒绝陪同。峡谷本身壮观无比，但整个游客体验周边管理混乱、令人沮丧得完全没有必要。"},
    {"name":"Michael_W","rating":2,"text":"大峡谷IMAX电影讲的不是大峡谷本身，而是关于人的故事，所以你得不到任何关于步道或地标的信息，坦白说根本不值票价。南缘的人潮令人窒息。村子里挤满了游客，一边吃冰淇淋，一边无视禁止喂食野生动物的告示。峡谷本身美丽，但游客管理十分糟糕。"}],
  "zion": [
    {name:"Holly C",rating:5,text:"这次旅行绝对令人惊叹。狭缝峡谷徒步之旅不容错过。强烈建议租用水上徒步靴、涉水裤和徒步杖（60美元）。"},
    {name:"Sherry T",rating:5,text:"我们采纳了建议，在八月的一个周六早上7:30就赶上了摆渡车——绝对是明智之举！没有排队，那么早也不需要公园通行证。"},
    {name:"BrakiWorldTraveler",rating:4,text:"锡安国家公园是另一个令人惊叹的公园，但在前一天游览布莱斯之后，它给我们的印象相对较弱。"},
    {name:"samdogNY",rating:5,text:"锡安公园雄伟壮观。我们曾担心八月份的酷热和人潮。正如许多人所说——早起早出发。"},
  ],
  "glacier": [
    {name:"Ash & Jon (Elevateverything)",rating:5,text:"我们去过许多国家公园，这是我们最爱的一个！太阳之路上所有年龄层都能欣赏到的壮丽景色，加上从轻松到挑战性不等的徒步机会，无与伦比！"},
    {"name":"FrustratedVisitor22","rating":2,"text":"太阳之路七月份到访时因施工封闭——网站上没有任何警告。我们开了6小时的车，结果基本只能看半个公园。车辆预约系统令人困惑，门票提前数月就售罄。公园管理处的信息沟通非常糟糕。"},
    {"name":"717wangy","rating":1,"text":"太阳之路的通行证根本买不到！！！而且我们在出行前两天才开始碰运气，这给我们带来了巨大的压力。我们最终放弃，取消了前往冰川国家公园的行程。结果，我们还因此损失了酒店40%的押金，因为酒店规定一周内取消须支付总费用40%的罚款。订票系统简直是一种耻辱。让人们安排好行程，却在出发前或到达之后才发现根本无法进入公园，这种做法令人痛心。提前更长时间告知人们能否购票，以便他们合理规划行程，难道有那么难吗？这是纳税人缴税建设的国家公园，但作为纳税人，我完全感受不到政策制定者有考虑我们的需求和福祉。我在网上看到了大量关于这个问题的投诉。我们过去一直很喜欢游览国家公园，从未见过对某个国家公园设施有如此强烈的抱怨声浪。"}],
  "great-smoky": [
    {name:"Sandrita",rating:5,text:"绝对令人叹为观止！这是我第一次游览国家公园，它为我对其余62个公园的期望树立了极高的标杆。"},
    {name:"Alejandro C",rating:5,text:"我们在2025年感恩节期间带着两个孩子（11岁和8岁）住在加特林堡，游览了大烟山国家公园，这次经历绝对令人难忘。"},
    {name:"Sierra D",rating:4,text:"大烟山国家公园的景色非常美丽！尽管公园内最新的道路封闭令人失望，但我们充分利用了一日游的时间，这里有很多值得一看的东西！"},
    {name:"Tammy P",rating:5,text:"这是一次美妙的旅行！先说几点不足：第一，通往切罗基的道路因山体滑坡封闭；第二，通往月桂瀑布的步道封闭至2026年秋季进行维修。"},
  ],
  "rocky-mountain": [
    {name:"Jerri L",rating:5,text:"这个国家公园绝对令人惊叹！我们很早就进入公园，从大湖入口驾车进入。这个入口似乎人流较少，交通更为顺畅。我们在每一个观景台都停了下来，欣赏到了壮美的景色。"},
    {name:"Don J",rating:3,text:"雷尼尔山是个美妙的地方，但现在游客过多，不堪重负。和许多国家公园一样，雷尼尔山正在被人们的过度热爱所摧毁。（注：这位评论者的语言同样适用于落基山国家公园，这是该公园评论页面上常见的呼声……）"},
    {"name":"leahcW4014FM","rating":1,"text":"我驾车345英里前往落基山。我有定时通行证，但没有在规定时间到达。下午5点，我和孩子们被允许进入，但随后开始下雨，我们不得不离开。第二天早上，我向护林员解释了情况，她让我下午5点再来，尽管我持有国家公园通行证。公园占地415英里，山脉绵延。我无法想象游客相互碰撞，这就是新冠疫情期间实行定时入场的原因。我们始终未能游览公园。我和孩子们不会再回来了。落基山国家公园正在被当作政治棋子。没有其他国家公园会拒绝入场。真是令人惋惜！"}],
  "acadia": [
    {name:"Eileen19",rating:5,text:"这个公园太美了。考虑到它是最小的国家公园之一，其环境的多样性令我印象深刻。这里有沙滩、崎岖的岩石海岸、悬崖、山脉、森林、沼泽、河流、湖泊和瀑布。"},
    {name:"SeniorTravelerTF",rating:4,text:"作为国家公园爱好者，无法给出5分令人痛心，但很难将阿卡迪亚的体验与巴港市（及其他城镇）分开。两者都很有趣，两者都很拥挤。"},
  ],
  "grand-teton": [
    {name:"Edward Q",rating:5,text:"大提顿国家公园是一个令人叹为观止的地方。这段经历将是我余生难以忘怀的记忆。"},
    {name:"Eric E",rating:5,text:"大提顿给我的震撼超出了预期！公园内大约95%的道路都能看到提顿山脉的美景。"},
    {name:"Craig S",rating:5,text:"这个公园和黄石一样非常繁忙。游览珍妮湖务必趁早，否则将多步行一英里。"},
    {name:"Charles S",rating:5,text:"我们把最好的留到了最后……这是一次奇妙的旅程，拍摄了许多精彩的照片，其中一张是如此出色，我妻子的照片被当地摄影俱乐部评选为\"年度最佳照片\"！"},
    {name:"[Parkscollecting.com compiled]",rating:1,text:"这个国家公园没有什么特别之处，我们认为没有任何令人惊叹的亮点。许多步道已经破损，而且蚊虫肆虐。除了三座提顿山峰的景色外，没有任何吸引人的风光。"},
  ],
  "joshua-tree": [
    {name:"Sarah M",rating:5,text:"约书亚树国家公园美得令人叹为观止！我非常喜欢探索隐谷和基斯观景台等地——景色令人窒息。一定要提前下载导览，因为到达后可离线使用。"},
    {name:"JoeFRocklin",rating:5,text:"即使在一个阴沉多雾的一月清晨，来这里依然值得。如果天气允许，有许多徒步路线可供选择，从简单到富有挑战性不等。在炎热或天气不佳的日子里，也可以轻松地驾车游览公园。"},
    {"name":"allifromWI","rating":2,"text":"这远不是我最喜欢的国家公园。约书亚树是独一无二的——其他地方看不到，所以如果想亲眼看看，这里是唯一的去处。不过，我们在淡季前往，即便如此，入场排队也要15-20分钟。任何登山口都没有足够的停车位，而且几乎没有洗手间。危险的是，公园内没有饮用水，而且大部分区域没有手机信号。这两者的组合非常糟糕。我知道在野外这两者都难以解决，但我在其他国家公园见过有人做到了。体验还可以，但我不觉得有必要再去一次。"}],
  "arches": [
    {name:"jbg74",rating:5,text:"拱门国家公园绝对值得一游。一天内就能看到主要亮点，但多待一两天才能真正体验整个公园。我在园内最喜欢的拱门是双拱门。"},
    {name:"[Parkscollecting.com compiled]",rating:1,text:"这个地方毫无价值。不过是岩石上的几个洞。不明白有什么大不了的。两个拱门都不是我们预期的样子。"},
  ],
  "olympic": [
    {name:"DannyWasserman",rating:5,text:"我们游览了华盛顿州所有的国家公园，奥林匹克国家公园是继雷尼尔山之后的第二站。这是一片美丽的地方，不容错过。我们尽情享受了山地、徒步、瀑布以及更多精彩。"},
    {name:"[Parkscollecting.com compiled]",rating:1,text:"我觉得这里并没有什么了不起的，就是另一片普通的森林。除了一些悬挂的苔藓和虫子之外，和其他森林没什么区别。就别去了，完全不值得。我们花了30美元开进这条路，结果什么也没看到，只有云雾。"},
  ],
  "bryce-canyon": [
    {name:"Kate S",rating:5,text:"这是我最喜欢的国家公园之一，因为其美丽令人叹为观止——石笋林、红岩、松树。皇后花园步道（根据你爬上之字形山路的速度，需1-2小时，未铺装路面，中等难度）是一大亮点。"},
    {name:"Marshall B",rating:5,text:"这个公园壮观到难以言表，尤其是在地面还残留积雪的时候。我们在大多数停车区停下欣赏景色，从头到尾大约花了两个半小时。"},
    {name:"Kurt H",rating:5,text:"布莱斯峡谷永远令人着迷，我们百看不厌。这次我们一月份到访，确实需要穿好冬装。积雪为记忆和照片增添了美丽的视觉元素。"},
    {name:"Daniele_Gorizia",rating:5,text:"对我们而言，这是西部行程中游览过的最美丽的公园之一。岩石地貌经过数千年的风化，形成了被称为\"石笋\"的独特尖顶形状。"},
    {name:"[Parkscollecting.com compiled]",rating:1,text:"这绝对是最无聊的公园之一。只有路过时才值得顺道一访。徒步路线有些平淡，风景也不怎么样。都是一样的石笋，只是角度略有不同。"},
  ],
  "death-valley": [
    {"name":"Penille_Juel_Y","rating":2,"text":"我们从拉斯维加斯途经死亡谷国家公园前往红杉国家公园。死亡谷极度炎热，几乎不想下车；公园完全可以坐在车里游览。当然，最初的景色令人叹为观止，但很容易觉得乏味，每个观景台看起来都大同小异。我们去过锡安和大峡谷，那些地方的体验令人叹为观止、景点众多，但与其他国家公园相比，死亡谷不过是一片沙地，而门票价格却和其他公园一样贵。"}],
  "denali": [
    {name:"hms917",rating:5,text:"这是我们此行的重头戏，我们乘坐了绿色班车。我们看到了麋鹿、豪猪、棕熊、狐狸、雷鸟、达尔羊和大量的驯鹿。这是一次史诗级的几天旅程。"},
    {name:"Colleen C",rating:5,text:"我们在德纳里地区待了几天，公园令人叹为观止！我们两天都能看到德纳里山峰。我们还了解到，自己属于幸运的5%——那些看到过晴空无云的德纳里山峰的人，那景色真是壮观！"},
    {name:"F L Eveline",rating:4,text:"公园非常美丽。马蹄湖步道是一大亮点，我们近距离看到了一头麋鹿正在湖边饮水。非常希望有一天能回来，深入公园内部探索。"},
  ],
  "mount-rainier": [
    {name:"Robert B",rating:5,text:"我们在雷尼尔山国家公园度过了美妙的一天。起初我们有些担心天气不配合，但最终我们享受到了山峰和公园其他部分的绝美景色。我们实际上驾车穿越了云层！"},
    {name:"Don J",rating:3,text:"雷尼尔山是个美妙的地方，但现在游客过多，不堪重负。和许多国家公园一样，雷尼尔山正在被人们的过度热爱所摧毁。"},
    {name:"[Parkscollecting.com compiled]",rating:1,text:"就像一块鲜美的牛排被摆在垃圾桶盖子上。花30美元开车上山30分钟，然后几乎所有东西都关闭了。完全是一招鲜。我们在天堂点因浓雾根本看不到山峰。"},
  ],
  "sequoia": [
    {name:"Adam J",rating:5,text:"值得前往扎营或驾驶房车游览。我们住在洛奇波尔营地，这是一个非常安静的区域，有很多鹿和花栗鼠。值得一看巨型红杉。"},
    {name:"Miguel Quintanilla",rating:5,text:"这是一个出色的公园，有许多景点和路线可供游览，标识也非常完善。由于某些区域停车位相当有限，在公园内自驾游颇为不便。"},
    {name:"Christian P",rating:5,text:"太棒了，绝对必看。只需注意：这条路有些难走，驾驶时必须非常小心。建议穿短裤和舒适的步行鞋，因为要走很多路。"},
  ],
  "everglades": [
    {name:"Tina",rating:5,text:"在导游带领的电车游览中，我们可以看到许多鸟类、短吻鳄和乌龟。作为小提示，请务必使用防蚊喷雾，那些小吸血鬼无处不在。"},
    {name:"William B",rating:5,text:"这是我大约18年来的第二次到访。夕阳西下时，佛罗里达湾的景色令人叹为观止。门票35美元，可使用6天。从霍姆斯特德入口到道路尽头的弗拉明戈，全程38英里。"},
  ],
  "shenandoah": [
    {name:"Zeec201457",rating:5,text:"我们驾车游览了天际线大道，景色令人叹为观止。记得带上食物，因为公园内购买食物的地方有限。游客中心有很多可做的事情，我们甚至见到了斯莫基熊。"},
    {name:"Lisa J",rating:5,text:"我们已经三次驾车穿越这个公园，刚刚在护照本上盖了章。这是一个非常美丽的公园，有许多徒步步道和观景停靠点。如果需要加油，大草地游客中心那里有加油站。"},
    {"name":"VAlocal_drive","rating":2,"text":"天际线大道基本上是一条以每小时35英里行驶的105英里测速陷阱。树木长得如此之高，以至于大多数观景台几乎看不到山谷。我们十月中旬到访时，著名的秋叶颜色斑驳且已枯黄。入场费高得离谱，结果只是一段行驶缓慢、视野有限的驾车游览。"},
    {"name":"Gabrielle M","rating":1,"text":"太离谱了。我不敢相信他们收30美元的入场费。记得以前才7美元，后来10美元，再后来20美元，现在30美元。就这短短几年间。他们在敲诈我们。太不可思议了。我以前经常去那里，但我很悲伤地看到这个美丽的空间只有富人才能进入。"},
    {"name":"Dillon M","rating":1,"text":"如果有任何下雨或起雾的可能，就不要去。我们在天气预报只有14%降雨概率、部分多云的日子进入公园，结果5分钟后就遇到了大雾和下雨，能见度不足100英尺（我们实际测量过）。我们什么都没看到，白跑一趟。"}],
  "crater-lake": [
    {name:"George A.",rating:5,text:"绝对令人叹为观止的自然景观！我去过很多美国国家公园，这里在纯粹的美丽方面名列前茅。"},
    {name:"Our Next Adventure",rating:5,text:"火山口湖真的令人难以置信……湖水是一种令人疯狂的晶莹剔透的蓝色，看起来都不像是真实的。驾车行驶33英里的湖边环路，景色令人叹为观止。"},
    {name:"carlotaTravel4fun",rating:4,text:"湖泊令人叹为观止……是的，很拥挤，无法靠近通往湖边的步道……另一个令人失望的是道路封闭。\"[好坏参半]"},
    {name:"Experience Junkies",rating:5,text:"从每一个停靠点望出去的湖景都非常壮观，但非常拥挤。我们很失望公园没有公园统一指南手册。"},
    {name:"ConfederateMike",rating:5,text:"沿克利特伍德步道向下徒步是值得付出努力的……返回顶部需要体力。建议携带水上鞋。"},
    {"name":"RoadTripFail","rating":2,"text":"我们专程绕道4小时来这里。整个湖区被大雾笼罩——什么都看不到。湖边环路部分封闭。礼品店和咖啡馆是唯一开放的地方，两者都价格偏高。入场费当然不退。完全浪费时间和金钱。"},
    {"name":"hikenbikers97","rating":1,"text":"火山口湖本身绝对是最令人叹为观止的景点！但是自从Xanterra接管管理后，我感到失望。首先，什么都很贵。其次，他们雇用的员工粗鲁且冷嘲热讽。靠近任何一位员工都会受到轻蔑的回应，尤其是那些做维修工作的人。我们向一位员工询问简单的方向，那是个大错误。他告诉我们指路不是他的工作。谢了Xanterra。"},
    {"name":"VncrCanada","rating":2,"text":"开了很长的路才到达，走过高而窄的山路，火山口湖却让人感到……平淡无奇。寒冷不稳定的天气没有帮助，使湖面波涛汹涌、灰色沉闷。湖周围干燥的火山地貌并不美丽，即使天气平静、湖水湛蓝，它仍然不是北美最壮观的景致。游船在大风疑虑的天气中出发，湖面白浪翻滚，没有雨具的游客被浪花打湿——这种天气下应该推迟游船行程。马扎马营地脏乱不堪，火坑和野餐桌周围垃圾横陈，营位间距太近，孩子们的尖叫声无处躲避。湖边环路坡度陡峭、令人胆战心惊，我们没有走完全程。总体令人失望，不会再来了。"}],
  "badlands": [
    {name:"M M",rating:5,text:"在恶地国家公园待上几天，您将创造出永生难忘的回忆。\"称赞了知识渊博的护林员和多样化的徒步选择。"},
    {name:"Melabaffi",rating:5,text:"它迷住了我！\"觉得风景令人叹为观止，欣赏了美丽的景色，并在游客中心欣赏到了鹰的身影。"},
    {name:"MikeB1952",rating:4,text:"对地质展览和野牛目击印象深刻，但指出游客中心的视频\"画质较差、灰暗且不够生动\"，影响了体验。\"[好坏参半]"},
    {name:"RetiredTravelerTN",rating:5,text:"景观质感和土壤颜色变化丰富而戏剧性\"，并建议根据光线条件选择观景时间，以获得最佳视野。"},
    {name:"Stacy H.",rating:5,text:"二月份到访，享受了较少的人潮和覆盖积雪的绝美景色，但指出当季草原犬鼠瘟疫导致无法观看野生动物。\"[好坏参半]"},
    {"name":"TexasTraveler99","rating":2,"text":"基本上就是一个30分钟的驾车穿越景点。你从路上看到那些地貌，在几个观景台停一停，然后就结束了。不值这门票费，也不值从90号州际公路绕这么大一段路。游客中心又小又没什么信息量。最多一小时就把所有东西都看完了。"},
    {"name":"LoveToTravel2510","rating":1,"text":"我们开车走了一圈，感觉没完没了。太无聊了，除了一个围起来的区域里有野牛（看来那是他们喂食的地方，所以野牛都待在那里）之外，根本没有其他动物。孩子们极度无聊，完全浪费时间。"},
    {"name":"Bebetiffanyof8","rating":1,"text":"真是难以置信。进园需要30美元，因为他们不接受在手机上扫描通行证（4年级和5年级学生免费通行证）。我们的车或房车里没有打印机，通行证就在手机上，而且我们车里明明有4年级和5年级的学生，他们都看得出来。不过里面肯定很美！"}],
  "hawaii-volcanoes": [
    {name:"Ilene",rating:5,text:"我们仔细观看了YouTube上的火山实时摄像头，耐心等待到了1月24日星期六——科学家们预测基拉韦厄火山将会爆发的那一天。\"亲眼目睹了喷涌岩浆的非凡喷发事件。"},
    {name:"Heather",rating:5,text:"这是一个很大的公园，所以务必提前规划，确保不会错过任何东西。\"提醒游客中心正在施工，建议提前规划。"},
    {name:"Good Names All Gone",rating:4,text:"我们最大的遗憾是，到访时基拉韦厄正处于间歇性喷发阶段。\"评论者遗憾地错过了活跃的岩浆喷泉，仅差一天，但仍然欣赏了蒸汽喷口和火山景观。[好坏参半]"},
    {name:"rbhogaraju",rating:5,text:"公园需要一整天的时间——有太多值得观赏和游览的内容。\"强调了郁郁葱葱的雨林与荒凉熔岩地之间的强烈对比，称其为令人敬畏的体验。"},
    {name:"Explorer43768791328",rating:4,text:"带足水！\"体验好坏参半——享受了站在火山内部的独特机会，但发现下行和上行路程有些具有挑战性。[好坏参半]"},
    {"name":"MauiMike55","rating":2,"text":"除非有活跃的喷发，否则这个公园令人大失所望。我们只看到了蒸汽喷口和一个巨大的空旷火山口。熔岩管道很酷，大概5分钟就看完了。火山口链公路在一个护栏前戛然而止，什么都看不到。花30美元入园就为了看岩石和蒸汽。省点钱吧。"},
    {"name":"Lisa L","rating":1,"text":"我们非常期待参观火山。然而，当天下雨。我们查阅网站，上面说火山仍在发光，有很多可看的东西。实际情况却从入口处就开始走样——一个油嘴滑舌的年轻收费员告诉我们，能看到什么完全取决于我们的\"态度\"。当我们提到自己是加拿大人时，他说\"哦，那你们要付双倍\"并哈哈大笑！这个开头很不好，完全不符合我期待的夏威夷精神。到达游客中心后，我们与一位正在讲述火山历史的工作人员交谈，问他火山在哪里可以看到，他说今天你们是看不到的，最好的选择是去剧场看电影。我们非常失望，转身离开了。我们在火山旁只待了五分钟。天气很糟糕，我理解公园无法控制天气，但如果在入口处就告知我们看到东西的可能性极低就好了，这样我们就可以选择不支付30美元的入场费。"}],
  "channel-islands-ca": [
    {name:"BruinDan",rating:5,text:"我们看到了几只可爱的岛屿狐狸\"和\"一大群嬉戏的海豚\"在回程中相伴，这是一段令人难忘的体验。"},
    {name:"Christine D.",rating:5,text:"这位旅行者在穿越途中遇到了鲸鱼和鲨鱼，并\"有足够的时间散步并看到小狐狸\"。"},
    {name:"Natty Park Traveler",rating:5,text:"看到了岛屿灌丛松鸦和岛屿狐狸\"，并表示遗憾没有在岛上安排更长的时间。"},
    {name:"Ry Ry",rating:5,text:"令人叹为观止的悬崖景色，\"但指出由于砾石步道，这里\"不推荐有行动不便需求的人\"前往。[好坏参半]"},
    {name:"Cohoman",rating:5,text:"尽管公园宣传狐狸很多，我只看到了一只，\"而且在徒步过程中由于遮阴不足，需要喝掉约三瓶8盎司的水。[好坏参半/偏负面]"},
    {"name":"SeasickSteve","rating":1,"text":"乘船前往圣克鲁斯岛花了一个多小时，我全程严重晕船。到达后基本上什么设施都没有——没有洗手间、没有遮阴、没有食物。徒步步道尘土飞扬且毫无遮挡。回程同样痛苦。每人80美元，换来一段令人恶心的船程，终点是一座荒芜的岛屿。"},
    {"name":"Backpacker_0905","rating":2,"text":"蝎子牧场营地的营位挨得很近，且安静时间没有被强制执行。护林员应该在天黑后巡逻。由于邻近营位有人吵闹，我几乎没怎么睡着——他们先是吵了好几个小时，然后凌晨12:30又开始，凌晨2:30又来一次……圣克鲁斯岛几乎没什么可做的。我徒步了16英里，游了个泳，才下午2:30。然后呢？"}],
  "north-cascades-wa": [
    {name:"Bellaire56",rating:5,text:"爱不释手，太美了。雨湖徒步最终到达湖边，湖面有着迷人的岩石倒影，宁静而祥和。"},
    {name:"Dana Wilson",rating:5,text:"景色绝对美丽，我们玩得非常开心……我们所见的山脉和湖泊如同明信片般美丽。"},
    {name:"Ron S.",rating:5,text:"这个公园非常特别，进入时没有人向你收费……最大的优点是人流稀少。"},
    {name:"Samona K.",rating:3,text:"我们非常期待这个公园，但有些失望……除了徒步之外没有其他可做的事情。公园本身免费，但住宿非常昂贵。\"[偏负面]"},
    {name:"Aaron Ross",rating:5,text:"这里的景色达到了另一个层次，由于冰川粉末在阳光下的折射而形成的碧绿湖水，是我从未见过的景象。"},
    {"name":"OMFG2023","rating":1,"text":"领取荒野许可证的地点在一条单车道公路上，交通状况极为糟糕！道路太窄，无法承受如此大的交通流量，周围还有小孩子四处嬉戏玩耍，看起来这是一个宁静的僻静乡村住宅区，限速先是25英里然后降至15英里，所以开到那里要花很长时间。工作人员可能友善而乐于助人，但他们对邻居却粗鲁无礼。我看到有人因为告诉一个在15限速区以50英里时速行驶的人减速——因为他孙子正在那里玩耍——而遭到罚款威胁。这是个什么公园？真想知道是哪个蠢蛋想出了这个方案。"}],
  "redwood-np-ca": [
    {name:"Great_Beer_Now",rating:5,text:"美国最伟大的自然奇观之一……给人留下其他国家公园难以企及的深刻印象。\"称赞了这些壮观的大树，并建议进行短途徒步。"},
    {name:"Kennet",rating:5,text:"完全就像走进了霍比特人的电影世界……内心如此宁静。\"评论者认为这段体验改变了人生，并计划重返。"},
    {name:"moodblu",rating:5,text:"我希望有更多关于树木和森林生态系统的信息标识。\"尽管提出了建设性意见，仍认为红杉是\"一次全新的美好体验\"，但也提到了对公园边界感到困惑。[好坏参半]"},
    {name:"Sue M.",rating:5,text:"如果只有一天时间，就从托马斯·库赫尔游客中心出发……只需在大树处停下拍照留念。\"为时间有限的游客提供了实用建议。"},
    {name:"Moath Ibrahim",rating:5,text:"这是我有生以来最棒的旅行之一！……照片完全无法呈现这些树木的宏伟壮观和令人敬畏之感。\"赞赏与约塞米蒂等拥挤公园相比，这里的宁静氛围。"},
    {"name":"CAwilderness","rating":2,"text":"公园极度分散，没有明确的中心区域。我们在狭窄蜿蜒的道路上驾车行驶了好几个小时才能到达各处树丛。巨木大道令人失望——不过是一条路旁有高大树木。许多步道封闭或泥泞不堪。GPS在这里信号不好，我们迷路了两次。体验非常令人沮丧。"},
    {"name":"SeniorTravelerTF","rating":2,"text":"公园分散在各社区的格局使人不确定下一步会遇到什么。蜿蜒曲折的双车道公路令驾驶者沮丧，加上频繁的道路问题。游客中心工作人员对公园其他区域出乎意料地一无所知。由于出行困难和住宿有限，我建议专注于一个区域，而不是尝试游览多个地点。"}],
  "carlsbad-caverns-nm": [
    {name:"Sarah B.",rating:5,text:"我们在开放前五分钟到达，一条长队已经绕着游客中心排开……第500张票在上午10:45就发放完毕了。\"描述了成功获取当日定时入场票的策略。"},
    {name:"njoireading247",rating:5,text:"确实可以看出人手不足，但护林员依然礼貌而乐于助人。\"尽管提到人手不足，仍称赞了溶洞1.6英里铺装环路。[好坏参半]"},
    {name:"Cheri Davis",rating:5,text:"这迄今为止是我见过的最好、最大的溶洞！\"她走了超过10000步，发现1美元的定时预约系统非常方便。"},
    {name:"NatSteveC",rating:5,text:"溶洞如此宽阔，我从来没有感到幽闭恐惧……绝对不容错过。\"克服了对地下探索的最初恐惧，并称其为最喜欢的国家公园。"},
    {name:"Michelle",rating:5,text:"这个国家公园的广阔和景色令人无法言喻！\"称赞了国王宫殿导览，并认为礼品店提供了多价位段的优质纪念品。"},
    {"name":"ClaustrophobicCarl","rating":2,"text":"自然入口的下坡路陡峭而湿滑——我的膝盖叫苦不迭。进入大厅后，不过是一个被刺眼的荧光灯照亮、充满石笋的黑暗洞穴。湿度极高，令人不适。回程电梯要等45分钟。蝙蝠飞行表演因风力而取消。不值得专程跑到新墨西哥州的穷乡僻壤来。"},
    {"name":"Feds294201","rating":1,"text":"工作人员看起来很友善，溶洞也很棒，但等电梯上去要1-2个小时，实在太离谱了。如果4部电梯只能开2部，他们应该关闭或至少在人们买票时告知。如果我们当时知道，就不会下去了。漫长的等待毁掉了整个体验，我们不会再来了。我认为被困的人员可能违反了安全方面的州法律，而且无障碍轮椅和婴儿车通道也不能接受。"}],
  "white-sands-nm": [
    {name:"tinaNtravel",rating:5,text:"感觉置身于另一个世界，令人惊叹而美丽。\"称赞了游客中心和标识清晰的徒步步道。"},
    {name:"srikanth0435",rating:4,text:"日出或日落时分前往最值得。其他时间的景色并不十分出众。\"提到入场排队时间较长，但建议在网上购票。[好坏参半]"},
    {name:"Escape49937438969",rating:5,text:"真的是我去过的最酷的地方，白沙绵延数英里。\"强烈建议赶上日落或日出时分的景色。"},
    {name:"Biblublu",rating:5,text:"可以做到但很有挑战性，远不是'平坦'的，但非常美好！\"一位意大利徒步者发现阿尔卡利步道虽然美丽但颇具难度，强调需要带水和做好防晒。[好坏参半]"},
    {name:"Escape49937438969",rating:5,text:"说真的，这是我去过最酷的地方，沙滩绵延数英里。\" 他鼓励其他人去观赏日落或日出。"},
    {name:"Biblublu",rating:5,text:"路虽可行但颇具挑战，远非\"平坦\"，却美不胜收！\" 这位意大利徒步者觉得碱湖小径虽风景宜人却难度不小，强调必须备足水和做好防晒。[褒贬不一]"},
    {name:"Excursion287061",rating:5,text:"如果你在附近，一定要来这个国家公园看看！\" 他提醒礼品店商品价格虚高，建议去沃尔玛购买雪橇而不是在园内租用。[褒贬不一]"},
    {"name":"AZdesertrat","rating":2,"text":"就是沙。白色的沙。仅此而已。我们开车穿越沙丘环路只用了30分钟。没有一点遮阴，气温高达105华氏度。他们宣传的\"滑沙\"项目要求你从礼品店买一个价格虚高的塑料圆盘。孩子们热得直哭。最多一小时，公园里值得看的东西就全看完了。"},
    {"name":"W L","rating":1,"text":"我和朋友于2024年10月7日（星期一）游览了这个国家公园。我们看完介绍视频，大约上午10点45分准备进入公园。入口站没有任何人收取每辆车25美元的门票费。我们不想就这样免票驶入。我们把车停好，四处察看。朋友试图用窗口的二维码在线付款。与此同时，其他车辆直接免费驶入。我们甚至走回礼品店，询问没人收费时该怎么办。工作人员说\"那就免费进去吧。\"等我们回到车旁，终于有一位留着深色长发的女士出现在入口站。我们付了25美元。我两次告诉她刚才没有人在岗，她两次都对我的话置之不理，视我如无物。作为公务人员，这种态度非常无礼。仅这一次糟糕的经历就抵消了大自然在那里提供的一切乐趣。"},
  ],
  "big-bend-tx": [
    {name:"Ian S.",rating:5,text:"美妙的地方。荒野沙漠，景色壮观。四月份游客不多，我可以轻松驾车行驶在铺设良好的公路上。\" 提醒在未铺装道路上行驶时要小心，除非驾驶四驱车。"},
    {name:"Lydia J.",rating:5,text:"这里可以拍摄到相当不错的风景照，沿途有许多可供停车的观景点。"},
    {name:"minimize940314",rating:5,text:"如果打算在旺季前往奇索斯地区，请尽早出发，因为交通管制和停车位不足的问题很快就会出现。\" [褒贬不一]"},
    {name:"TennisStar602",rating:5,text:"在沙漠中看到白杨树与仙人掌共生，美不胜收……由于海拔较高，这里比圣埃莱娜峡谷更凉爽。"},
    {name:"RichardIII",rating:2,text:"在炎热的夏季游览时，\"开阔的空间和辽阔的视野让人感到难以承受\"，总体感觉令人失望。他们觉得这种规模给人的感觉是压迫而非震撼。[负面]"},
  ],
  "mesa-verde-cliff": [
    {name:"Daniele",rating:5,text:"这个公园比周边其他著名公园的游客少得多……绝对值得一游。\" 指出由于位置偏远且导览名额有限，需要提前预订。"},
    {name:"HouTexGal",rating:5,text:"悬崖宫殿导览之旅堪称满分。\" 提醒游览\"需要大量体力，上下陡峭的原始台阶和梯子\"。[褒贬不一]"},
    {name:"George A.",rating:5,text:"这是我见过的最为壮观的崖居遗址……有极佳的观景点。\" 建议预留至少半天时间，因为各景点之间需要驾车前往。"},
    {name:"Stephane",rating:4,text:"美丽而令人惊喜的景点……即便只是登高远望那一刻也值回票价。\" 褒贬不一：提到蜿蜒漫长的盘山公路，但承认其风景价值。[褒贬不一]"},
    {name:"RecreationV",rating:4,text:"公园面积巨大，有很多区域可以探索\"，但在原本轻松的索达峡谷瞭望台等小径上出现了轻微的高原反应。[褒贬不一]"},
    {"name":"HistoryBuff_CO","rating":2,"text":"崖居仅可通过公园管理员带领的导览参观，且门票需提前数周在网上预订一空。我们不知道这一点，驱车3小时后才发现无法参观主要景点。从边缘远眺的效果很远，令人失望。盘山公路上去的路程漫长。游客信息沟通极差。"},
    {"name":"forrest3256","rating":2,"text":"由于新冠防疫规定，所有博物馆及半数其他服务均已关闭。导览的主要项目——悬崖宫殿徒步和云杉树屋——被取消，游客在巴士上度过了4小时的观景时光。营地商店下午5点关门，导致数十名游客无法补给物资。非常令人失望，不值这个门票价格。"},
  ],
  "great-sand-dunes": [
    {name:"Ellen S.",rating:5,text:"看着10岁的小外孙在沙地上滑沙嬉戏，对我来说是一种莫大的喜悦。\" 赞赏了八月到访时的亲子游体验。"},
    {name:"Michele L.",rating:5,text:"就坐在沙丘上30到45分钟，拍照、让手指划过洁净的沙粒\"，感觉这次经历让人焕然一新。建议在九月下旬到访。"},
    {name:"CocoChanel05",rating:4,text:"七月份实在太热了（大约100华氏度，沙子的温度高达110-120华氏度），根本无法踏上沙丘。\" 酷暑阻止了对主要景点的游览。[负面]"},
    {name:"Jeri Jo S.",rating:5,text:"每迈一步都会陷入沙中\"，而且\"风非常大\"。尽管如此，她仍盛赞这片独特的地貌，并建议携带耳罩和头巾。[褒贬不一]"},
    {name:"Brendan S.",rating:5,text:"这个公园\"说白了只有一样东西……就是标志性的沙丘\"，但它壮观无比。大多数游客在几个小时内就能充分游览，除非进行强度较大的徒步。"},
    {"name":"DenverDayTripper","rating":2,"text":"沙丘从停车场看起来很壮观，但实际攀登极为艰难——在厚厚的沙子里每走两步退一步。我们在灼热中坚持了20分钟就放弃了。尽管网站上说夏季溪流会流淌，但我们8月到访时梅达诺溪完全干涸了。感觉像是一场诱人上当的骗局。"},
    {"name":"PYB321","rating":2,"text":"这个公园达不到国家公园的水准。除了随处可见的营地和徒步小径，基本上没什么可做的，而且其他公园里都能找到更好的版本。沙丘看起来确实很酷，但也就仅此而已了，除非你想租一块板子滑沙，感觉还挺有意思的。这里绕道20英里，门票25美元，实在不值。可能维持国家纪念地的地位就够了。"},
  ],
  "mammoth-cave": [
    {name:"Callie S.",rating:5,text:"体验非常棒。景色令人叹为观止……双腿可能会酸，但一切都值得。"},
    {name:"A & M Travels",rating:5,text:"如果你想选择特定时间和导览项目，请提前购票……有适合不同体力水平的多种选择。"},
    {name:"Cat B.",rating:4,text:"赞扬了\"历史之旅\"和\"穹顶与滴石之旅\"，称其为\"非常好的选择\"，但指出住宿设施需要更新，\"地毯、浴室和门都相当破旧\"。[褒贬不一]"},
    {name:"Cheri D.",rating:5,text:"这是我列在必游清单上很久的地方，没有令我失望……公园管理员都很热情，非常乐于助人。"},
    {name:"Phonia337",rating:5,text:"参加了穹顶与滴石溶洞导览，棒极了！……洞内全年温度保持在华氏54度。"},
    {"name":"KYcaver2023","rating":2,"text":"幽闭恐怖的噩梦。\"历史之旅\"需要与其他100名游客挤在狭窄的通道里弯腰前行，相互呼吸。洞内黑暗潮湿，导游匆匆而过。地面上的公园只是普通的肯塔基森林，没有任何特别之处。不值得从纳什维尔开两个小时的车来这里。"},
    {"name":"Sandy J","rating":2,"text":"令人失望，差强人意。我们在导览票开放的当天就预订了。我们参加了历史之旅（2小时，中等难度，2英里，534级台阶）。这个导览团至少有100人，多了大约70人。我们在队伍的最后四分之一处。感觉就像在小跑才能跟上。太荒唐了。导游停下来讲解时共有5个停留点，也不知道我们错过了她讲的什么。与新墨西哥州的卡尔斯巴德和弗吉尼亚州的卢雷相比，这个溶洞并不令人印象深刻。换一个导览项目可能会有更好的感受。"},
  ],
  "canyonlands-ut": [
    {name:"Gwen C.",rating:5,text:"小径美丽且维护良好，适合各种程度的徒步者。令人叹为观止的拱门和一望无际的峡谷景色是最大的回报。"},
    {name:"HennySchaijk",rating:5,text:"这个国家公园令人难以置信地震撼……对于行动不便的人来说，许多美景往往就在公路旁边\"。"},
    {name:"jbg74",rating:5,text:"峡谷地国家公园里的台地拱门是我最喜欢的拱门，甚至胜过拱门国家公园里的那些。"},
    {name:"slhokie",rating:4,text:"飞机导览展示了这片地貌的辽阔与多样\"，但\"洗手间就是地上挖的坑，没有自来水\"。[褒贬不一]"},
    {name:"TripPhotographer52",rating:4,text:"天空之岛地区有许多有趣的峡谷地貌\"，但总体而言\"不如预期中的美丽\"。[负面]"},
    {"name":"FirstTimerUT","rating":2,"text":"峡谷地基本上就是大峡谷一个不那么令人印象深刻的翻版。天空之岛地区就是一个又一个俯瞰同一片棕色峡谷的观景台，没有水，没有遮阴，方圆数英里内没有任何服务。针状岩地区需要四驱车，他们根本不会提前告诉你。交了门票费之后感觉很坑。"},
    {"name":"jetsly","rating":2,"text":"由于进入困难，大多数游客只游览天空之岛地区，而放弃其他区域。除非你驾驶四驱或同样坚固的越野车下到峡谷底部，否则你只是在各个观景台之间的高原上开车兜圈。所有的景色都是全景式的，你看到的效果完全取决于当天的雾霾或烟尘状况。在我们最近的一次到访中，条件尚可——有些观景台视野清晰，有些则被烟雾笼罩。坦率地说，如果你喜欢风景、寻找绝佳拍摄机会，不如驾车从摩押沿UT 128公路驶向州际公路。在那里，你可以在峡谷壁之间行驶，紧靠科罗拉多河——而且道路上几乎只有你一辆车。"},
  ],
  "capitol-reef-ut": [
    {name:"Michelle L.",rating:5,text:"这是游客较少的公园之一，因为它相当偏远，因此所有登山口的停车位都非常有限。"},
    {name:"Jerri L.",rating:5,text:"我们在公园里露营了两晚，尽管那段时间大部分时候都在下雨，但我们还是享受了小径、徒步、果园和历史遗迹。"},
    {name:"g8rslp01",rating:5,text:"我徒步穿越了犹他州\"壮丽五部曲\"，我必须说国会礁是我最喜欢的。这里人少，景色粗犷而美丽。"},
    {name:"Laurie M.",rating:4,text:"如果你打算在夏天徒步，必须在早上8点前出发……起初小径非常平坦，然后以相当陡峭的上坡路结束，通往那道拱门。\"[褒贬不一]"},
    {name:"ThomUSA",rating:5,text:"有些土路普通两驱车也能通行……部分小径标记不够清晰，例如前往国会峡谷水槽的路线。\"[褒贬不一]"},
    {"name":"UTroadtripper","rating":2,"text":"这是犹他州\"壮丽五部曲\"中最无聊的一个。景观公路就是8英里毫无特色的沙漠路。岩画需要放大镜才能欣赏。果园大约5分钟就能逛完。我们开车来这里的时间比实际游览的时间还长。跳过这里，把更多时间留给锡安或布莱斯峡谷吧。"},
    {"name":"WenyuW2","rating":1,"text":"我们去过不少国家公园，国会礁绝对是迄今为止最差的一个！它糟糕到让我专门注册了一个账号来发表评论。公园里几乎没有任何有趣的东西。一所关闭于20世纪40年代的小学被标注为景点？岩石上几幅小小的岩画算是一处名胜？溪流完全干涸，还有几条极其无聊的小径，而且只能驱车行驶10多英里的土路才能进入。顺带一提，路非常窄，需要格外小心以免与对向来车相撞。我的孩子们不停地抱怨这个无聊的公园，甚至在被所谓的景点接连让人失望几次之后，拒绝下车。"},
  ],
  "wind-cave-sd": [
    {name:"Jerri L.",rating:5,text:"草原犬鼠总是很有趣，沿所有徒步小径和公路两侧都能看到它们的身影。\" 在两天的游览中广泛探索，目睹了野牛群、麋鹿和叉角羚。"},
    {name:"Hatzlacha",rating:4,text:"总体上觉得体验有些令人失望。就导游的讲解水平而言，\"这里实在更适合儿童\"。与宝石洞的体验相比，她更青睐后者的教育价值。[负面]"},
    {name:"Godsgirl",rating:5,text:"溶洞非常值得参观。\" 赞扬了导游卡茜的专业知识和幽默感，也很欣赏整个公园内随处可见的草原犬鼠和野牛。"},
    {name:"MikeB1952",rating:4,text:"指出\"导览途中大部分是狭窄的通道\"，大型洞室不多。虽然对溶洞的规模印象深刻，但与其他溶洞体验相比，觉得洞内的钟乳石形态不够有趣。[褒贬不一]"},
    {name:"Jennifer A.",rating:3,text:"地面景色很美，但没能参加溶洞导览。\" 建议提前规划：溶洞预约需提前约三周。[负面]"},
    {"name":"Scarlett628","rating":1,"text":"在我们到访前两天，溶洞导览因电梯故障而取消。尽管我们已提前预订，公园方面拒绝为我们保留其他时段的门票，而是要求我们一家在早上8点前到场，以\"先到先得\"的方式排队，等待时间可能长达7小时。我认为公园应该对那些提前计划并购票的游客给予更多照顾。我们专程长途驱车来看溶洞，最终什么都没看到。这种客户服务完全不可接受。"},
  ],
  "hot-springs-np-ar": [
    {name:"njoireading247",rating:5,text:"这是一个免费的国家公园，不需要预约入场，就在市中心……\" 赞扬了20世纪30年代修复的浴场建筑和风景优美的环山公路。"},
    {name:"Art and Ginny",rating:4,text:"这是一座城市公园，要做好没有停车位、街道拥挤、音乐嘈杂的心理准备……\" 尽管面临拥堵挑战，仍觉得浴场街颇有魅力，也很欣赏那里的山间小径。[褒贬不一]"},
    {name:"bylandorbyair",rating:4,text:"这不是美国国家公园体系中那种令人叹为观止的壮丽公园，但它有其历史价值……\" 值得一游，而且感谢狗狗可以进入大多数区域。[褒贬不一]"},
    {name:"francisc077",rating:3,text:"对此次体验感觉平平，称浴场街以外的城区\"破败而令人沮丧\"，过往车辆的噪音也令人不适。[负面]"},
    {name:"Lynnette27",rating:3,text:"在我们游览的9个地方（8个是州立公园）中，这里是我们最不喜欢的。\" 因周边城市环境而感到与自然脱节，并觉得街道噪音影响了徒步体验。[负面]"},
    {"name":"mike_n","rating":1,"text":"停车收费和第三方支付系统对于国家公园来说显得太寒酸了。公园本身还算干净，但周边地区实在令人大失所望。温泉市是评价最低的国家公园之一，亲身游览后我理解了原因。感觉更像一条小城街道，而非国家公园。这里几乎没有任何理由支撑其国家公园地位，与系统内其他任何公园相比，整体体验都令人失望。再也不会来这里了。"},
  ],
  "lassen-volcanic-ca": [
    {name:"Jill H.",rating:5,text:"不负期望。公路仅开放到邦帕斯地狱小径。\" 尽管六月份因大雪封路而进入受限，但仍欣赏到了美丽的景色。"},
    {name:"djmathews",rating:4,text:"这座位于加利福尼亚北部的偏远国家公园给我留下了极其独特的印象。\" 褒贬不一：赞扬了公园的地热景观和野生动物，但指出公园面临积雪和火灾的双重困扰。[褒贬不一]"},
    {name:"kevan j.",rating:5,text:"令人叹为观止的徒步体验！路途颇为陡峭，但往返大约只有5英里。\" 这位62岁的徒步者称其为\"我一生中最难忘的十次徒步之一\"。"},
    {name:"John E.",rating:4,text:"门票费为30美元。小径上有许多关于火山喷发的详细介绍。\" 对具有教育意义的小径给予积极评价，但指出门票费用可能会让部分游客望而却步。[褒贬不一]"},
    {name:"SeattleReebs",rating:5,text:"我们几乎包场……公园本身令人叹为观止。\" 对这个被低估的目的地给予热情评价，公路状况一流。"},
    {"name":"NorCalNancy","rating":2,"text":"公园内的主干道因积雪而关闭至七月中旬。邦帕斯地狱的木栈道因维修而部分关闭。地热区散发的硫磺味令人作呕。公园的大部分地方只是普通的森林，毫无火山特征。与黄石公园的地热景观相比，这里被过度吹捧了。"},
    {"name":"Vic J","rating":2,"text":"我们前往北加州旅行，游览拉森火山国家公园是原因之一。我们被收取了25美元的全价门票，但从西北侧进入后只能在公园内行驶10英里。北端唯一能看到的就是\"热\"岩石（它在100年前才是热的）——这完全是骗人的。如果公园南端（所有地震和火山活动所在之处）尚未开放，请不要前往——那里没有任何东西可看。"},
  ],
  "pinnacles-ca": [
    {name:"Our Next Adventure",rating:5,text:"尖峰石阵真是一颗被低估的明珠！巨大的岩柱和嶙峋的山峰令人叹为观止\"，还有独特的巨砾洞穴探险以及可能目睹加州神鹫的机会。"},
    {name:"Brendan S.",rating:5,text:"尖峰石阵在63个国家公园中排名靠后，所以我的期望并不高。但它完全配得上国家公园的称号。"},
    {name:"LukeS",rating:5,text:"神鹫沟-高峰-熊沟洞穴环线是我有史以来最喜欢的日间徒步路线之一。\" 由于夏季酷热，最好在初春或深秋前往。"},
    {name:"FAFNAR",rating:4,text:"前往熊沟水库的徒步很有趣，尤其是攀爬岩石和翻越瀑布\"，但质疑是否值得专程前往，除非是露营或进行更长的徒步。[褒贬不一]"},
    {name:"luv4phood",rating:5,text:"在大约4小时内完成了一条令人满足的6英里环线。营地隐私性较差，就坐落在主游客公路旁边，这被指出是一个缺点。[褒贬不一]"},
    {"name":"BayAreaHiker","rating":2,"text":"专程来看神鹫——一只都没看到。蝙蝠保育期间洞穴关闭。夏季徒步酷热难耐，毫无遮阴。停车场早上9点就满了，东入口拒绝了我们入内。作为国家公园，这里的基础设施和规划简直差得令人瞠目结舌。"},
    {"name":"celesten2022","rating":1,"text":"这个公园绝对是最不友善的！不仅公园管理员对我们一家人态度粗鲁，而且在我们长途驱车赶来之后，还被告知根本不能停车等候上小径。班车停运——我们要步行总共6英里才能来回到达目的地。这次经历糟透了。驱车长途赶来后不得不原路返回。管理员和游客中心的工作人员都态度恶劣。他们根本应对不了大量游客，无法管理众多车辆，不建议在繁忙的日子前往这个公园！他们完全无法应对大量人流！！！"},
    {"name":"Craig B","rating":1,"text":"作为一个县立公园倒是不错。但国家公园？简直是个笑话。它根本无法与优胜美地、落基山脉、黄石、大峡谷甚至冰川、大提顿或雾霾山相提并论。这是对国家公园品牌的一大污点，让我想起了那个人人都能拿到参与奖的时代。说真的，半岛开放空间区就有比这更好的公园。"},
  ],
  "congaree-np-sc": [
    {name:"Brian E.",rating:5,text:"国家公园管理局在游客中心生态系统和历史解说方面做得非常出色。"},
    {name:"Gina B.",rating:5,text:"这处南卡罗来纳州的隐秘珍宝远超我们的预期。野生动物十分丰富——我们发现了猫头鹰、蛇和石龙子。"},
    {name:"BruinDan",rating:4,text:"环境会非常潮湿，请做好相应准备。\" 同时也赞扬这是\"我们曾经历过的最独特的环境之一\"。[褒贬不一]"},
    {name:"Hannah S.",rating:4,text:"维护良好的国家公园——工作人员超级友善，环境整洁！木栈道部分路段较滑，请注意安全。\"[褒贬不一]"},
    {name:"It may be a free park but to u",rating:2,text:"对我们来说，即便是免费公园，价格也高于其应有的价值……只走木栈道小径，否则别浪费时间。\" 将蚊子描述为\"非常可怕\"，并指出\"一旦停下来，你就会被蚊虫包围\"。[负面]"},
  ],
  "dry-tortugas-fl": [
    {name:"Kbenoithake",rating:5,text:"我们放弃了乘船，选择了全天水上飞机游览……绝对值回票价！\" 赞扬了风景绝美的水上飞机之旅以及渡轮抵达前独享的岛屿时光。"},
    {name:"Barry L.",rating:5,text:"公园里的堡垒非常有趣。鸟类繁殖地令人叹为观止。\" 建议穿运动鞋而非凉鞋，因为海滩上布满粗糙的贝壳。"},
    {name:"Fran B.",rating:5,text:"需要步行很长的路，请穿舒适的鞋子并涂抹防晒霜，这里几乎没有遮阴。\" 着重介绍了历史意义和从杰斐逊堡顶端俯瞰的绝美景色。"},
    {name:"hd4me",rating:3,text:"船行有些颠簸，有人晕船……可能不会再去了。\" 抱怨风浪导致晕船以及有限活动的高昂费用。[负面]"},
    {name:"Grover R.",rating:5,text:"美国的历史与自然双重宝藏……这里有太多精彩的事情可以做和可以看。\" 详细介绍了堡垒历史、浮潜和鸟类保护区。"},
    {"name":"fauchelle4010","rating":2,"text":"杰斐逊堡看起来像一个电影布景，令人叹为观止，但食物却很糟糕——非常廉价、高度加工、品质低劣——这不是你对一次价格超过170美元的一日游所期望的。在家吃好早餐，自己带个冰箱装食物。浮潜体验一般，能见度是个问题。渡轮现代且快速，船员很热情，但整体性价比很差。公园本身没有遮阴，一旦进入就无处购买像样的食物或饮水。这是一个漂亮的地方，但你实际得到的远不值这个价钱。"},
  ],
  "biscayne-np-fl": [
    {name:"Jodi307",rating:5,text:"比斯坎研究所每月两次提供从迪尔林庄园出发的4小时灯塔游船之旅。\" 赞叹看到了多座灯塔和海豚。"},
    {name:"Elizabeth C.",rating:5,text:"我们的导游西耶娜非常和蔼、热情、博学。\" 一家人在这次2小时的导览体验中享受了穿越红树林隧道的皮划艇之旅。"},
    {name:"Grover R.",rating:5,text:"体验比斯坎国家公园的最佳方式。\" 重点介绍了在琼斯潟湖划桨和与海洋生物相遇的经历，尽管天气原因导致原定的浮潜计划未能实现。"},
    {name:"Departure31426160252",rating:4,text:"这次旅行非常棒！\" 但指出了人员超载的问题：\"船上共有34人，而网站上的船只信息显示'最大载客量为30人'。\"[褒贬不一/负面]"},
    {name:"J S.",rating:4,text:"游客指出船\"相当拥挤，座位朝向船内，视野受到一定影响\"，但博卡奇塔礁岛被描述为美不胜收。[褒贬不一]"},
    {"name":"MiamiLocal305","rating":1,"text":"这个公园95%在水下，没有船基本上无法进入。游客中心只是一栋放了几个鱼缸的小楼。因天气原因，浮潜导览被取消了。如果你无法下水，这里字面意义上什么都做不了。我们去过最差的国家公园——它根本不该算是公园。"},
    {"name":"NancyAV","rating":1,"text":"这是我经历过的最糟糕的国家公园体验。首先，去程的船行让人浑身湿透。我们根本没法四处张望，因为海浪浪花太猛烈，不得不一直低着头。等我们抵达博卡奇塔礁岛，那里简直是派对中心，到处是播放着嘈杂音乐、醉醺醺的人群和游艇。是的，灯塔确实挺有意思——但主要是因为它\"不过是个华而不实的装饰品\"，这是我们导游的原话。它从来就不是一座正常运作的灯塔，现在也不是。通往小径的桥梁损坏，除了那些游艇什么都没得探索。我从来没有如此迫不及待地想要离开一个公园，但当时只能干等。体验糟透了，我绝不会再去。"},
  ],
  "indiana-dunes": [
    {name:"DLP",rating:5,text:"阳光、沙滩与湖水……有什么不喜欢的呢？许多小径沿着沙丘延伸，通向密歇根湖的美丽景色。"},
    {name:"Duraiya K.",rating:4,text:"印第安纳沙丘国家公园是徒步探险的绝佳去处，沙丘小径尤为精彩。"},
    {name:"Deanna A.",rating:3,text:"如果你在打卡所有国家公园，那值得一游。否则可以跳过……游客中心完全没有组织。\"[负面]"},
    {name:"Jeff M.",rating:4,text:"俯瞰密歇根湖的景色非常棒，天气好的时候在海滩上休憩也是一大享受。但小径的维护可以做得更好一些。\"[褒贬不一]"},
    {name:"dizzneegirl",rating:4,text:"西海滩的水和沙滩不错，但四周被工业区包围，感觉很奇怪，不像国家公园。\"[褒贬不一]"},
    {"name":"Laura_L","rating":2,"text":"作为国家公园，这里令人印象不深。我们看到的最好的部分是1933年世博会的几栋建筑。最糟糕的是，这个公园在自然美景方面根本比不上我们去过的许多其他国家公园。它分散在很多不同的区域。一些受保护的区域看起来并没有什么特别之处：一座老农场、一间皮草商人的小屋，还有几片海滩。公园的宣传片基本上是一部30分钟的广告，几乎没有关于沙丘形成或历史的实质内容。我真的不明白为什么这里会成为国家公园。我完全没有再来的计划。"},
  ],
  "cuyahoga-valley-oh": [
    {name:"rzahm",rating:5,text:"阿克伦和克利夫兰之间一处美丽的宝藏\"，地貌优美，有许多方便到达的小径。很欣赏那里结冰和流动的瀑布。"},
    {name:"wirttravelers",rating:4,text:"礁石小径以其岩石地貌和遮阴的小路脱颖而出，格外美丽。觉得它不如其他国家公园壮观，但仍然值得一游。[褒贬不一]"},
    {name:"lithlith",rating:3,text:"公路的\"持续噪音\"贯穿整个公园，影响了自然体验。建议改去霍金山，那里的景观和徒步路线更胜一筹。[负面]"},
    {name:"Rosanne S.",rating:3,text:"觉得布兰迪万瀑布很美，但提醒\"繁忙的周日停车位极度紧张\"。推荐使用GuideAlong应用程序探索鲜为人知的瀑布。[褒贬不一]"},
    {name:"Gage113",rating:5,text:"感谢这里\"无需购买公园通票\"，并喜欢礁石徒步路线。指出公园占地分散，需要多次开车前往不同景点。"},
    {"name":"tklasinski","rating":1,"text":"除非你住在附近，想利用众多野餐区，否则不要浪费时间来这里。唯一的自然景观就是瀑布，而且你只能在瀑布中途侧面的木栈道观景台上观看，不允许进入下瀑布区域，所以根本没有好的拍摄角度。我不明白这里是怎么被评定为国家公园的，几处被住宅区、高尔夫球场和滑雪场包围的\"自然\"区域，对我来说实在算不上国家公园。"},
  ],
  "new-river-gorge-wv": [
    {name:"Dane C.",rating:5,text:"对于一家人来说，新河峡谷大桥巍然矗立于新河之上，令人叹为观止，是一项工程奇迹。\" 推荐法耶特站公路。"},
    {name:"Kathy R.",rating:4,text:"赞扬了美丽的景色和知识渊博的护林员，但也指出：\"有很多交叉小径，所以经常搞不清楚哪条才是主线路。\"[褒贬不一]"},
    {name:"Suzanne",rating:5,text:"主观景台位于游客中心旁边，真的令人叹为观止！\" 着重介绍了多样的地貌，并推荐参观大景观和砂岩区域。"},
    {name:"Jeanne S.",rating:5,text:"与17位家庭成员一同游览，并感谢\"这片区域的自然之美和未受商业侵蚀\"。指出小径上游客不多。"},
    {name:"THINGS2LIVE4",rating:5,text:"将长点小径的体验与锡安国家公园的天使降落相提并论，并称赞了塔蒙德保留鬼城，指出\"桥梁步道需要提前很久预订\"。"},
    {"name":"WVweekend","rating":2,"text":"新河峡谷大桥观景点不过是一个能看到桥梁的停车场。峡谷本身还算漂亮，但与西部公园相比实在平淡无奇。费耶特维尔小镇毫无活力。漂流公司收费过高，而那些III级激流连初学者都能轻松应对。作为美国最新的国家公园，这里被严重过誉了。"},
    {"name":"Joseph I","rating":2,"text":"更像是国家森林，而非国家公园。显然是为了给贫困的西弗吉尼亚州带来旅游收入而设立的。营地标识不清，设施落后。阿姆特拉克列车和货运列车频繁穿越公园。从一处景点到另一处往往需要先离开公园。园内有许多私人产权的土地——我从未在国家公园里见过这种情况。如果你住在附近或途经此地，也许还好，但总体而言，如果你去过大烟山、冰川、优胜美地等地，就会意识到这里根本达不到国家公园的标准。"},
  ],
  "gateway-arch-mo": [
    {name:"arleye",rating:5,text:"乘坐缆车前往顶部绝对值得——但不是人人都能接受！\" 指出吊舱空间狭小且有幽闭感，但描述抵达顶端是\"一生一次的体验\"。"},
    {name:"parksvisitor",rating:5,text:"拱门非常壮观\"，广场也很棒。但觉得博物馆\"在将西进历史与拱门联系起来方面做得有些过头\"。[褒贬不一]"},
    {name:"TravelingSoccerLoon",rating:5,text:"拱门的外部景观比从内部看到的景色更为壮观。\" 建议在日落时分安排游船游览，以获得最佳观赏效果。[褒贬不一]"},
    {name:"Ashley R.",rating:4,text:"爬上顶端的过程不是我的菜，有点幽闭感。\" 尽管有些不适，但指出运作效率高，并觉得在山顶的短暂停留已足够。[褒贬不一]"},
    {name:"jkweebs",rating:4,text:"拱门是令人叹为观止的建筑\"，其建造历史引人入胜。然而，这位打卡国家公园的爱好者指出，这些地方\"是国家纪念碑，而非国家公园\"。[褒贬不一]"},
    {"name":"STLskipper","rating":2,"text":"前往顶部的缆车是幽闭恐怖的噩梦——一个小小的蛋形舱，4分钟的纯粹煎熬。顶部的观景窗只是一道道细缝。下面的博物馆还算不错，但不值20多美元的门票。整个体验大约需要一个小时。这不过是一座冒充国家公园的纪念碑。"},
    {"name":"disasterfem","rating":1,"text":"我以前来过圣路易斯几次，从未上过拱门，但被丈夫和几位朋友说服，说这是必游之处。于是我来到了拱门。进入底部后，买了下一班次的门票，五分钟后出发。来到乘车区，看到那些小小的门，立刻知道麻烦来了。要知道，我不是一个身材娇小的人，我更喜欢宽松的空间。缆车舱里根本没有多余的空间。幸好我和丈夫是我们那节缆车里唯一的两个人。蜷缩着身子坐了4分钟，乘坐一个叮当作响、闷热的吊舱。到达顶部后人很多，这是意料之中的，景色还不错，工作人员无精打采，对他人漠不关心。下来的过程也好不到哪去。然后我们去购物。收银员看到我丈夫来自田纳西州的驾照后，学起了\"乡巴佬南方口音\"来评论我们的来处。看到我们的表情，我说我们说话没有这种口音，他才说\"也许我不该那样说的\"。这确实非常无礼。外面的广场很美，适合拍照，但此后听说了其他不少关于缆车的糟糕经历，所以我的第一次也是唯一一次到此打卡已经结束了。"},
  ],
  "mount-rushmore-sd": [
    {name:"BrakiWorldTraveler",rating:5,text:"我大约早上8点就到了，强烈建议这样做。首先，你能立刻找到停车位；其次更重要的是——那时游客寥寥无几。"},
    {name:"Tom",rating:4,text:"对这个景点的看法会因人而异，但由于这是我从童年起就列在愿望清单上的地方，我持更积极的态度。"},
    {name:"Jill E.",rating:4,text:"政府停摆期间游客中心关闭令人失望，但雕刻本身依然\"美丽，可以从不同角度拍照留念\"。[褒贬不一]"},
    {name:"Rick_2785",rating:4,text:"拉什莫尔山亲眼看来无疑令人印象深刻——雕刻的规模、细节和历史都非常了不起。然而，除了单纯地观赏纪念碑，实在没有太多其他可做的事情。\"[褒贬不一]"},
    {name:"Barry S.",rating:5,text:"欣赏了游客中心播放的\"《石刻天地》纪录片\"，觉得\"非常有教育意义，让我对这座纪念碑有了全新的认识\"。"},
    {"name":"RealTalkTravel","rating":2,"text":"它比你想象的要小，比你预期的要远，而且10美元的停车费真的很侮辱人。你走过去，看着岩石上雕刻的四张脸，拍张照片，然后离开。整个游览过程只需20分钟。礼品店比观景区还大。总统步道最多再加15分钟。极度被过誉的旅游景点。"},
    {"name":"KevinN769","rating":2,"text":"我不知道自己期待着什么，但拉什莫尔山完全让我感到平淡无奇。它和你预期的一模一样：就是四位总统脸孔的高大石刻。你的门票让你与它相距500英尺以上，所以根本感受不到其真实的规模和细节，即便如此，它也没有你最初预期的那么大。我和我哥哥一起去，说实话，在到达纪念碑前几个转弯处，有一块形状极其……特别的岩石让我们更觉得有趣。我们在拉什莫尔山唯一拍的照片是一个\"就这？\"的苦笑表情。我们俩都超过25岁，以防你想知道。"},
  ],
  "glacier-bay": [
    {name:"theoriginalchrz",rating:5,text:"没有任何照片能与这个美丽的国家公园的实景相比。\" 游客们赞叹其令人屏息的自然风光，并建议携带望远镜观察野生动物。"},
    {name:"46oceangirl",rating:5,text:"如果你在乘坐游轮且能自选行程，冰川湾是绝对不可错过的。\" 享受了难得的好天气并目睹了冰川崩解。"},
    {name:"K B.",rating:4,text:"尽管天气条件不佳，仍发现了座头鲸、虎鲸、海狮和山羊。指出大型游轮在近距离观赏方面不如小型船只。[褒贬不一]"},
    {name:"Emptynester",rating:5,text:"如果你有机会乘坐游轮游览这片海域，请寻找包含穿越本公园行程的路线。\" 公园护林员全程提供了精彩的野生动物解说。"},
    {name:"D H.",rating:2,text:"这次旅行不过是一整天的游船之旅\"，冰川观赏有限，野生动物邂逅也令人失望。与特雷西臂冰川游相比，那里更令人兴奋。[负面]"},
  ],
  "wrangell-st-elias": [
    {name:"Wendy N.",rating:4,text:"紧靠理查森公路的游客中心很不错\"，护林员讲解生动翔实，附近的森林小径可以\"欣赏铜河、山谷和兰格尔山脉的壮丽景色\"。"},
    {name:"Nancy T.",rating:5,text:"这是一个非常偏远的公园，但非常值得一游。\" 尽管路况恶劣，在麦卡锡路上还经历了爆胎，她仍表示还会再来。"},
    {name:"terrapinproud",rating:3,text:"尽管承认公园本身\"叹为观止\"，但批评了展览工作人员的专业知识不足，并指出游客中心距离公园核心地带遥远，让人感觉与之脱节。[褒贬不一/负面]"},
    {name:"CrankingChick",rating:4,text:"赞扬了设施的精致建筑和翔实的展览，但指出\"这里的蚊子非常厉害——是我们在阿拉斯加遇到过的最猖獗的\"。[褒贬不一]"},
    {name:"Shavy",rating:4,text:"将其描述为\"我们去过的最大的公园\"，工作人员乐于助人，还有关于公园活动的纪录片，但强调公园\"相对难以进入\"。[褒贬不一]"},
    {"name":"Brian_O","rating":1,"text":"我们是根据一本小册子对历史小镇的描述而前往肯尼科特的。那里是一座鬼城。矿山并不在肯尼科特，只有一座14层楼高的旧磨坊。谁会想爬14层摇摇欲坠的楼梯呢？小镇只有1家餐厅和1辆餐车供餐。我们乘坐的肯尼科特班车车辆存在安全带扣卡住、座椅破损、地板肮脏、车顶破旧、无头枕等问题，司机还单手开车，一边喝健怡百事可乐，并在休息站脱下鞋袜抠脚趾。"},
    {"name":"terrapinproud","rating":2,"text":"公园本身令人叹为观止，美不胜收，但游客中心完全配不上这座公园。原住民文化展览的工作人员对被问及的时间轴图示毫无了解，自己似乎也不感兴趣。而且游客中心距离麦卡锡在字面意义上有好几个小时的车程，让人感觉与实际的公园体验完全脱节——就好像把大弯国家公园的游客中心设在埃尔帕索一样。建议改去规模较小的肯尼科特游客中心。"},
  ],
  "kenai-fjords-ak": [
    {name:"NorthStar819606",rating:5,text:"公园令人叹为观止！我真的很享受了解冰川的知识以及这片区域所孕育的野生动物。\" 赞扬了护林员带队的导览和前往西北冰川的游船之旅。"},
    {name:"TFAtravel",rating:5,text:"基奈峡湾国家公园的大部分地区是无法进入的原始荒野……然而，那些可以进入的区域绝对是必游之地。\" 着重介绍了出口冰川徒步和目睹鲸鱼、水獭、老鹰等野生动物的经历。"},
    {name:"Firefly78",rating:5,text:"我在这里看到了最为丰富的野生动物（比德纳利多得多）。\" 记录了目击黑熊、海獭、白头鹰、鲸鱼、海豹和海鹦的经历。"},
    {name:"Violeta M.",rating:5,text:"简直太棒了，美丽至极。必去之地，携带防熊喷雾。小径众多，景色震撼。\" 推荐将免费的热门出口冰川小径与其他选择结合游览。"},
    {name:"Guide37396532207",rating:1,text:"驱车前往苏厄德并预订酒店后，他们取消了行程……提前不到24小时才通知。\" 对影响其计划的导览取消感到沮丧。[负面]"},
  ],
  "isle-royale-mi": [
    {name:"Sue F.",rating:5,text:"我们住在罗克港旅馆，享受了俯瞰湖景的房间以及那里的宁静安详。"},
    {name:"THINGS2LIVE4",rating:5,text:"我非常愿意回来在这里住上几晚。如果你想要一个没有电视、Wi-Fi有限的原始、独特而美妙的地方，皇家岛就是为你而设的！"},
    {name:"Raintree_Thailand",rating:4,text:"皇家岛是本土48州访客最少的国家公园……前往代价不菲——每人单程160美元。\" 赞扬了目的地，但着重指出了高昂的费用和交通不便。[褒贬不一]"},
    {name:"midwesterner5",rating:3,text:"这次游览对国家公园管理局的表现并不满意\"——批评了护林员不友好的态度和高昂的旅馆费用（是同等州立公园住宿的2.5倍），但承认在自然体验方面不错。[负面]"},
    {name:"Toby M.",rating:5,text:"这是一处默默打动你的特别地方。\" 热情推荐了水上飞机选项，提醒注意苏必利尔湖的浪涛，并指出旅馆入住含独木舟租赁服务，以及托宾港的绝美景色。"},
    {"name":"midwesterner5","rating":2,"text":"这次游览对国家公园管理局的表现并不满意。我们遇到的护林员感觉像是从执法部门调来的——那种\"你大概会毁了这座岛\"的气息多于对游客的欢迎。罗克港旅馆的食物质量平庸，但价格却贵得离谱。渡轮费用昂贵且耗时漫长。如果天气突变、水上飞机无法飞行，被迫在岛上过夜是真实存在的风险。这里无疑是美丽的荒野，但繁琐的交通和国家公园管理局的态度使这次体验充满压力，而非平静。"},
  ],
  "alcatraz-island-ca": [{"name":"MartinB_London","rating":5,"text":"穿越囚室楼的语音导览非常出色——前警卫和囚犯的声音让这个地方以照片从未能做到的方式重焕生机。乘坐渡轮前往时，可以欣赏到金门大桥的壮丽景色。"},
    {"name":"TravelJunkie2019","rating":4,"text":"恶魔岛是旧金山必游之地。请提前购票，因为票很快就会售罄。记得带件夹克——海湾的风真的不是开玩笑的。语音导览制作非常精良，内容翔实。"},
    {"name":"SunnyDaysCA","rating":3,"text":"值得一游，但略显失望。岛上大部分是废弃的、风化剥落的建筑和残垣断壁。原以为保护得会更好一些。不过语音导览不错。"},
    {"name":"StinkyIslandVisitor","rating":2,"text":"迎接我们的是难闻的气味和驱赶不走的苍蝇群。部分区域的维护有待提升，高峰时段人流非常拥挤。被过度吹捧的旅游景点。"},
  ],
  "antelope-canyon": [{"name":"DesertExplorer22","rating":5,"text":"令人叹为观止的美景——它美得让你停不下来拍照。我们的导游知识渊博，热情洋溢地分享关于峡谷的历史和文化意义。"},
    {"name":"PhotoFanatic_Mike","rating":5,"text":"导游帮我们调整相机设置，拍摄到了绝美的照片，还指出了独特的岩石构造。三月至十月间的光柱如梦似幻。"},
    {"name":"CalmWalker_Jane","rating":3,"text":"值得一游，但感觉商业化过度。同一时间峡谷里人太多了，很难拍到没有人入镜的照片。"},
    {"name":"RushedTourist","rating":2,"text":"我们的导游非常赶时间，没有给我们足够的时间欣赏峡谷。如果你想要沉浸式的漫步体验，不推荐这里。感觉就像被赶着的牛群。"},
  ],
  "apostle-islands": [{"name":"LakeSuperiorFan","rating":5,"text":"海蚀洞非常壮观，绝对不能错过！我们参加了3小时的大游览，这是我们威斯康星之行的亮点。贝菲尔德也是一个迷人的小镇。"},
    {"name":"NatureLover_WI","rating":4,"text":"俯瞰苏必利尔湖的绝美景点，贝菲尔德还有许多小店可以逛。这里历史底蕴深厚，可以乘坐游船近距离欣赏各个岛屿。"},
    {"name":"MidwestHiker","rating":3,"text":"如果贝菲尔德离你不远，值得去看看这些岛屿，至少去一次，但与彩绘岩石和睡熊沙丘相比，我觉得这里的印象最淡。"},
    {"name":"LandLubber99","rating":2,"text":"从陆地角度来看，可看的东西有限。一处国家公园管理局的景点在很远的地方，另一处正在施工。基本上你需要私人船只或旅游公司才能看到任何值得一看的东西。"},
  ],
  "appalachian-trail": [{"name":"ThruHiker2024","rating":5,"text":"在天气晴朗的日子里，当你接近乔治亚州路段上最高的山峰时，景色壮观无比。作为全国最受欢迎的徒步胜地之一，其盛名名副其实。"},
    {"name":"VermontWalker","rating":4,"text":"我们在佛蒙特州徒步的路段管理非常到位，标识清晰。如果可以的话，请在春季前往，以避开积雪和另一个极端——蚊虫的困扰。"},
    {"name":"PAhiker_boots","rating":3,"text":"宾夕法尼亚州路段相对平坦，但遍地的岩石会拖慢你的速度、磨坏你的靴子，让你的双脚酸痛。沿途有一些有趣的地方，但整体是一段苦旅。"},
    {"name":"ShenandoahLover","rating":5,"text":"在谢南多厄国家公园，无论你身处何处，都离阿巴拉契亚步道不远。你肯定会多次与它相遇。这里的步道技术难度相当低，而且风景优美。"},
    {"name":"LucasA","rating":1,"text":"我对新罕布什尔州AMC直接管理路段阿巴拉契亚步道的糟糕路标感到失望和愤慨。AT穿越新罕布什尔州的路段路标极差或根本没有路标。你能看到小路名称的指示牌，但主要的阿巴拉契亚步道名称和方向指示牌（南/北）完全缺失。"},
  ],
  "assateague-island": [{"name":"WildPonyFan","rating":5,"text":"这里是美丽的国家公园，有迷人的海滩以及令人叹为观止的日出和日落。野马非常雄伟，常常成群出现在岛上。请记得与它们保持100英尺的距离。"},
    {"name":"BeachCamperMD","rating":5,"text":"这里的海滩比海洋城安静得多，小额门票费非常值得。年度会员只需30美元，非常划算——我们一来再来。在码头垂钓也很棒。"},
    {"name":"QuietBeachSeeker","rating":4,"text":"淡季是最佳到访时机——没有人群，没有排队，只是沿着海滩和小径静静地漫步，亲近自然。野马是意外的惊喜加分项。"},
    {"name":"BugHater_2023","rating":2,"text":"夏季的蚊子和苍蝇简直令人崩溃。野马从远处看确实很酷，但除此之外，这里不过是一片设施有限的普通海滩，不值这么多的宣传。"},
  ],
  "blue-ridge-parkway": [{"name":"AutumnDriver_NC","rating":5,"text":"在蓝岭公园大道上的秋日驾车是一次绝妙的体验。风景驾车路线蜿蜒曲折，五彩缤纷的叶色让你感觉仿佛在逃离尘嚣。沿途有许多可以停车欣赏的观景台。"},
    {"name":"ScenicRoadTripper","rating":4,"text":"即使只驾驶50英里左右也值得一游。护林员非常博学友善，帮助你规划路线。全程风景优美。"},
    {"name":"DisappointedHiker","rating":2,"text":"时隔5年第二次到访，非常失望。许多游客中心已关闭或开放时间极为有限。一些观景台植被过度生长，景色受阻。部分路段关闭，需绕行40多英里。"},
    {"name":"WeekendExplorer","rating":3,"text":"风景还不错，但说实话，开过第一个小时之后，看起来都大同小异了。部分路段维护不佳，限速使得行程感觉无休无止。"},
  ],
  "cape-hatteras": [{"name":"BeachLover_OBX","rating":5,"text":"我坚定地认为这是美国最好的海滩，没有之一。绵延数英里几乎未经开发的天然美丽海滩。那座灯塔已成标志性符号。"},
    {"name":"ShellCollector","rating":5,"text":"免费公共停车，免费进入海滩，而且捡到完整的大贝壳并不罕见。人不多，可以垂钓。野生动物丰富，包括鸟类、海龟和螃蟹。"},
    {"name":"OctoberVisitor","rating":4,"text":"十月到访，天气宜人，海水温暖，游客稀少。沿着70英里的海岸线，三座岛屿上分布着三座迷人的灯塔——博迪岛、哈特拉斯岛和奥科克岛。"},
  ],
  "cape-hatteras": [{"name":"CityBeachFan","rating":3,"text":"如果你想要一个轻松的假期，哈特拉斯角还算不错，但这里没有海滨步道，也没有什么刺激活动。如果你期待夜生活或餐厅，那你来错地方了。这里只有沙滩和风。"},
    {"name":"NoatakGirl","rating":2,"text":"我以为外滩群岛和这段驾车路线在返回佛罗里达途中会是一段绝美风景线。这绝对是我见过的最不像风景道的\"风景道\"。大部分路段只是灌木丛或平坦荒地，几乎看不到海水或海滩。纳格斯黑德及沿途小镇都令人大失所望。"}],
  "chaco-culture-nhp-nm": [{"name":"ArchaeologyBuff","rating":5,"text":"这是一处联合国教科文组织世界遗产，查科普韦布洛建造者创造了与太阳对齐的建筑，成就令人叹为观止。这些建筑在美国无与伦比。"},
    {"name":"StarGazer_NM","rating":5,"text":"查科的夜空令人窒息，仿佛伸手便能触到繁星。请至少预留整整一天。我们在此露营了五晚，探索岩画并参加了护林员讲解游览。"},
    {"name":"MuddyRoadTripper","rating":3,"text":"对于历史爱好者值得一来，但进山的路十分崎岖。从北入口进入的最后四英里路段无人维护，满是车辙，雨天可能无法通行。出发前请先致电确认路况。"},
    {"name":"UnpreparedVisitor","rating":2,"text":"查科没有任何服务设施——没有食物、没有加油站、没有手机信号。那条路险些毁了我们的租车。遗址很美，但入园之难让我很难向普通游客推荐这里。"}],
  "columbia-river-gorge": [{"name":"WaterfallChaser_OR","rating":5,"text":"壮观的景色，拥有90多处瀑布！前三名分别是马尔特诺马瀑布、婚纱面纱瀑布和马蹄铁瀑布。景观从西部的温带雨林一路延伸至东部的干旱荒原，变化万千。"},
    {"name":"PortlandDayTripper","rating":4,"text":"美景如画，可游览的地方很多，包括不错的餐厅、美丽的瀑布和葡萄酒庄。建议一早出发，因为停车位经常供不应求。马尔特诺马瀑布附近尤为拥挤。"},
    {"name":"WeekendHiker_WA","rating":5,"text":"该地区位于华盛顿州和俄勒冈州之间，拥有徒步步道、瀑布、森林等众多景观。沿着风景路有许多停车点和徒步机会。"},
    {"name":"CrowdedParking","rating":3,"text":"即便是十月，这一带也相当热闹。马尔特诺马瀑布在夏天简直人满为患。停车和徒步的地方不少，但旺季时找车位令人抓狂。"},
    {"name":"vinker","rating":2,"text":"哥伦比亚河峡谷被当地旅游局大力宣传，但其实并不算特别壮观。河岸边景色不错，但我们认为不算必游之地。大多数特色区域都商业气息浓厚，礼品店比景点本身更受重视。"}],
  "craters-of-the-moon-nm-id": [{"name":"VolcanoFanatic","rating":5,"text":"这个地方真的绝无仅有，即便与黄石公园相比也毫不逊色。7英里的环形路集合了各种类型的火山地貌——煤渣锥、火山口、熔岩原野、裂谷峡谷，应有尽有！"},
    {"name":"NightSkyWatcher","rating":5,"text":"这里的星空令人叹为观止——我们看到了好几颗流星，银河清晰可见。你可以步入熔岩管洞穴，整个纪念地内遍布步道。"},
    {"name":"HotAndDusty","rating":3,"text":"这里阳光很烈，几乎没有树荫，但仍然值得一看。春季是最佳游览时间，气温较为宜人，数以千计的野花竞相盛开。请务必多带水。"},
    {"name":"PassingThrough","rating":2,"text":"大约有趣30分钟，之后就只是石头和更多石头了。地理位置非常偏远，周围什么都没有。除非你真的对地质学感兴趣，否则不值得专程前往。"}],
  "crazy-horse-memorial-sd": [{"name":"BlackHillsExplorer","rating":4,"text":"疯马纪念碑远超我的预期。纪录片制作精良，北美印第安博物馆收藏了种类繁多的原住民艺术品与文物。"},
    {"name":"WorkInProgress","rating":3,"text":"值得一看，但从入口和道路所能看到的，基本上就是全貌了。这座纪念碑自1948年起开始建造，至今似乎仅完成了约10%。请做好心理预期。"},
    {"name":"CashGrabAlert","rating":1,"text":"这简直是圈钱！门票已经很贵了，还要另付4美元乘坐一辆根本凑不到跟前的巴士。建造了75年多，才刻出了一张脸。这些钱都花到哪里去了？"},
    {"name":"MuseumLover_SD","rating":4,"text":"请花时间探索纪念碑之外的区域。关于美国原住民历史的展览、博物馆陈列和文化展示都十分精彩，既有趣又有教育意义。"}],
  "devils-tower-wy": [{"name":"RoadTrip_Wyoming","rating":5,"text":"魔鬼塔的体量令人叹为观止，越靠近就越觉得震撼。塔身步道一小时内便可走完。步道维护良好，设施也很便利。"},
    {"name":"NatureSpirituality","rating":5,"text":"必看的上帝之作。它看起来像一根巨大的树干，美丽绝伦。这里的氛围神圣而庄严，值得为之付出时间和门票钱。"},
    {"name":"EarlyBirdParker","rating":4,"text":"一定要早点到！停车场不大，很快就会停满。进去之后，景色相当壮观。秋冬季节人较少，风景同样迷人。"},
    {"name":"QuickStopTraveler","rating":3,"text":"亲眼看一次确实很震撼，但老实说，大约一个小时就能把整个纪念地转完。如果你途经怀俄明州，可以顺路来看看，但我不会专程为此出行。"},
    {"name":"ChandraS","rating":2,"text":"我们光等进那个小停车场就花了45分钟。游客中心小得可怜，还挤满了人。而且热得要命。我们在步道上走了10分钟就放弃了。花了35美元堵在车里晒太阳，然后掉头回去。"}],
  "dinosaur-nm-co": [{"name":"FossilHunter_UT","rating":5,"text":"世界上几乎没有任何地方能像恐龙墙一样展示如此数量庞大的恐龙化石——近1500块恐龙骨骼直接裸露在崖面上！游客甚至可以亲手触摸这些骨骼。"},
    {"name":"CanyonExplorer","rating":5,"text":"这里有一条全程铺设的精彩风景驾车路线，景色堪比大峡谷。哈珀斯角步道以适度的体力换来丰厚的回报——全程仅略超两英里往返。"},
    {"name":"PeacefulPark","rating":4,"text":"绝对值得专程驱车前来，是我们在科罗拉多和犹他州公路旅行中最喜欢的地方之一。美丽而宁静——路上、观景台和步道上游客寥寥无几。"},
    {"name":"LongDriveThere","rating":3,"text":"化石采石场很酷，但公园地处偏远，需要长途驾车才能抵达。看完化石墙、完成一条风景驾车路线后，便没有太多内容能继续吸引注意力了。"},
    {"name":"purenz123","rating":2,"text":"我们在暑假期间从斯廷博特临时决定驾车前往。往返途中景色不错，但相当荒凉。就算带着孩子，纪念地本身也只值得花一个小时左右。你还能顺便看到科罗拉多州不那么光鲜的一面，比如克雷格——落基山脉污染最严重的燃煤电厂就在那里，也是你在斯廷博特附近看到大片枯树的主要原因。真希望当时省下那笔油钱。"},
    {"name":"Brad_Y","rating":2,"text":"我给它打平均分，是因为如果当天往返的话路程实在太长。公园本身还不错，但离格兰德章克申或斯廷博特斯普林斯以外的任何城市都太远，不值得专程跑这么远。不值得为了来这里和回去就花6到8小时开车，更别说在公园里的时间了。在犹他州一侧游览只需约一小时。入口城镇詹森和恐龙镇几乎没有任何服务设施。"}],
  "ellis-island-ny": [{"name":"ImmigrantDescendant","rating":5,"text":"令人印象深刻的博物馆，我在这里重走了祖先的足迹。建筑宏伟壮观，众多展览都值得细细品味，语音导览非常丰富。这是一次关于移民历史的及时回望。"},
    {"name":"HistoryBuff_NYC","rating":5,"text":"强烈推荐安全帽导览——这是一种小团体参观方式，带你探访不同建筑，亲身了解移民的生活。请预留充裕的时间来参观游览。"},
    {"name":"CrowdedMuseum","rating":3,"text":"请早点到达，在博物馆后期变得拥挤嘈杂之前参观，否则很难静心浏览展览。渡轮处的安检队伍可能很长，寒冷天气下等候时间可达约两小时。"},
    {"name":"OverpricedCafe","rating":2,"text":"岛上的餐厅供应典型的美式菜肴，但鉴于选择极为有限，价格却高得离谱。渡轮体验令人失望，感觉像是赶牛入栏。本以为这样一处历史名胜应该更有品质。"}],
  "garden-of-the-gods": [{"name":"ColoradoLocal_CS","rating":5,"text":"众神花园最让我喜爱的地方：免费、交通便利，而且美不胜收！步道维护良好，许多步道对行动不便的游客也无障碍通行。"},
    {"name":"FamilyHiker2024","rating":5,"text":"这里美得令人窒息，维护良好，停车也是免费的。长1.5英里的珀金斯中央花园步道适合轮椅通行，途经亲吻骆驼等所有主要景点。"},
    {"name":"WeekendVisitor","rating":4,"text":"公园内有21英里步道，完全免费——包括停车。汽船岩是一大亮点。这个地方实在挑不出什么毛病。"},
    {"name":"PeakSeasonCrowds","rating":3,"text":"除了旺季可能过于拥挤之外，众神花园几乎无可指摘。夏季周末，停车场乱成一锅粥，步道上人流如织。"},
    {"name":"344glennf","rating":2,"text":"众神花园无疑是个不错的游览地。不过，避开周末来访。交通和人群实在太多。景色虽好，但依我之见有些名不副实。"},
    {"name":"Brian_R","rating":2,"text":"它不值得那些溢美之词。另一位徒步者的反应和我一样，称其为\"众神花园商城\"。这里全是铺装步道，一条道路蜿蜒穿行其中，供人驾车浏览。虽然确实有一些壮观的红岩，但与亚利桑那州的部分地区，或得克萨斯州大弯曲国家公园那连绵数英里的类似地貌相比，差得远了。对于带着幼儿的家庭来说是个不错的去处，是个安全的玩耍、消耗精力的地方。"}],
  "gates-of-the-arctic-ak": [{"name":"WildernessSeeker_AK","rating":5,"text":"美丽而偏远——造访美国参观人数最少的国家公园，是一段非凡的体验。飞越这片壮美的土地，极目所及皆是自然，令人窒息。"},
    {"name":"ArcticCamper","rating":5,"text":"在这片广袤天穹下的荒野里露营，享受漫漫长昼，是一种不可错过的享受。乘坐金鹰探险公司的飞机降落在冻原上，体验绝妙。"},
    {"name":"JohnRiverPaddler","rating":4,"text":"九月中旬在约翰河沿岸露营了10天。由于那一带正在经历干旱，河流流速较慢，野生动物也较少，但徒步体验极佳，我们看到了大量野生动物的足迹。"},
    {"name":"ExpensiveAccess","rating":2,"text":"只能从周边几个小镇乘飞机前往，费用极为高昂。附近的小木屋破旧、脏乱，不适合普通游客。这绝对不是休闲度假的目的地。"}],
  "gettysburg-nmp-pa": [{"name":"CivilWarScholar","rating":5,"text":"站在葛底斯堡的战场上，你会在心中穿越回那个年代。可做的事情很多——循环全景画、博物馆、巴士游览、护林员带领的步行参观。你需要多天时间才能尽兴。"},
    {"name":"GuidedTourFan","rating":5,"text":"订一辆巴士，跟着超级博学的导游游览两小时吧。通过博物馆预约的私人导游费用为63美元两小时——非常值得。这是必游之地。"},
    {"name":"HistoryTeacher_PA","rating":4,"text":"国家公园管理局将这里维护得干净整洁、与时俱进，令人称叹。新建博物馆非常精彩，循环全景画更是亮点。导游巴士游览绝对值得。"},
    {"name":"NotMyThing","rating":3,"text":"如果你对内战历史不感兴趣，这里可能不适合你。本质上，这就是一片散落着纪念碑的大片田野。没有导游的话，很难理解眼前景物的重要意义。"},
    {"name":"Bronco7766","rating":2,"text":"我去过很多内战战场和博物馆，可以说葛底斯堡博物馆与游客中心是其中最差的一个。设施相当新，也很漂亮，但展示的解说信息、文物，尤其是那部影片，实在令人失望。虽然有一些非常独特的原版展品，但几乎没有任何内容能反映普通士兵对战争和战役的视角。那部影片花了足足20分钟宣扬政治倡导内容，而关于实际战役的内容不足10分钟。循环全景画很不错，也是一种非常独特的展示方式，值得一看；但与亚特兰大循环全景画相比，后者规模更大，对整场战役的全貌呈现也更为宏观。"}],
  "going-to-the-sun-road": [{"name":"MontanaRoadTripper","rating":5,"text":"游览冰川国家公园时，太阳之路绝不容错过。冰川侵蚀形成的山峰与山谷，景色无与伦比。我们在途中还发现了山地山羊的身影！"},
    {"name":"RedBusTourist","rating":5,"text":"那些舒适的红色老巴士经过全面翻新，车顶可以敞开拍照。司机见多识广、友善热情，并频繁停车供乘客在瀑布旁拍照留念。"},
    {"name":"ScaredDriver","rating":3,"text":"我被吓得魂飞魄散！这条路窄得令人发指，旁边就是令人胆寒的悬崖。开大型车辆的游客请勿轻易尝试，否则只会白手心冒汗。不过，如果你能接受，沿途景色确实美不胜收。"},
    {"name":"BumperToBumper","rating":2,"text":"从西入口到东入口全程车辆拥堵，非常拥挤。停车区不多，想要下车好好观景，就得极早到达，或者干脆避开旺季。"}],
  "golden-gate-nra-ca": [{"name":"BayAreaBiker","rating":5,"text":"金门游憩区对于热爱户外的人来说选择十分丰富。海角地区的道路已重新铺装，骑行体验更胜从前。从鹰山俯瞰，景色令人惊叹。"},
    {"name":"PhotoSpot_SF","rating":5,"text":"多处停车区和观景台可直接眺望旧金山、恶魔岛、海湾、太平洋和金门大桥。是摄影的绝佳地点。"},
    {"name":"DogWalker_Crissy","rating":4,"text":"克里西菲尔德是遛狗和带孩子的好去处，环境安全，以家庭活动为主。这里是全美最大的城市国家公园，面积近81,000英亩。"},
    {"name":"TrafficNoise","rating":3,"text":"公园内道路纵横，无论走到哪里都难逃车辆噪音。景色虽美，但感觉更像一座城市公园，而非国家游憩区。周末停车较为困难。"},
    {"name":"RoadTripperUSA","rating":2,"text":"本应是自然之地，却被太多道路切割得七零八落。马林海岬附近，车辆噪音彻底破坏了游览体验——你永远无法离繁忙的道路或满载旅游大巴的停车场超过一步之遥。海雾让能见度变得随机，每天都是一场赌博。与真正的荒野公园相比，你会意识到这里不过是路边风景的高配版。周末停车是噩梦，每处观景台都人头攒动，排队等候不过是为了看一个明信片上随处可见的风景。"}],
  "guadalupe-mountains-tx": [{"name":"TexasPeakBagger","rating":5,"text":"瓜达卢佩峰是我最喜欢的徒步路线之一。从山顶望去，卡皮坦峰是公园内最具标志性的景观。晴天时，视野可延伸至100英里以外。"},
    {"name":"FamilyHiker_TX","rating":4,"text":"这是一处鲜为人知的国家公园宝藏。曼萨尼塔泉步道短小易行，可欣赏倒映着山峦的天然水塘，美不胜收。人流量极少。"},
    {"name":"ToughClimb_2024","rating":3,"text":"攀登瓜达卢佩峰颇具挑战——包含休息时间，我们一家大约花了7小时。即使山脚下天气温暖，山顶也要做好迎风受寒的准备。"},
    {"name":"LimitedServices","rating":2,"text":"本想给四星，但游客中心关门时间早得离谱，而且下班后唯一开放的厕所状况堪忧。地处偏远，附近无食物或住宿供应。"}],
  "havasu-falls": [{"name":"CanyonBackpacker","rating":5,"text":"这是我见过的最美丽的地方之一——水从红色峭壁倾泻而下，流入湛蓝碧绿的水潭。这是大峡谷中的世外桃源，每一步跋涉都值得。"},
    {"name":"ThirdTimeVisitor","rating":5,"text":"第三次来，也是最美的一次！穆尼瀑布需要攀爬狭窄陡峭的岩石通道，包括梯子和抓手。洗手间出乎意料地干净，几乎没有虫子。"},
    {"name":"CrowdedParadise","rating":3,"text":"本以为是一处偏远绿洲，却被营地的游客数量震惊了。直升机接送服务进一步加剧了拥挤程度。景色虽美，但并非我所想象的那种静谧逃世之地。"},
    {"name":"DangerousHike","rating":2,"text":"这条徒步路线存在危险——每年都有很多人在此受伤。进去大约花了5小时，出来花了7小时。营地的松鼠会偷走任何无人看管的食物。不适合普通徒步者。"}],
  "horseshoe-bend": [{"name":"SunsetPhotographer","rating":5,"text":"科罗拉多河这处马蹄形弯道令人叹为观止。建议在黄金时段造访，光线如梦如幻——标志性的碧绿水湾在橘红色悬崖的映衬下熠熠生辉。"},
    {"name":"PageDayTripper","rating":4,"text":"必游自然奇景之一。从停车场步行前往相对轻松，但请务必戴帽子、涂防晒霜，并多带水——沿途没有任何遮阴。靠近悬崖边缘时请格外小心。"},
    {"name":"ParkingLotWoes","rating":3,"text":"停车需付10美元，但停车场对于进出的游客来说并不宽裕。清晨或傍晚是最佳游览时段。景色虽然惊艳，但这里实际上只有一个观景点——看完、拍完照就没了。"},
    {"name":"OverhypedSpot","rating":2,"text":"完全被过度炒作的网红打卡地。在烈日下毫无遮阴地走完一个1.5英里往返路程，就为了看一处河湾。人山人海，大家都在险峻的悬崖边争抢自拍位置。"}],
  "independence-hall-pa": [{"name":"HistoryPilgrim","rating":5,"text":"站在这个房间里，杰斐逊、富兰克林、汉考克、华盛顿、汉密尔顿和麦迪逊曾在此做出塑造国家命运的无畏抉择，令人心潮澎湃。必游之地。"},
    {"name":"PhillyTourist2024","rating":5,"text":"导览非常精彩——大约40分钟，内容丰富详实。护林员非常擅长将游客带回那个年代。入场免费！请提前在网上取票。"},
    {"name":"QuickVisit_PA","rating":4,"text":"费城必游的核心景点。对面的游客中心提供各景点门票、纪念品商店和洗手间。步行即可到达自由钟。"},
    {"name":"NeedsRenovation","rating":3,"text":"室内外均有不少油漆剥落，亟需翻新。导览时间较短，不允许自行参观。历史意义重大，但实体观感令人有些失望。"},
    {"name":"rft0000","rating":2,"text":"导游不错，导览也很好，但我们无法参观二楼——理由是\"戒严令\"，这是一个糟糕透顶的理由，完全是出于政治目的。在国会厅，导游不愿回答问题，只想照本宣科，急着把游客赶完走，整体体验显得非常仓促。整个参观过程就像是一条流水线。"}],
  "jewel-cave-nm-sd": [{"name":"CaveExplorer_SD","rating":5,"text":"导览非常有趣、愉快，组织得井井有条。洞穴中的\"培根\"岩石造型令人着迷。这是黑山地区一处物超所值的好景点——成人风景游览票仅需8美元。"},
    {"name":"FamilyCaver","rating":4,"text":"洞穴内岩石造型精彩，老少咸宜。我们的导游知识渊博，对孩子们的问题耐心十足。行走路线轻松，非常适合家庭游览。"},
    {"name":"StairClimber","rating":3,"text":"风景游览路线有些费体力，全程需上下700多级台阶。请至少提前3天预订，因为导览名额抢手。膝盖或行动有问题的游客不太适合参加。"},
    {"name":"WindCaveBetter","rating":2,"text":"前一天刚参观完风之洞，再来朱厄尔洞感觉有些重复，也不如前者令人印象深刻。游客中心很不错，但洞穴本身并未让我们感到惊艳。如果在黑山只有时间参观一处洞穴，请选择风之洞。"}],
  "kobuk-valley": [{"name":"SandDunesFlyer","rating":5,"text":"降落在沙丘上是一次绝妙的体验。飞越这片壮美的土地，极目所及皆是自然，令人窒息。这里的与世隔绝令人心旷神怡。"},
    {"name":"ArcticAdventurer","rating":4,"text":"乘坐金鹰探险公司的飞机飞抵科布克谷，体验非常棒。我们在公园内降落，四处走走，有充足时间拍照。沙丘令人称奇，周围景色也美不胜收。"},
    {"name":"RemoteAndExpensive","rating":3,"text":"前往不易——只能从几个小镇乘飞机抵达。体验别具一格，但为了走几步沙丘，花费极为高昂。主要吸引那些立志打卡所有国家公园的游客。"},
    {"name":"SketchyLodge","rating":2,"text":"科布克河小屋与网上图片相差甚远。小卖部和小屋环境很差，脏乱破旧，让人望而却步。访客基础设施极为匮乏。"}],
  "lava-beds-nm-ca": [{"name":"CaveAdventurer_CA","rating":5,"text":"真正的隐藏宝藏！洞穴难度各异，从铺装路面到需要爬行和攀爬的洞穴应有尽有。我们原计划只游览几小时，却最终待了整整一天，还意犹未尽。"},
    {"name":"LavaTubeLover","rating":5,"text":"游客中心的护林员非常热情，根据我们的经验水平推荐了合适的熔岩管洞穴。印第安岩画和洞穴壁画为整个体验增添了深厚的历史底蕴。"},
    {"name":"PreparedExplorer","rating":4,"text":"请穿好鞋、多带手电筒，并加满油再出发——这处纪念地地处荒无人烟的偏远地带。游客中心有安全帽出售，价格为8.30美元。公园内无任何食物出售。"},
    {"name":"TooRemote_CA","rating":2,"text":"开了好几小时的车来这里，却发现这里真的在天涯海角。这些洞穴不过是地上的黑洞。看过一处熔岩管，就等于看过所有。除非你恰好在附近，否则不值得专程前往。"}],
  "liberty-bell-center-pa": [{"name":"AmericanHistory101","rating":5,"text":"费城必去之地——这是美国历史上极具象征意义的铜钟。可以出乎意料地近距离观看真正的钟。绝佳的拍照地点，游客们都很有礼貌、相互谦让。"},
    {"name":"FreeTourFan","rating":4,"text":"无需门票，且距独立厅步行可达。博物馆详细记录了这口钟的历史，内容非常完整。工作日上午参观几乎无需等待。"},
    {"name":"SecurityLineHater","rating":3,"text":"进门时需要经过类似机场的安检程序。钟本身大约5分钟就能看完。博物馆内容较为有限，陈列简约。历史意义重要，但作为景点观感一般。"},
    {"name":"DisappointedTourist","rating":2,"text":"看完钟——也就30秒——就没什么了。不能触摸。排队过安检的漫长等待与最终的收获完全不成正比。建议跳过排队，晚上直接从窗外看就好了。"}],
  "little-bighorn-battlefield-mt": [{"name":"BattlefieldHistorian","rating":5,"text":"这是我参观过的最好的战场纪念地之一。45分钟的护林员讲解非常详尽，令战役跃然眼前。场地景色优美而肃穆。"},
    {"name":"CrowTourFan","rating":5,"text":"强烈推荐参加阿普萨阿洛克旅游公司（克劳部落）的一小时导览。导游从美国原住民的视角讲述他们保卫家园的历史、文化和生活方式。"},
    {"name":"AudioDriveFan","rating":4,"text":"战场上的道路规划合理，设有停车点和详细的解说牌。驾车聆听语音导览是体验该地的好方式。建议自带零食，附近餐厅不多。"},
    {"name":"LimitedHours","rating":3,"text":"该地并非每天开放——每周仅开放三至四天。前往前请务必查询开放时间。每车收费25美元，持国家公园年票可免费入场。"},
    {"name":"BrakiWorldTraveler","rating":2,"text":"我非常期待参观这处著名的战场，却只能在紧闭的大门外和围栏旁远望。这里并不是每天开放，每周只开放三四天——对于如此重要的历史遗址来说，实在令人失望。出发前务必核实开放时间。开了好几小时的车赶到这里，到头来大门紧锁，无法进入，彻底体验战场历史，是一次极大的遗憾。"}],
  "mesa-verde-cliff-palace-co": [{"name":"CliffDwellingFan","rating":5,"text":"在梅萨维德，崖宫是必游景点。这是梅萨维德规模最大的崖居——世界奇迹之一。每人4美元，参加一小时导览即可入内。"},
    {"name":"ArchaeologyNerd","rating":5,"text":"导览需要攀下高低不平的石阶，并分别攀登3处独立梯子——对于恐高者有些挑战，但绝对值得。导游专业且讲解详尽。"},
    {"name":"EarlyBirdTourist","rating":4,"text":"夏季请在开园时到达，以便参加护林员带领的导览，因为名额很快便会售罄。进入崖居的唯一方式是参加导览；否则只能在远处观看。"},
    {"name":"HeightsFear","rating":3,"text":"不错，但不参加导览也可以从观景台看到崖宫。回程需要爬100英尺高的梯子，并非人人都能应对。通往高原的道路漫长而蜿蜒。"},
    {"name":"Ikbenbijnaopvakantie","rating":2,"text":"团队人数非常多——我估计有25到30人。我们参观时毫无遮阴。人太多让导览显得匆促，很难听清护林员的讲解，也很难看清任何东西。一处本应是特殊考古奇迹的地方，体验起来却像流水线作业。环境无疑令人印象深刻，但由于导览人数过多，整体体验令人失望。"}],
  "monument-valley-navajo-az": [{"name":"NavajoTourGuest","rating":5,"text":"一次精彩的体验，让我学到了很多，也感受到了纳瓦霍人的力量与温情。这里的沙漠景观让你大开眼界。这是美国最大的保留地，面积达27,000平方英里。"},
    {"name":"ScenicDrive_163","rating":5,"text":"163号公路是全美最具标志性的驾车路线之一。风景独特而震撼。如果你前往大峡谷，又有时间的话，一定要来纪念碑谷看看。"},
    {"name":"RoughRoadDriver","rating":3,"text":"谷地环形公路状况极差——坑坑洼洼、沙尘飞扬、颠簸不堪。要么开四驱车，要么参加有导游的吉普游览。开普通轿车的游客看起来颇为惶恐。"},
    {"name":"DustyDisappointment","rating":2,"text":"整条环线在一条让人牙关发抖的糟糕土路上开约两小时。风景还不错，但公路旁免费就能看到最精彩的部分，完全不必花钱买门票进去。"}],
  "muir-woods-nm-ca": [{"name":"RedwoodLover_SF","rating":5,"text":"缪尔森林让你真切感受到大自然的力量。漫步于参天红杉之间，宁静、踏实、令人心生谦卑。主步道为木栈道，连轮椅都可畅行其上。"},
    {"name":"NatureEscape_CA","rating":5,"text":"宁静而美丽，参天大树和如画的溪流交相辉映。那些大树的雄伟体量只有亲眼所见才能体会——它们确实高耸入云，令人仰望。"},
    {"name":"CrowdAvoider","rating":4,"text":"早点来或晚点来，以避开人群——因为每个人都爱这里！如果走一些冷门步道，可以避开最拥挤的区域。这里有一家温馨的咖啡馆和一家很棒的书店。"},
    {"name":"NotWorthVisiting","rating":2,"text":"请务必提前预约，因为入口附近几乎没有手机信号。停车位很快就会占满。大老远赶来，不过就是在一些大树间走一小段铺装路。名过其实。"}],
  "na-pali-coast": [{"name":"KauaiBoatTour","rating":5,"text":"如同人间天堂的一隅，巍峨峭壁、翠绿山谷和湛蓝海洋令人叹为观止。导游们热情友好，讲述了许多关于海岸和当地文化的精彩故事与历史。"},
    {"name":"HelicopterViewer","rating":5,"text":"从空中俯瞰，美得令人难以置信，令人窒息。山脉壮观至极，那种地貌无法用语言形容——你必须亲眼看到。纳帕里崎岖的海岸没有公路可达。"},
    {"name":"RaftAdventurer","rating":4,"text":"乘坐那帕里海盗的高速橡皮艇颠簸刺激，需要一定体力，但绝对物有所值。我们近距离看到了海豚、海龟和海底洞穴。"},
    {"name":"SeasickSufferer","rating":2,"text":"早上出海时风浪可能相当汹涌。如果你有任何晕船倾向，请务必谨慎。我大半程都趴在船舷上呕吐。即便景色迷人，整个体验也让我痛苦不堪。"}],
  "natural-bridges-nm-ut": [{"name":"UtahGemFinder","rating":5,"text":"犹他州的隐藏宝藏之一！沿着峡谷边缘9英里的环形驾车路线，可欣赏3座天然桥和一处崖居。是我们在公路旅行中走过的最棒的短程徒步路线之一。"},
    {"name":"DarkSkyFan","rating":5,"text":"这里是全球首个国际暗夜公园，拥有北美最暗的夜空之一。我们在公园里只遇到了另外三个人。请慢下来，细细感受这颗宝石的宁静。"},
    {"name":"QuickStopVisitor","rating":4,"text":"这是一处宁静、低流量的好去处，半天便可游览完毕。整个区域内我们遇到的人不到15人。下到桥边的徒步路较为轻松，但返程更具挑战性。"},
    {"name":"MixedEmotions","rating":3,"text":"需要绕一段路——距US-191公路约40分钟车程。景区小巧精致，但说实话，与犹他州其他公园的天然拱门相比，这里的桥梁并不算特别壮观。如果有时间值得一看，但算不上必游之地。"},
    {"name":"DisabledTraveler","rating":2,"text":"我行动不便，无法徒步，也许因此错过了最精彩的部分，但我和丈夫都感到有些失望。从公路上的观景点很难感受到这些桥的魅力，不徒步进入峡谷就很难真正欣赏到天然桥。20美元的门票费，如果不打算徒步，感觉不值。犹他州有很多其他美丽的地方，既更易于通行，又更物有所值。"},
    {"name":"EuropeanVisitor","rating":1,"text":"别浪费时间和金钱了。令人非常失望的纪念地。对于那些参观过莫阿布附近拱门国家公园的人来说，这里完全不值得专程前往。拱门国家公园的拱门要壮观得多，有些甚至令人叹为观止。在犹他州其他地方见识过那些宏伟景观之后，天然桥确实让人大失所望。"}],
  "niagara-falls": [{"name":"FirstTimeWowed","rating":5,"text":"这是一次令人难以忘怀的体验，绝对震撼。奔腾飞泻的水流所展现的力量与美丽令人心旷神怡，在你还未看到它之前便已远远听到了它的轰鸣。\"迷雾中的少女\"游船是必玩项目。"},
    {"name":"NightVisitor","rating":5,"text":"早晨或夜晚来访效果最佳，夜间有灯光秀。翠鸟游轮、瀑布背后之旅和惠而浦高空缆车都是必体验的项目。"},
    {"name":"TouristTrapAlert","rating":3,"text":"瀑布本身壮观无比，但令人失望的是那些俗气的配套设施——维加斯风格的赌场、鬼屋和刺眼的霓虹灯将其团团围住。市中心显得拥挤而廉价。"},
    {"name":"OverratedFalls","rating":2,"text":"尼亚加拉大瀑布被过度吹捧，而且价格离谱。票价高得出奇，食物也不值得排队。游船上人山人海。世界上比尼亚加拉更美的瀑布多的是。"}],
  "oregon-caves-nm-or": [{"name":"CaveEnthusiast_OR","rating":5,"text":"我们参加过的最棒的洞穴导览！90分钟的导览组织得非常好，涵盖了超过一英里的通道、洞室和廊厅。仅需11美元每人，性价比极高。"},
    {"name":"RangerTourFan","rating":5,"text":"洞穴导览非常精彩——护林员专业且极具感染力。钟乳石、石笋和蜿蜒的通道，仿佛步入了另一个世界。"},
    {"name":"PhysicalWarning","rating":3,"text":"路线有些费体力，约有500级台阶，还有低至45英寸的矮小通道。不建议有呼吸、心脏、膝盖或背部问题的人参加。儿童须达到42英寸身高方可入内。"},
    {"name":"WaitingForHours","rating":2,"text":"夏季导览非常抢手，如不早到则会面临长时间等待或无票可买的情况。洞穴全年温度为44华氏度，请记得穿多层衣服。驾车前往洞穴章克申的路途漫长且弯道频繁。"}],
  "pacific-coast-highway": [{"name":"CoastalRoadTripper","rating":5,"text":"世界上最壮观的驾车路线之一。崎岖的海岸线、陡峭的悬崖和纯净的海滩令人叹为观止，包括大苏尔和标志性的比克斯比大桥。沿途有众多观景停车点可供拍照。"},
    {"name":"SouthboundDriver","rating":5,"text":"对于热爱壮丽景色的人来说，这是美国最棒的公路。一定要选择向南行驶。傍晚太阳悬挂在太平洋上空时光线最为迷人。"},
    {"name":"SpringTimeDrive","rating":4,"text":"春季气候宜人、绿意盎然、野花盛开，是驾车最佳时节。由于各小镇之间距离较远，出发前请加满油。如果你容易晕车，请注意沿途弯道频繁。"},
    {"name":"RoadClosureFrustration","rating":2,"text":"名过其实，而且道路预警管理混乱。一次道路封闭迫使我们绕了一大段路，而且指示牌稀少。出发前务必确认道路是否畅通。靠近洛杉矶的路段不过是普通公路。"}],
  "painted-hills": [{"name":"OregonNatureLover","rating":5,"text":"这是美国最令人叹为观止的自然体验之一。图片完全无法呈现其真实之美！卡罗尔峰步道多费些力气，可换来令人叹为观止的全景视野，绝对值得。"},
    {"name":"PhotographerPro","rating":5,"text":"公园面积不大，却惊艳异常。有人认为它可与大峡谷、布莱斯峡谷和拱门相媲美。彩绘湾步道色彩最为鲜艳夺目，但路程极短。"},
    {"name":"SizeExpectation","rating":3,"text":"面积比我预想的要小得多——并非大片绚烂多彩的山丘。主景区就是照片上看到的那样。绝对值得一游，但请做好心理预期。"},
    {"name":"LongDriveShortVisit","rating":2,"text":"从任何较大城市驾车前来都需要一段时间，而且地处相对偏僻。夏季高温让徒步颇为困难。大约一小时便能将所有景点看完。不值得专程前往。"}],
  "petrified-forest-az": [{"name":"ArizonaGemFinder","rating":5,"text":"亚利桑那州最被低估的宝藏之一，值得花一整天探索。奇异的地貌、绚丽的色彩和独特的岩石形态令人叹为观止。仅报纸岩一处就有超过650幅岩画。"},
    {"name":"PaintedDesertFan","rating":4,"text":"这是一个可以多处停靠的驾车穿越公园。俯瞰彩绘沙漠的观景台、蓝色台地的多彩地质景观，以及彩虹森林的古生物博物馆，各有精彩。"},
    {"name":"HighAltitudeWarning","rating":3,"text":"海拔在5300至6200英尺之间，不习惯高原环境的游客可能在运动时感到吃力。夏季气温极高。对大多数游客而言，半天游览已足够。"},
    {"name":"UglyDrive","rating":1,"text":"漫长而枯燥的车程。到了之后依然枯燥。没有拖车露营的话，最近的酒店也在20英里以外。如果你去过布莱斯峡谷、锡安或国会礁，这里一定会让你失望。"}],
  "pictured-rocks": [{"name":"MichiganExplorer","rating":5,"text":"一处隐藏的宝藏，值得给自己几天时间从陆地和水面两种角度去探索。岩石的形态和色彩如梦如幻——戏剧性的多彩悬崖和独特的砂岩造型令人叹服。"},
    {"name":"CruiseHighlight","rating":5,"text":"游船是我们密歇根上半岛之旅的最大亮点。海滩、步道和瀑布让这次旅行画上了圆满句号。这里拥有瀑布、步道、绝景和一座灯塔，是一处真正的宝藏。"},
    {"name":"KayakAdventurer","rating":5,"text":"皮划艇是此生最难忘的体验之一！我们划行了五英里，探索洞穴，在石拱下穿行，沉浸在美丽的自然风光之中。绝对值得。"},
    {"name":"LongBoatRide","rating":3,"text":"游船是不错的风景游览方式，但时间很长，达3小时——请自备零食。八月是游览好时节，但请早到确保停车位。部分步道泥泞，维护不佳。"},
    {"name":"Dave_M","rating":1,"text":"画岩国家湖岸曾经是一处偏远的隐藏宝藏，45英里的搓板路只有勇者或冒险者才愿意跋涉。如今道路已铺设完毕，房车和摩托车畅行无阻。这反而削弱了画岩的魅力，那些曾经偏僻而原始的营地如今拥挤不堪，难以抢到。这里总共只有三处营地，约65个营位，没有淋浴，只有旱厕。想要抢到营位，早上8点前就得赶到，否则可能扑空。如果你沿着H-58公路穿越国家湖岸，请做好跟在摩托车队和房车后面慢行的准备。"}],
  "rainbow-bridge-nm-ut": [{"name":"LakePowellBoater","rating":5,"text":"这是世界上最大的天然桥，高度与自由女神像相当，跨度达275英尺。我走遍了犹他州各处拱门，而这里确实与众不同，值得一看。如果你在鲍威尔湖附近，这是绝对必做之事。"},
    {"name":"JetBoatRider","rating":4,"text":"船程单程约2.5小时，峡谷的地貌和岩石特征在沿途不断变化，十分有趣。通往拱桥的徒步路沿着一条清澈的小溪延伸。导游一再强调要尊重这处神圣遗址。"},
    {"name":"SevenHourTrip","rating":3,"text":"全程耗时7小时，且仅在特定季节运营。鲍威尔湖的风景和彩虹桥本身都令人印象深刻，但为了看一处拱门付出如此漫长的时间，未免令人踟蹰。"},
    {"name":"ExpensiveArch","rating":2,"text":"虽然印象深刻，但游船导览的费用与所得相比实在高昂。你几乎一整天都在船上，只为了用20分钟看一处岩石构造。犹他州各地有许多更实惠的拱门可供参观。"}],
  "saguaro": [{"name":"TucsonNatureFan","rating":5,"text":"巨人柱仙人掌雄伟壮观，是美国西部最具代表性的标志之一。风景驾车路线和步道维护良好。壮观的风景适合各个年龄层的游客。"},
    {"name":"DesertSunrise","rating":5,"text":"一派西部老电影的画面。沿途有许多停车点可以驻足欣赏美景或踏上步道。凉爽的月份，尤其是冬天和清晨，是最佳的体验时机。"},
    {"name":"TwoParksConfusion","rating":4,"text":"公园分为两个独立区域，驾车距离约一小时，各有自己的游客中心。两处都值得游览，但请提前规划好两处之间的驾车行程。"},
    {"name":"TooHot_Tucson","rating":2,"text":"温度超过100华氏度，四处无遮阴。游客很容易脱水。请备足防晒霜和水。夏天这里就是酷热难耐加一堆仙人掌。请在冬季来访，或者干脆放弃。"}],
  "sleeping-bear-dunes": [{"name":"MichiganProud","rating":5,"text":"密歇根湖美得无与伦比，那碧蓝的湖水美得像假的。湖岸的风景可与加勒比媲美，沙子比墨西哥某些地方还要细腻柔软。"},
    {"name":"WinterVisitor_MI","rating":5,"text":"大多数人在夏季来沙丘游览，但冬天来更令人叹为观止。每一场降雪之后，景色焕然一新，林间步道宁静祥和。皮尔斯·斯托金风景驾车路提供了绝佳的观景视角。"},
    {"name":"FamilyFunDunes","rating":4,"text":"孩子们爬沙丘玩得不亦乐乎，站在顶上俯瞰美景令人叹为观止！停车场底部设有野餐桌。请穿好鞋、戴帽子、涂防晒霜并多带水。"},
    {"name":"ExhaustedClimber","rating":3,"text":"请做好心理准备——这里不是爬一个沙丘就完事的地方。我们一家五口，只有22岁的成员成功走到了密歇根湖边。在沙地和烈日下前行极为消耗体力。"},
    {"name":"66AngelaH29","rating":1,"text":"景色确实很美，沙丘和湖泊令人惊叹；然而这里人满为患，没有片刻独处的时间。这是一个不折不扣的热门旅游区，毫无宁静或荒野感可言。我们长途驱车而来，本以为会有一次亲近自然的体验，却发现这里简直是海滩上的迪士尼乐园。停车是一场噩梦，沙丘攀爬本身也人头攒动，彻底破坏了对这片景观的任何感悟。"}],
  "statue-of-liberty": [{"name":"NYCfirstTimer","rating":5,"text":"参观自由女神像是一次令人难以忘怀的体验。这座纪念碑的气场与象征意义令人震撼不已。组织有序，信息清晰，从炮台公园乘渡轮也十分顺畅。"},
    {"name":"CrownClimber","rating":4,"text":"从蜿蜒的楼梯攀登162步即可到达王冠。王冠门票极为紧俏，通常提前一个月就会售罄。自由女神博物馆免费参观，展有原始的火炬。"},
    {"name":"WinterVisitor_NY","rating":4,"text":"冬季来访是个好选择，人没那么多。建议清早到达，避开周末。这里有一家非常棒的礼品店、咖啡馆和饮水站。博物馆既吸引人又有教育意义。"},
    {"name":"HugeDisappointment","rating":2,"text":"排队耗费了大量时间，整体体验令我极为失望。从王冠向外看受限于几扇小窗，视野极为有限。建议改乘免费的史坦顿岛渡轮——沿途就能经过雕像旁边。"}],
  "sunset-crater-volcano-nm-az": [{"name":"FlagstaffExplorer","rating":5,"text":"令人窒息的目的地，拥有绝美的火山地貌景观。近距离可以看到陡峭的黑色火山灰坡面，并在山脚下的熔岩流间漫步。"},
    {"name":"JuniorRangerDad","rating":4,"text":"游客中心设有小护林员项目，非常适合带孩子参观。护林员友善专业。有多条步道可供选择，包括一条带有火山解说牌的混凝土栈道。"},
    {"name":"ScenicDriveOnly","rating":3,"text":"确实值得一游……但主要就是一条风景驾车路，配上几段短步道。这座火山当年用熔岩和火山灰覆盖了64,000英亩的土地。地质景观颇为有趣，但大约一小时便可游览完毕。"},
    {"name":"SummerAvoid","rating":2,"text":"七八月份气温酷热，请避免在此时前来。这里能做的事不多——几条短步道加几块解说牌。与附近的大峡谷等景点相比，令人觉得平淡无奇。"}],
  "the-wave": [{"name":"LotteryWinner_AZ","rating":5,"text":"这是我见过的最令人叹为观止的天然岩石雕塑之一。照片完全无法呈现其真实之美——没有任何体验能与亲眼所见相比。这处人间奇景值得无数次参与抽签守候。"},
    {"name":"GuidedHiker","rating":5,"text":"壮观、绝美，那些色彩！全程6英里往返，难度适中，但周围地貌高度相似，建议聘请持有GPS和卫星电话的向导。每天仅限20名徒步者入内。"},
    {"name":"PermitFrustration","rating":3,"text":"参加了十多次抽签才终于获得许可证。十个名额在四个月前通过网络提前确定，另外十个名额通过当天抽签决定。抵达之后令人惊艳，但许可证制度让人抓狂。"},
    {"name":"LostWithoutGuide","rating":2,"text":"绝对值得一看，但前往波浪谷的3英里路途没有任何路标，我们迷路了好几次。在沙漠高温下令人心生恐惧。在没有向导或出色导航技能的情况下，切勿贸然尝试。"}],
  "theodore-roosevelt-nd": [{"name":"BadlandsLover_ND","rating":5,"text":"雄伟壮阔，令人叹为观止，辽阔的景观与丰富的野生动物共存。我们看到了野牛、草原犬鼠、郊狼、羚羊、鹿、麋鹿、火鸡和豪猪。一处真正的隐藏宝藏，关注度远未及其应得的程度。"},
    {"name":"ScenicDriveFan","rating":5,"text":"许多旅行者推荐以自驾方式探索公园，风景驾车路线规划合理，道路易于导航。在泰迪·罗斯福国家公园夏季露营体验绝佳——野生动物随处可见。"},
    {"name":"WildHorseFan","rating":4,"text":"家庭游客和自然爱好者乐于寻觅野牛和野马的踪影。设施维护良好，游客中心也很便于到达。来访前请做好应对天气变化的准备——北达科他州的气候可以变化莫测。"},
    {"name":"NorthUnitSkip","rating":3,"text":"北单元距南单元至少80英里，驱车前往并不太值得。南单元已能满足你的所有需求。偶尔的道路封闭可能会限制通行。"},
    {"name":"TravellerND2023","rating":2,"text":"专程驱车来此观赏野生动物，却满心失望而归。风景环线上大段路程只有稀疏的灌木和极少的动物踪影。我们游览期间，野牛群根本不在路边。当我们向游客中心工作人员请求具体的徒步建议时，他们态度冷漠、敷衍了事。与我们去过的其他国家公园相比，这里感觉开发不足，不值得横穿北达科他州长途跋涉而来。由于野火，公园部分区域一片焦土，显得荒凉萧瑟。驾车体验还算不错，但不是一个值得专程前往的国家公园。"}],
  "timpanogos-cave-nm-ut": [{"name":"CaveHiker_UT","rating":5,"text":"徒步爬上去很值！1.5英里的步道需要攀升1100英尺，全程铺装，虽然陡峭，但沿途的风景让一切都值得。护林员带领的导览穿越3处洞穴。"},
    {"name":"EducationalTour","rating":4,"text":"蒂姆帕诺格斯洞穴的导览既精彩又有教育意义。景色壮观，知识性强！请提前数周或数月预订，因为导览规模有限，名额稀缺。"},
    {"name":"SteepClimb","rating":3,"text":"值得攀登，但不要对洞穴本身期望过高。洞穴内相当凉爽，温度约为45华氏度，请记得带件运动衫。徒步路虽为铺装路面，但坡度相当陡峭，颇为费力。"},
    {"name":"NotForEveryone","rating":2,"text":"夏季高温下前往洞穴的徒步路极为艰辛——需要攀升1100英尺，遮阴极少。如果你体能一般，请放弃这个选项。与卡尔斯巴德或猛犸洞相比，这里的洞穴规模较小。"}],
  "valley-of-fire": [{"name":"VegasDayTripper","rating":5,"text":"这是那种鲜为人知、却迅速跻身必游榜首的宝藏之地。从拉斯维加斯大道出发，只需轻松驾车约一小时即可抵达。我们看到了郊狼、大角羊和各种鸟类。"},
    {"name":"WhiteDomeHiker","rating":5,"text":"1.25英里的白色圆顶步道令人叹为观止，对于有经验的徒步者挑战十足，同时也对初学者足够友好。每车10美元的票价非常合理。"},
    {"name":"VisitorCenterFan","rating":4,"text":"游客中心是一个精彩的互动空间。放眼望去，绚丽的色彩和岩石造型无处不在。大多数主要景点可以轻松地在拉斯维加斯的一日游中全部打卡。"},
    {"name":"EntryBackup","rating":2,"text":"公园只有一条车道入口，造成长达45分钟的排队等候。公园内没有加油站，食物供应也极为有限。离开城区后加油站迅速消失。请提前做好准备，否则会非常狼狈。"}],
  "voyageurs-np-mn": [{"name":"LakeExplorer_MN","rating":5,"text":"不乘船出湖，就无法真正看到或体验航海者国家公园。我们参加了大巡游，一路看到了许多秃鹰和潜鸟。风景如画的岛屿和丰富多彩的野生动物贯穿始终。"},
    {"name":"BoatTourEnthusiast","rating":4,"text":"国家公园提供的湖上游船导览绝对能提升你的游览体验。公园拥有风景优美的岛屿、历史遗址和美丽的水上体验项目。"},
    {"name":"LimitedHiking","rating":3,"text":"步道又少又短，大多数都是铺装路面。徒步步道风景不错，但没有提供任何开阔的视野。很明显，公园大部分区域只能通过水路到达。"},
    {"name":"NoBoatNoFun","rating":2,"text":"没有船，这里基本上无事可做。你要么自带水上交通工具，要么依赖有限的公园游船导览。这是美国本土48个州中可及性最差的国家公园。对于徒步爱好者来说令人失望。"}],
  "waimea-canyon": [{"name":"KauaiExplorer","rating":5,"text":"太平洋上的大峡谷！绝对值得一看——沿着一条狭窄蜿蜒的山路上上下下，两旁景色迷人，最终抵达山顶，视野开阔壮丽。建议清晨前来，人相对较少。"},
    {"name":"RainbowSpotter","rating":5,"text":"峡谷的景色似乎随着一天中时间的变化而不断变幻。你甚至可能看到一道彩虹，夏季尤为常见。峡谷绵延超过14英里，深度超过3,600英尺，令人叹为观止。"},
    {"name":"GuidedTourFan_HI","rating":4,"text":"导游对各个岛屿了如指掌，分享了历史、神话和个人故事。峡谷美不胜收，导游也知道拍照和观景的最佳停留地点。"},
    {"name":"MuddyHiker_Kauai","rating":3,"text":"怀梅阿峡谷步道难度中等，但泥泞不堪，有些陡峭的上下坡段。你可以下到一处瀑布旁，在冰凉的水中游泳。请务必穿好鞋，否则你会后悔的。"},
    {"name":"zail_c","rating":1,"text":"弯道又多又窄，路面破损严重，厕所老旧破败，没有洗手液和擦手纸——还不如直接去树丛里解决，干净多了。峡谷景色还算不错，但依我之见并不值得。整个公园都亟需大规模整修。夏威夷把从游客身上收刮的那么多税都花哪里去了？带上你的晕车药和自备纸巾吧。我给一星，因为没有更低的选项，别浪费时间和金钱在这里了。"}],
  "wupatki-nm-az": [{"name":"PuebloExplorer_AZ","rating":5,"text":"亚利桑那州最棒的普韦布洛遗址！围墙经过修复，但600年前的遗迹依然令人叹为观止。可以眺望彩绘沙漠，而且不会有大峡谷或其他周边景点那样的人潮。"},
    {"name":"JuniorRangerFamily","rating":4,"text":"这是一处非常棒的国家公园，游客中心后面的铺装小路步行即可轻松抵达古老的普韦布洛遗址。护林员热情友好，我的孩子们也成功完成了小护林员徽章的考核。"},
    {"name":"HotSummerWarning","rating":3,"text":"这一带比附近的日落火山口热得多，夏季请在上午游览。游客中心内容丰富，但遗址本身规模较小。值得一游，但不算独立景点。"},
    {"name":"PassThroughOnly","rating":2,"text":"值得一游，但与梅萨维德或查科峡谷相比并不突出。遗址经过部分修复，规模相对较小。30至45分钟便能看完所有内容。更像是一处顺路的路边停靠点，而非一处独立的景点。"}],
  "carter-g-woodson-home-national-historic-site": [{"name":"HistoryBuff_DC","rating":5,"text":"虽然房子里的陈设不多，但导游极为亲切且博学多闻。我们学到了很多，也进行了精彩的交流。这栋房子坐落在一个可爱的街区，室内还设有一家小书店。"},
    {"name":"NPS_Passport_Fan","rating":4,"text":"陈设上的不足被导游们渊博的知识所弥补。几个房间几乎空空如也，陈设稀疏，但护林员就\"黑人历史之父\"作了一场精彩的演讲。"},
    {"name":"WanderlustMom22","rating":3,"text":"参观故居必须跟团，而且每周只开放三天。前往前请务必查看网站，因为开放时间非常有限。参观时间很短，但如果你恰好在附近，还是值得一看的。"},
    {"name":"DCWeekender","rating":2,"text":"我们到达时大门紧闭，但网站上明明显示开放。开放时间极为有限，也没有任何指示牌。外面的国家公园管理局工作人员对克拉拉·巴顿或导览信息一无所知。"}],
  "cedar-creek-and-belle-grove-national-historical-park": [
    {"name":"VA_RoadTripper","rating":4,"text":"驾车游览路线标识清晰，沿途指示牌一目了然，非常容易跟随。贝尔格罗夫是一座建于1797年的美丽石灰石庄园，提供成人12美元的导游参观服务。"},
    {"name":"HistoryNovice","rating":3,"text":"如果你走I-81公路且对内战历史感兴趣，这里是个不错的歇脚之处。景区主要由开阔的田野组成，仅有有限的土工防御工事和大炮，以及几座纪念碑。"},
    {"name":"QuickStopCarl","rating":2,"text":"这里真的没有什么值得参观或体验的东西。很难凭借自身价值为这次参观找到正当理由。游客接待站位于大街上的一个条形商场内。"}],
  "chamizal-national-memorial": [
    {"name":"BorderlandExplorer","rating":5,"text":"一处真正珍贵的历史场所，展览详尽精美，介绍了美墨两国和平解决边界争端的历史。护林员们非常乐于助人。"},
    {"name":"ParkStamper_Mike","rating":4,"text":"令人赞叹的游客中心，维护良好的园区，建筑物上绘有色彩斑斓的精美壁画。了解1963年边界解决方案的好去处，免费入场。"},
    {"name":"NPS_Completionist","rating":2,"text":"参观过逾120处NPS景点后，我发现查米萨尔是信息最为匮乏的NPS地点之一。提供的信息极为有限，参观时间不需超过30分钟。"},
    {"name":"TXTraveler99","rating":3,"text":"它所纪念的事件在埃尔帕索以外鲜为人知。公园环境适合散步，但游客中心规模较小。开放时间为上午10点至下午5点，最多只能作为集邮盖章的打卡地点。"}],
  "charles-pinckney-national-historic-site": [
    {"name":"LowcountryLover","rating":5,"text":"非常棒的历史遗址！资料详尽，环境优美。影片对于理解查尔斯·平克尼18世纪末期的生活世界至关重要，解说出色。"},
    {"name":"SCFamilyTrip","rating":4,"text":"公园护林员亲切友善。免费青少年护林员项目用孩子们能理解的语言向他们介绍公园。园区环境宜人，参观体验平和舒适。"},
    {"name":"HistoryWalker","rating":3,"text":"景区内可看可做的并不多。即便认真阅读每块展板、观看影片并步行游览小道，也很难在此消磨两个小时。"},
    {"name":"QuickVisitPete","rating":2,"text":"平克尼的原始建筑已无一留存，只能看到它们原来所在位置的轮廓。如果就在芒特普莱森特附近，可以顺道一游，但不值得专程前往。"}],
  "chesapeake-and-ohio-canal-national-historical-park": [
    {"name":"BikeTheTowpath","rating":5,"text":"真是一大享受！沿美丽的波托马克河延伸184英里，平坦无车的小径，非常适合步行、跑步或骑行。C&O运河博物馆收藏了大量历史照片和故事。"},
    {"name":"OutdoorAdventurer","rating":5,"text":"如果你热爱探险和户外活动，C&O运河就是你的理想去处。这里提供运河船游览，还可以免费乘坐渡槽并下行至船闸。景色壮美。"},
    {"name":"GeorgetownWalker","rating":4,"text":"乔治敦境内的C&O运河段景色怡人，漫步其间令人心旷神怡，沿途设有历史标志牌，可与DC其他景点轻松结合游览。"},
    {"name":"FrustratedHiker","rating":2,"text":"公园亟需改善。当地游客不清理宠物粪便，垃圾随处可见，严重影响自然体验。步道状况泥泞，部分路段因洪水关闭。"}],
  "chickamauga-and-chattanooga-national-military-park": [
    {"name":"CivilWarBuff_GA","rating":5,"text":"丰富的历史宝藏！游客中心收藏着令人叹为观止的枪械系列，并提供出色的战役概述影片。NPS应用程序的语音导览极为精彩，建议预留至少6小时游览全程。"},
    {"name":"FamilyHistory101","rating":5,"text":"无论是探寻历史还是野餐休闲，这里都值得一游。佐治亚州一侧的一切均免费开放，维护良好，比田纳西州一侧提供更丰富的体验内容。驾车穿越战场的旅途美不胜收。"},
    {"name":"WeekendExplorer","rating":4,"text":"承载着厚重历史的好去处，有标识清晰的观光道路，可到达大多数主要景观附近。请务必下车，充分利用丰富的步道网络。"},
    {"name":"CasualTourist","rating":3,"text":"田纳西州一侧的波因特公园需收取门票和停车费，但视野绝佳。佐治亚州一侧免费，但对于非历史爱好者而言，驾车穿越开阔田野和纪念碑可能略显乏味。"},
    {"name":"NotMyThing2023","rating":2,"text":"除非你真的对内战历史情有独钟，否则这里不过是驾车穿越一片片田野、观看一座座纪念碑。不使用应用程序几乎没有任何讲解，孩子们30分钟后便兴味索然。"}],
  "christiansted-national-historic-site": [
    {"name":"IslandHistorian","rating":5,"text":"非常有趣且保存完好的丹麦要塞，建于一战前的殖民时期。入口附近设有精彩的解说区，通过视频和展板详细介绍圣克罗伊岛的历史。"},
    {"name":"CaribbeanTraveler","rating":4,"text":"要塞提供约14个房间的自导式参观，展示了19世纪的生活面貌。从城墙可欣赏到城镇和港口的美景，从木板路即可方便抵达。"},
    {"name":"BeachGoer_FL","rating":3,"text":"历史爱好者的好去处，其他人可能会感到略显无聊。若持有美国国家公园通行证，值得一游。自导式参观配有良好的标识，但规模较小，不到一小时即可游览完毕。"},
    {"name":"SunSeekerTom","rating":2,"text":"满怀期待而来，却发现不过是一座小型古堡。内部闷热，没有空调。宁愿把时间花在海滩上，不值得专程前往。"}],
  "clara-barton-national-historic-site": [
    {"name":"RedCrossVolunteer","rating":5,"text":"在这里，你可以用一个小时了解克拉拉·巴顿如何推动免费公共教育、系统化战地护理、创建美国红十字会以及推广急救培训。必去之地。"},
    {"name":"DCHistoryLover","rating":4,"text":"这处遗址的特别之处在于，它让人感觉克拉拉·巴顿刚刚离开不久。虽不精致，有股阁楼气息，但所有文物都展示在外，没有玻璃隔离，仿佛穿越回了那个年代。"},
    {"name":"WeekendTripper_MD","rating":3,"text":"该遗址仅在有限时间内开放：周五和周六，导游参观时间为下午1、2、3和4点。外部正在进行大量翻修工程，建议提前致电确认。"},
    {"name":"DisappointedVisitor","rating":2,"text":"具有重要历史意义却疏于维护的遗址。房屋在翻修期间缺乏家具，没有指示牌，通道令人困惑，且有一位对遗址和导游一无所知的公园管理人员。"}],
  "colonial-national-historical-park": [
    {"name":"HistoryTeacher_VA","rating":5,"text":"我们用3天时间游览了三个部分：詹姆斯敦聚居地、约克镇战场和殖民地公园大道。两处景点都由国家公园管理局精心维护，提供出色的护林员导览。"},
    {"name":"FamilyVacation2024","rating":5,"text":"公园护林员导游生动有趣，毫不枯燥，让孩子和历史爱好者都能全程投入。詹姆斯敦拥有更丰富的信息资源、大量考古发掘现场和精心制作的博物馆。"},
    {"name":"RoadTripDave","rating":4,"text":"殖民地公园大道是一条美丽怡人的风景驾车路线，沿途设有多个停靠点，可了解该地区的历史。从威廉斯堡前往詹姆斯敦和约克镇的最佳途径。"},
    {"name":"SummerTraveler","rating":3,"text":"建议等凉爽季节再来，夏季湿度令人窒息。此外请注意，詹姆斯敦要塞区域和考古博物馆的很大一部分需要在NPS公园票之外另行购票。"},
    {"name":"BudgetTourist","rating":2,"text":"付费景点与NPS景点混杂，令人困惑。抵达后才意识到詹姆斯敦部分区域需要额外付费。不同区域之间的指示牌也很差。"}],
  "coltsville-national-historical-park": [
    {"name":"HartfordLocal","rating":4,"text":"蓝色洋葱顶科尔特大厦是哈特福德的一座建筑地标。沿康涅狄格河延伸的园区环境优美，适合散步。这是美国工业史上独一无二的一页。"},
    {"name":"NPS_Collector","rating":3,"text":"该公园仍处于开发阶段，游客服务十分有限。驾车路过欣赏标志性的科尔特圆顶尚可，但不要期待传统的国家公园体验。"},
    {"name":"CTWeekender","rating":2,"text":"前来寻找游客中心或展览，却几乎一无所获。该公园目前基本上只存在于纸面，只有一些可从外部观看的历史建筑，令人大失所望。"}],
  "coronado-national-memorial": [
    {"name":"AZHiker_Sara","rating":5,"text":"人迹罕至的绝美之地！山顶的360度全景令人震撼，一侧是美国，另一侧是墨西哥。科罗纳多洞穴是公园的瑰宝。"},
    {"name":"SouthwestExplorer","rating":5,"text":"绝对值得一游！几条维护良好的步道难度各异，景色壮美。工作人员友善且学识渊博，无需门票，建议游览约3小时。"},
    {"name":"DesertWanderer","rating":4,"text":"乔的峡谷步道坡度陡峭但精彩绝伦。进入洞穴颇具挑战，因为入口处有巨石阻挡，可能湿滑。请穿好的登山鞋并携带足量饮水。"},
    {"name":"CasualVisitor_AZ","rating":3,"text":"这是一处开发程度较低、机会也少于许多其他公园的瑰宝。驱车前往需要在农村道路上长途跋涉，景色宜人，但除非你是集邮控，否则不值得专程绕道。"},
    {"name":"Unprepared_Tourist","rating":2,"text":"海拔6575英尺，我们完全没有做好准备。徒步时气喘吁吁，洞穴入口过于湿滑无法安全进入。设施有限，地处偏僻。"}],
  "cowpens-national-battlefield": [
    {"name":"RevWarFan","rating":5,"text":"游客中心放映了一部关于《爱国者》电影中所述战役的精彩短片。铺装步道无疑是NPS战场遗址中最为宜人的步道之一。"},
    {"name":"SCRoadTripper","rating":5,"text":"美国独立战争的活历史！停车免费且就在跟前。设施现代、整洁，展览精彩，工作人员乐于助人。美丽而令人心生敬畏。"},
    {"name":"FamilyOutdoors","rating":4,"text":"适合骑行和野餐的好去处。战场面积不大，地势平坦，步行游览轻松惬意。慢慢阅读战役介绍，非常宁静。老少皆宜。"},
    {"name":"DetailOriented","rating":3,"text":"步行道沿途的部分故事板标识需要修缮或更换。阳光已使部分标识褪色开裂，导致内容难以辨认甚至无法阅读。"},
    {"name":"PassingThrough","rating":2,"text":"不过是一片铺有步道和标识牌的田野。如果你对美国独立战争历史没有兴趣，这里没有太多能吸引你的东西，我们20分钟就逛完了。"}],
  "cumberland-gap-national-historical-park": [
    {"name":"TrailBlazer_KY","rating":5,"text":"游客中心、步道和营地都非常出色。驾车沿尖顶路登高俯瞰坎伯兰峡谷全貌是绝对不能错过的体验。你站在弗吉尼亚州，眺望田纳西州，而车就停在肯塔基州！"},
    {"name":"HikingFamily2024","rating":5,"text":"比烟雾山还要喜欢！峡谷洞穴导览绝对值回票价，奇特的岩石构造、水潭、宽阔的洞室和历史底蕴令人叹为观止。步道美丽且标识清晰。"},
    {"name":"NatureLover_TN","rating":4,"text":"与其他国家公园相比，这里人流量极少，热门徒步路线大多空空如也。免费入场，近十年的大规模翻新使整个园区整洁有序。"},
    {"name":"HistoryNerd123","rating":3,"text":"游客中心非常出色，但景区内各景点之间需要大量驾车往返。尖顶观景台值得一看，其他地方却让人感觉分散而平淡。"},
    {"name":"WearyTraveler","rating":2,"text":"通往尖顶的道路令人提心吊胆，急弯连连，部分路段甚至没有护栏。峡谷本身不过是山间一道豁口，实在难以理解为何声名大噪。"}],
  "dayton-aviation-heritage-national-historical-park": [
    {"name":"AviationGeek","rating":5,"text":"整个航空之旅都精彩绝伦！游客中心设有大量互动体验活动和一部精彩的30分钟影片。在赫夫曼草原，护林员让我们驾驶模拟莱特兄弟飞行器。"},
    {"name":"OhioFamilyTrip","rating":4,"text":"如果你对莱特兄弟感兴趣，这里值得一游。景区包含多处参观地点，包括保罗·邓巴故居、赫夫曼草原飞行场和莱特兄弟自行车店。护林员友善热情。"},
    {"name":"HiddenTreasure","rating":4,"text":"博物馆规模不大但质量极高，且完全免费。莱特兄弟自行车店不可错过，那是一处真正的隐藏宝藏。孩子们因成功操控模拟飞行器而获颁证书！"},
    {"name":"SkyHighExpectations","rating":3,"text":"赫夫曼草原飞行场可能显得相当单调，开阔地里只有几处小型建筑。除了打个卡，与游客中心相比，感觉略显失望。"},
    {"name":"RoadTripSkipper","rating":2,"text":"各景点分布在代顿各处，需要大量驾车穿行。部分地点几乎没有什么可看的。我们到访时自行车店尽管公示了开放时间，却仍大门紧闭。"}],
  "de-soto-national-memorial": [
    {"name":"FloridaHistoryFan","rating":5,"text":"景色宜人的遗址，设施出色，步道优美，历史信息丰富，工作人员亲切友善。游客中心的影片对德索托的探险历程介绍得非常详尽。"},
    {"name":"BradentonLocal","rating":4,"text":"在美丽的环境中感受一段历史。环形步道全程约半英里，可欣赏到河流美景。免费入场，交通便利，停车充裕，非常适合家庭游览。"},
    {"name":"NatureLover_FL","rating":4,"text":"宠物友好型国家纪念地！整个园区人少，维护良好，凉风习习，干净整洁，风景如画。穿越红树林步道的徒步体验绝佳。"},
    {"name":"StormChaser2024","rating":3,"text":"景区在风暴后仍在修复重建，但步道已开放，部分周末会举办有限的活动。前往前请先查询。"},
    {"name":"ExpectingMore","rating":2,"text":"这里除了一个小型游客中心和一条短程步道，真的没有太多内容。展览感觉已经过时，影片需要更新。除非你在集邮盖章，否则不值得专程前往。"}],
  "dwight-d-eisenhower-memorial": [
    {"name":"DCMemorialWalker","rating":4,"text":"艾克在诺曼底登陆前向部队训话以及作为总统的雕塑栩栩如生。这里设有一个小型NPS中心，配有展览、洗手间和礼品店。请使用二维码语音导览！"},
    {"name":"PresidentFan_USA","rating":4,"text":"如果你在附近游览其他景点，值得顺道一游。纪念馆以他少年时期、将军时期和总统时期为主题，两根柱子上分别标明他是第34任总统和最高盟军统帅。"},
    {"name":"CapitalTourist","rating":3,"text":"三角形的纪念馆看起来像个事后补救之作——封闭马里兰大道的一段，种上草坪，竖起一块巨大的屏幕。散步尚可，但本身不足以成为目的地。"},
    {"name":"NotWorthTheTrip","rating":2,"text":"不值得从其他纪念馆专程前往。纪念馆位于航空航天博物馆后面，与国家广场主体区域感觉脱节，与DC其他纪念馆相比显得黯然失色。"}],
  "edgar-allan-poe-national-historic-site": [
    {"name":"LiteraryPilgrim","rating":5,"text":"爱伦·坡粉丝必去之地！我们非常幸运，在客厅里听到一位护林员朗诵《乌鸦》，那是一次令人难忘的体验。"},
    {"name":"PhillyExplorer","rating":4,"text":"护林员友善而博学。博物馆规模不大但免费，可自行参观。故居内提供一段关于坡的生平与时代的视频，颇为不错。"},
    {"name":"BookwormSally","rating":3,"text":"坡的粉丝会喜欢，NPS爱好者则未必。遗址内容不多，因为坡只在此居住了两年且身无长物。房间基本空置，但相关信息资料充足。"},
    {"name":"WalkingPhilly","rating":2,"text":"这处历史遗址位置偏僻，周边环境看起来较为杂乱，远离费城其他主要景点。房间空空如也，15分钟即可游览完毕。"}],
  "eisenhower-national-historic-site": [
    {"name":"GettysburgVisitor","rating":5,"text":"参观这座故居100%值得，可能是我们在葛底斯堡之旅的高光时刻。我最喜欢的房间是背面的玻璃门廊，可以俯瞰战场。"},
    {"name":"PresidentialHomes","rating":5,"text":"仿佛回到了20世纪50年代！园区维护良好，景色优美。学识渊博、乐于助人的公园护林员提供免费导览，另有小册子或二维码供参阅。"},
    {"name":"HistoryExplorer_PA","rating":4,"text":"这是艾森豪威尔夫妇拥有的唯一一处房产。这处690英亩的遗址保存了1950年购置的故居和农场。导览部分由护林员引导、部分自行参观，非常值得。"},
    {"name":"TransitComplainer","rating":3,"text":"景区不允许私家车进入，必须前往葛底斯堡游客中心购票，再乘坐接驳巴士。接驳车班次频繁，但增加了时间成本，给行程带来不便。"},
    {"name":"ShortOnTime","rating":2,"text":"接驳系统麻烦重重，耗费葛底斯堡的宝贵时间。故居导览简短，之后就只是参观几处农场建筑，不值得为此费那么大的周折。"}],
  "eleanor-roosevelt-national-historic-site": [
    {"name":"HydeParkVisitor","rating":5,"text":"瓦尔基尔小屋值得专程前往！公园护林员出色地讲述了埃莉诺在富兰克林·罗斯福逝世后的生活。你将深刻理解她对权力与影响力的独特见解。"},
    {"name":"NYDayTripper","rating":5,"text":"埃莉诺唯一属于自己的家，既富有启迪性，又充满沉思氛围。故居简朴温馨，镶木墙板，书籍和照片琳琅满目，完美还原了埃莉诺的精神世界。"},
    {"name":"FDR_Enthusiast","rating":4,"text":"前往FDR景点时务必顺道参观瓦尔基尔。导游学识渊博，在讲解各处展览时不慌不忙，介绍了大量鲜为人知的细节。距离主要院落仅需短驱几分钟。"},
    {"name":"CasualDayTrip","rating":3,"text":"故居有趣但规模不大，导览节奏较快。距FDR主院落仅需短驱几分钟。对于追求完整体验的游客不可错过，但若在海德公园时间有限，则并非必须。"},
    {"name":"SkippedIt","rating":2,"text":"在FDR图书馆和故居游览了一整天后，我们已经太累了，不想再参加另一个故居导览。小屋较为朴素，绕道前往感觉没有必要，不如把更多时间留给斯普林伍德。"}],
  "eugene-oneill-national-historic-site": [
    {"name":"TheaterLover_SF","rating":5,"text":"美国最伟大剧作家的故居，必须一游！迪亚布洛山的景色令人叹为观止，尤金·奥尼尔的历史同样引人入胜。这座充满历史积淀的房子颇具神秘色彩。"},
    {"name":"BayAreaHiker","rating":4,"text":"NPS精华！通过铁马步道徒步前往道家别墅，身临其境感受奥尼尔钟情于此地的原因。林荫小道提供了极佳的自然体验，巴士和参观均免费。"},
    {"name":"LitHistoryBuff","rating":4,"text":"部分导游对奥尼尔有着深入的研究，既能启迪观众，又能妙趣横生地讲解历史。坐落于壮美山坡上的地理位置，曾是奥尼尔逃离名利喧嚣的避风港。"},
    {"name":"CasualVisitor_CA","rating":3,"text":"预约和准时到达是最困难的部分。遗址本身若没有出色导游的生动讲解，只能说差强人意，主要适合奥尼尔的忠实爱好者。"},
    {"name":"DisappointedDan","rating":2,"text":"我们的遗址导游对相关史实并不熟悉，故居导览也显得仓促。地处偏远，且需提前预约接驳车。除非你是资深戏剧迷，否则不值得专程前往。"}],
  "federal-hall-national-memorial": [
    {"name":"NYCHistoryWalker","rating":5,"text":"小而奇特，却具有重要历史意义！1789年华盛顿在此宣誓就任首任总统，宪法在此批准，《权利法案》亦在此起草。内部圆形大厅美轮美奂。"},
    {"name":"WallStreetVisitor","rating":4,"text":"华尔街核心地带一处颇具历史感的好去处。内部建筑精美，白色大理石柱林立，门外矗立着华盛顿的巨型雕像。免费入场。"},
    {"name":"FinancialDistTour","rating":3,"text":"如果有时间，值得一游。不建议专程来曼哈顿下城，但如果你恰好在附近，可以顺道参观一下，馆内有三个小型展览。"},
    {"name":"StampCollector_NPS","rating":3,"text":"至少这里有国家公园护照的盖章。大楼内设有一个非常小的博物馆，馆内有公园护林员。20分钟即可游览完毕。"},
    {"name":"TouristOverload","rating":2,"text":"这里被附近的纽交所和华尔街铜牛完全遮盖了光彩。内部空间极小，几乎没有什么可看的。门外著名的雕像才是真正的亮点，而且你甚至不需要进去就能欣赏到它。"}],
  "first-ladies-national-historic-site": [
    {"name":"PresidentialFan_OH","rating":5,"text":"萨克斯顿故居维多利亚风格典雅端庄！专人导览服务非常值得。麦金利的故居修缮精美，导游提供了丰富多样的历史信息。"},
    {"name":"CantonVisitor","rating":4,"text":"萨克斯顿故居才是真正的瑰宝。这座对第一夫人们的致敬之所令人大为赞叹，两栋建筑的建筑风格都令人印象深刻。导游亲切随和，讲解引人入胜。"},
    {"name":"ExpectingMore_OH","rating":3,"text":"第一夫人展览仅限于一楼的部分区域，内容不如预期丰富。复制的礼服与史密森尼博物馆的真品相比，显得毫无意义。"},
    {"name":"BoredInCanton","rating":2,"text":"乏善可陈。博物馆展览区域极小，故居导览虽然不错，却不足以支撑专程前往坎顿的理由。受众极为小众，对大多数游客缺乏吸引力。"}],
  "first-state-national-historical-park": [
    {"name":"DelawareProud","rating":5,"text":"一堂德拉华历史课！这条步行导览穿越一座典型殖民地城市的核心区域，将多佛所有的历史脉络串联贯通。解说员知识渊博，带我们走遍了每个房间。"},
    {"name":"ColonialHistory","rating":4,"text":"导览从绿地上的约翰·贝尔故居出发，全程约半小时，途中停留拍照并聆听古老房屋的故事。这是了解德拉华重要历史地位的绝佳入门体验。"},
    {"name":"NPS_Collector_DE","rating":3,"text":"德拉华州唯一的NPS景点，独特之处在于它是分布于全州多个地点的集合体。主要吸引历史爱好者，各景点较为分散。"},
    {"name":"ConfusedTourist","rating":2,"text":"网站让我们以为有更多内容可看。该公园实际上由分散各处的地点构成，缺乏统一连贯的游客体验。很难分清哪些是NPS管辖，哪些是州立公园。"}],
  "flight-93-national-memorial": [
    {"name":"PatriotVisitor","rating":5,"text":"这是我此生最动人心弦的体验之一。建筑设计沿飞行轨迹延伸，刻有名字的纪念墙，标记坠机地点的巨石，以及博物馆中的录音信息——一切都深深震撼人心。"},
    {"name":"NeverForget_USA","rating":5,"text":"神圣的土地。40名乘客的名字永远铭刻在大理石墙上。工作人员的友善与学识使这段体验更加意义深远。请穿好走路的鞋子，并参观游客中心。"},
    {"name":"FamilyTrip_PA","rating":5,"text":"情感深沉、庄严肃穆的纪念地。虽然地处偏远，驾车需要较长时间，但维护良好的步道和清晰的导向标识使参观便利易行。对家庭而言具有深刻的教育意义。"},
    {"name":"HistoryTeacher","rating":4,"text":"令人不寒而栗的地方。极简主义的建筑风格与宁静的周边环境共同营造出深沉庄重的氛围。参观游客中心在内的完整体验，请预留至少2小时。"},
    {"name":"RoadTripDetour","rating":3,"text":"纪念馆设计精良，但地处极为偏僻。本质上不过是一面刻有名字的墙和一片田野中的巨石。游客中心提供了背景信息，但部分人可能觉得漫长的驾车与实际体验不成比例。"},
    {"name":"Ken_C","rating":2,"text":"首先映入眼帘的是蜿蜒漫长的通往游客中心的道路，以及游客中心高耸的混凝土墙。中心规模不大，却收藏了大量有趣的文物，那些电话录音令人心碎。你可以步行前往纪念地点，那里有铭刻着逝者姓名的大理石板和一块标志地点的巨石。但这里大量使用了混凝土——墙壁、走道、长凳，许多似乎都是多此一举，不过既然资金已经拨付，便全部用在了道路和混凝土上。我对93号航班的乘客们深怀敬意，也喜欢这里讲述他们故事的方式——只是那些混凝土和漫长的步行，实在令人不快。"}],
  "fort-bowie-national-historic-site": [
    {"name":"DesertHiker_AZ","rating":5,"text":"一次走进历史的绝妙徒步！全程3英里往返，沿途设有展示牌和解说牌，途经墓地、蝴蝶驿站遗址和阿帕奇泉，最终抵达要塞遗址。"},
    {"name":"FrontierExplorer","rating":5,"text":"鲍伊堡——杰罗尼莫的幽灵！如果你热爱历史、喜欢中等强度的徒步、欣赏沙漠美景，鲍伊堡绝对难逢对手。这是唯一一处需要徒步1.5英里才能抵达游客中心的NPS景点。"},
    {"name":"SouthwestRoadTrip","rating":4,"text":"阿帕奇隘口的守护者，在铁路兴起之前曾是重要交通要道，历史底蕴深厚。请早出发——步道海拔较高且遮阴极少。"},
    {"name":"Unprepared_Dan","rating":2,"text":"从186号公路沿土路驾车约7英里才能抵达步道入口，轿车通行颇为困难。然后还需在炎热的沙漠中徒步1.5英里。我们到达时游客中心无人值守。"},
    {"name":"NotWorthTheDrive","rating":1,"text":"历史确已湮没无闻。在烂泥土路上驾车7英里、在100华氏度的高温下往返徒步3英里之后，我们看到的只是几堵残垣断壁。步道入口处没有饮水，没有任何设施。"}],
  "fort-davis-national-historic-site": [
    {"name":"TexasFortFan","rating":5,"text":"戴维斯堡绝对是德克萨斯所有边境要塞中规模最大、景色最美的。工作人员以饱满的热情呈现了水牛士兵的历史，制作非常精良的历史要塞。"},
    {"name":"WestTexasRoadTrip","rating":5,"text":"历史遗迹与文物大观园！多处修缮一新的建筑可供参观，包括普通士兵营房、骑兵营房、军官宿舍和医院。1.5英里的环形步道视野壮阔，建议至少预留几个小时。"},
    {"name":"HistoryBuff_TX","rating":4,"text":"一窥西部前哨生活的绝佳机会。可进入多处历史建筑参观，博物馆虽小但品质极高，关于早期拓荒者和水牛士兵的展览制作精良。"},
    {"name":"SummerMistake","rating":3,"text":"建筑群分布较为分散，切勿像我们一样在大热天前往。历史内容精彩，但西德克萨斯的酷热使户外参观部分难以充分享受。请备足饮水。"},
    {"name":"QuickStop_TX","rating":2,"text":"不过是西德克萨斯偏远小镇里的一批旧建筑。如果你对边境军事史没有特别的兴趣，实在没有理由驱车长途前来。"}],
  "fort-donelson-national-battlefield": [
    {"name":"CivilWarTracker","rating":5,"text":"任何认真的内战爱好者都应来参观唐尼尔森堡——格兰特将军在此开始迅速崛起，也在此赢得了\"无条件投降\"的绰号。从原始射击阵地到河流，视野一览无余。"},
    {"name":"TNNatureLover","rating":5,"text":"精彩的内战遗址，还有鹰巢！河边炮台附近有一个活跃的白头鹰巢，鹰爸、鹰妈和鹰宝宝就在那里。沿坎伯兰河徒步、骑行或野餐的绝佳去处。"},
    {"name":"BattlefieldDriver","rating":4,"text":"值得绕道一游。战场和要塞保存完好，有六英里的徒步道覆盖所有重要景点。公园规模不大且人迹罕至，工作人员极为友善。"},
    {"name":"VisitorCenterFan","rating":3,"text":"先在斯图尔特县游客中心了解背景信息。公园本身不错但规模较小。如果你在附近，可以安排几个小时，但不建议为此专程驱车数小时。"},
    {"name":"ClosedAgain","rating":2,"text":"我们在公示开放时间内到达，游客中心却大门紧闭。没有游客中心提供背景信息，只能开车转悠，看看土工工事，阅读标识牌，令人失望。"}],
  "fort-laramie-national-historic-site": [
    {"name":"OregonTrailFan","rating":5,"text":"必去之地！摩门教徒小道、加利福尼亚小道、俄勒冈小道和快马驿递四条重要历史路线都途经拉勒米堡。拉勒米堡完全超出了我们的预期，我们在此停留了将近3.5小时。"},
    {"name":"WyomingExplorer","rating":5,"text":"令人叹为观止的边境历史遗址！保存与修缮工作精良，展览充分还原了其鼎盛时期的风貌。涵盖美国人与原住民双重视角的精彩讲座令人印象深刻。"},
    {"name":"PioneerHistory","rating":4,"text":"探索先驱时代的精彩窗口！非常值得一游，游客中心不错，影片和展览引人入胜，还有大量复原建筑可供参观，护林员学识渊博。"},
    {"name":"CrossCountryDrive","rating":3,"text":"免费开放且维护良好，但拉勒米堡确实地处偏远。请仔细安排行程，因为周边没有其他景点。2至3小时可游览完毕，但需要绕道不小。"},
    {"name":"HotAndEmpty","rating":2,"text":"建筑物颇有看头，但我们到访时许多房间都上了锁。园区暴露在外，烈日下毫无遮阴。拉勒米堡小镇几乎没有为游客准备的设施。"}],
  "fort-larned-national-historic-site": [
    {"name":"SantaFeTrailBuff","rating":5,"text":"拉尼德堡是必去之地！是圣菲小道上一颗未经雕琢的钻石。要塞由砂岩砌成，保存状态极为完好。身着历史服饰的志愿者们友善有趣，非常乐于交流。"},
    {"name":"KansasExplorer","rating":5,"text":"体验大草原上的生活！众多原始建筑和家具让你真切感受到19世纪60年代偏远军事前哨的生活面貌。公园护林员生动地向孩子们讲述历史故事。"},
    {"name":"FrontierFortFan","rating":4,"text":"感受边境历史的绝佳去处，游客中心出色，大多数建筑都可进入，还有木匠和铁匠作坊可供观摩学习。保存完好的要塞坐落于波尼河畔。"},
    {"name":"LostInKansas","rating":3,"text":"要塞内标识牌极少，既没有导览也没有语音导览，我们几乎不知道自己在看什么。建筑物美观，但缺乏解说。"},
    {"name":"MiddleOfNowhere","rating":2,"text":"除非你正途经堪萨斯州中部，否则专程绕道至此实不值当。要塞不错，但极为偏僻，周围数英里内一无所有。"}],
  "fort-necessity-national-battlefield": [
    {"name":"RevolutionaryFan","rating":5,"text":"乔治·华盛顿曾来过这里！游客中心的展览和文物精彩纷呈，并有一部关于内塞西蒂堡和国道的精彩影片。护林员是我见过最友善的！免费入场。"},
    {"name":"PAHistoryBuff","rating":5,"text":"绝对值得一游，请预留至少2小时进行完整探索。游客中心设有关于战役和国道的高质量展览，设计精良，内容引人入胜。"},
    {"name":"FamilyDayTrip_PA","rating":4,"text":"值得短暂一游，从游客中心步行即可抵达复原的要塞。这里还有一个精彩的游乐场供小朋友玩耍，这在历史公园中实属难得。"},
    {"name":"HonestReviewer","rating":3,"text":"对历史爱好者来说这里极具魅力，但要塞本身规模不大，观感一般。步道在美丽的环境中漫步令人愉快，游客中心是收获最多的地方。"},
    {"name":"DroveTooFar","rating":2,"text":"不过是一片田野里的一个小木圆圈，代表着要塞的位置。出色的游客中心过后，实际遗址显得虎头蛇尾。不值得专程从匹兹堡驱车前来。"}],
  "fort-point-national-historic-site": [
    {"name":"SFPhotoWalker","rating":5,"text":"一次游览远远不够！从内部和屋顶欣赏金门大桥的景色令人叹为观止。这是旧金山一处免费、不拥挤且极为有趣的隐藏宝地。"},
    {"name":"GoldenGateFan","rating":5,"text":"参观金门大桥时必须顺道一游！这座内战时期修建于大桥下方的要塞提供了绝佳的拍照机会。除博物馆外，这里还定期举办艺术展览。"},
    {"name":"BridgeExplorer","rating":4,"text":"要塞旁有停车场，但很快就会停满。这是一处历史感十足的好去处，拍照机会绝佳。请做好爬楼梯的准备，并携带保暖衣物，因为这里风大且气温较低。"},
    {"name":"ParkingNightmare","rating":3,"text":"停车较为困难，尤其在周末。要塞有趣，但仅周五至周日开放。参观前请查好时间安排。不过景色确实不错。"},
    {"name":"WindyDisappointment","rating":2,"text":"拍照圣地，但我们专程驾车前来时要塞却大门紧闭。开放时间有限，风力强劲令人难以忍受。从停车场步行下来坡度颇陡。"}],
  "fort-raleigh-national-historic-site": [
    {"name":"LostColonyFan","rating":5,"text":"绝对值得一游！游客中心关于失落的殖民地和自由人殖民地的展览制作精良。公园护林员出色——友善、博学，且非常善于与孩子互动。"},
    {"name":"OBXHistoryBuff","rating":4,"text":"罗阿诺克失落殖民地所在地，游客中心宽敞，礼品店备货充足，并有一部15分钟的影片。历史遗址不错，护林员对历史知之甚深。"},
    {"name":"ManteoVisitor","rating":3,"text":"免费开放，规模适中，体验尚可。园区优美，有一段短途步行可抵达海湾。作为了解失落的殖民地、地下铁路和自由人殖民地的入门介绍不错，但土筑要塞本身略显平淡。"},
    {"name":"EarthworkSkeptic","rating":2,"text":"历史性的土筑工事令人大失所望，不过是树林里的一个小土丘。事先了解这一点就不会失望，但我们原本期待看到真正的要塞遗址。"}],
  "fort-scott-national-historic-site": [
    {"name":"FrontierHistoryFan","rating":5,"text":"想象你是19世纪40年代的美国陆军骑兵！大量复原建筑展示了步兵营房、骑兵营房、军官宿舍和医院。工作人员友善且学识丰富。"},
    {"name":"KansasTraveler","rating":5,"text":"借助园区内手机语音讲解和解说标识讲述了一段精彩的历史故事。活态历史活动包括内战角色扮演和圣诞节烛光游览。"},
    {"name":"WeekendExplorer_KS","rating":4,"text":"领略旧西部风情的好去处！无论你是历史初学者还是对边境要塞历史了如指掌，这里都能满足你的需求。12月的烛光游览是不可错过的活动。"},
    {"name":"PassingThrough_KS","rating":3,"text":"要塞不错，但斯科特堡小镇并没有太多其他值得一看的地方。若途经69号公路，可以安排1至2小时游览。建筑维护良好，但互动式展览有待增加。"},
    {"name":"RemoteAndQuiet","rating":2,"text":"位于堪萨斯州东南部，周边极为偏僻。要塞修缮完好，但我们到访时没有护林员或导游，只能独自穿行于空旷的建筑之间。"}],
  "fort-smith-national-historic-site": [
    {"name":"TrueGritFan","rating":5,"text":"如果你看过《绞刑架》或《大地惊雷》，这就是一切故事发生的地方！这里是美国第一批法警的驻地，设有'绞刑法官'的法庭。如此小的地方承载着如此厚重的历史。"},
    {"name":"ARExplorer","rating":5,"text":"非常值得一游！沿水边的美丽步道，出色的导览视频，以及精彩的展览。独特的NPS展览包括博物馆和军需处大楼内的互动活动。"},
    {"name":"HistoryWalker_AR","rating":4,"text":"西南方向重要历史路线上的必经要塞。设有充足标识牌的步行道游览约需45分钟。园区、绞刑架和军需处免费参观，监狱和法庭需收取小额门票。"},
    {"name":"QuickStopper","rating":3,"text":"短暂停留的好去处，但规模较小。监狱和帕克法官法庭另行收费，这让人感觉有些不必要。若要参观室内展览，请预留约两小时。"},
    {"name":"Underwhelmed_AR","rating":2,"text":"园区大多是废墟，附有部分复建建筑。在本应免费的国家公园景点基础上，还要为室内展览额外付费，感觉像是在向游客雁过拔毛。"}],
  "fort-sumter-and-fort-moultrie-national-historical-park": [
    {"name":"CharlestonHistory","rating":5,"text":"公园护林员对内战初期士兵生活的讲解极为翔实。来回乘船各需30分钟，途中可见海豚，并欣赏到城市的壮美景色。"},
    {"name":"CivilWarPilgrim","rating":5,"text":"穆尔特里堡的参观体验远胜萨姆特堡。这里的历史可追溯至美国独立战争，令人印象深刻的大炮阵列展示了防御工事随时代演变的历程。门票仅需3美元。"},
    {"name":"SCVacation2024","rating":4,"text":"萨姆特堡和穆尔特里堡合游可以打造一整天充实的内战历史之旅。护林员学识渊博，令人叹服。建议先游萨姆特堡，再游穆尔特里堡以获得更深入的体验。"},
    {"name":"BudgetShocked","rating":3,"text":"前往萨姆特堡的成人船票每人高达40美元，且国家公园通行证无法抵用。穆尔特里堡票价低廉，仅需3美元，诚实而言质量不逊于萨姆特堡。"},
    {"name":"BoatRideRegret","rating":2,"text":"大炮、大炮，还是大炮。每人花费40美元乘船前往一座海岛砖石废墟。沙利文岛上的穆尔特里堡几乎免费，且参观内容更为丰富。不要坐船了。"}],
  "fort-union-trading-post-national-historic-site": [
    {"name":"FurTradeFan","rating":5,"text":"太棒了！这是一处对一个极为重要的贸易站的精彩复原。要塞内的展览制作精良，屋内的小型博物馆也非常有趣。免费入场。"},
    {"name":"NDExplorer","rating":4,"text":"位于蒙大拿州与北达科他州交界处一处小型却意义重大的历史地标。6月的联合堡会集活动汇聚了逾百名身着历史服饰的角色扮演者，是活态历史的生动呈现。"},
    {"name":"MissouriRiverTrip","rating":4,"text":"密苏里河畔皮毛贸易商的要塞，设有精美的博物馆和解说区域。工作人员超级友善且信息丰富。沥青路就在要塞门口戛然而止。"},
    {"name":"MosquitoVictim","rating":3,"text":"如果你在附近，值得停留30分钟。务必携带驱蚊剂——蚊子在这片水域旁繁盛异常！位于威利斯顿西南方向约20分钟车程的边境地带。"},
    {"name":"TooRemote","rating":2,"text":"要塞字面意义上地处北达科他州与蒙大拿州交界的不毛之地。复原工程不错，但不值得大费周章绕道前往。驾车时间将远远超过参观时间。"}],
  "fort-vancouver-national-historic-site": [
    {"name":"PNWHistoryBuff","rating":5,"text":"令人叹为观止的历史地标！国家公园管理局在保护历史方面做得非常出色。大多数时候都有导游和身着历史服饰的工作人员，包括一位铁匠。荣登华盛顿州温哥华第一名。"},
    {"name":"OregonTrailFan","rating":5,"text":"跨越时空的同一地点！复原的要塞寓教于乐，工作人员充满热情。沿军官排屋散步令人心旷神怡，是了解美国西北历史不可错过的必游之地。"},
    {"name":"WashingtonVisitor","rating":4,"text":"历史底蕴深厚，导游经验丰富。多栋建筑按历史时期复原，还有一位志愿者精心打理的大型花园。铁匠演示是孩子们最喜欢的环节。"},
    {"name":"CasualStopper","rating":3,"text":"如果你在波特兰-温哥华地区，值得快速游览。由于要塞是复原建筑，真实感略显不足。游客中心部分志愿者并不太乐于助人或信息不够准确。"},
    {"name":"DroveForNothing","rating":2,"text":"对一处国家历史遗址的期望远不止于此。这里不过是一座有几位身着历史服装志愿者的复原要塞，更像是一个社区公园，而非具有重要历史意义的目的地。"}],
  "frederick-douglass-national-historic-site": [
    {"name":"DCHistoryPilgrim","rating":5,"text":"故居导览绝对是必选项目！70%的物品都是原件。从屋内可以望见华盛顿特区市中心、华盛顿纪念碑和国会大厦。我们的导游丽莎出色极了，对历史充满热情。"},
    {"name":"AnacostiaExplorer","rating":5,"text":"千万不要专程来DC却错过这个景点，强烈推荐！弗雷德里克·道格拉斯故居值得前往阿纳科斯蒂亚一游。务必预约导览——NPS护林员无比出色。"},
    {"name":"EducatorTrip","rating":4,"text":"出乎意料地精彩！让这次参观激励你进一步探求。到达故居需要爬不少台阶，但景色和历史都物有所值。导览时间不到一小时。"},
    {"name":"MovieCritic_DC","rating":3,"text":"导览影片已严重过时，游客中心亦然，早该更新了。不过故居本身非常精彩。请提前预约，因为参观团体人数有限。"},
    {"name":"TransitStruggles","rating":2,"text":"千万别搭公交车过来，乘公共交通前往阿纳科斯蒂亚简直是噩梦。附近街区给人感觉不太安全，停车也很困难。故居虽好，但位置偏僻，交通不便。"}],
  "frederick-law-olmsted-national-historic-site": [
    {"name":"LandscapeArchFan","rating":5,"text":"费尔斯特德！展览信息量极大，护林员导览服务出色。档案室收藏着138,000份原始图纸和60,000张照片，是我们波士顿之行中最有趣的地方之一。"},
    {"name":"BrooklineWalker","rating":4,"text":"美丽的园地和工作室，让人深入了解景观建筑的运作方式。这处遗址组织得相当井然有序，让我们对美国公共花园的历史有了很多新认识。"},
    {"name":"ParkDesignNerd","rating":4,"text":"护林员出色地解读了奥姆斯特德设计的深远影响。一个精心设计的档案室在湿度控制下保存着数千张蓝图，令人着迷！"},
    {"name":"LimitedHoursIssue","rating":3,"text":"请提前致电确认开放时间，因为这里开放时间不长，也不是每天都开放。我们从波士顿专程驾车前来，却发现大门紧闭。再次到访时，导览出色但时间较短。"},
    {"name":"TooNiche","rating":2,"text":"除非你对景观建筑史有特别的兴趣，否则这里不过是一栋摆放着几张旧蓝图的房子。导览时间短，遗址规模小，而且布鲁克林有更值得游览的地方。"}],
  "fredericksburg-and-spotsylvania-national-military-park": [
    {"name":"CivilWarScholar","rating":5,"text":"漫步凹陷路步道，深切感受这场血腥搏杀。登上玛丽高地，你将完美理解李将军所占据的有效防御阵地。叹为观止。"},
    {"name":"BattlefieldTourer","rating":5,"text":"该公园涵盖四处不同的内战战场：弗雷德里克斯堡、斯波特西尔瓦尼亚、荒野战场和钱瑟勒斯维尔。每处都值得花数小时深入游览。请预留整整两天时间。"},
    {"name":"VAWeekendTrip","rating":4,"text":"游客中心紧邻公墓，展览精良，静态与互动陈设兼备，并有一部22分钟的影片。护林员学识渊博，导览引人入胜，广受好评。"},
    {"name":"SelfDrivingTour","rating":3,"text":"自驾游览不错，但各战场分布区域较广。NPS提供的GPS导航不太可靠。游览时间完全取决于个人的兴趣程度。"},
    {"name":"TooSpreadOut","rating":2,"text":"千万不要指望NPS带你找到游客中心！四处战场遗址分散在广大地区，需要大量驾车往返。没有向导，不过是一片片田野和一块块标识牌。"}],
  "friendship-hill-national-historic-site": [
    {"name":"GallatinFan","rating":5,"text":"园区景色优美，参天大树林立，通往加洛廷故居的小路令人心旷神怡。在故居内，NPS工作人员热情而详尽地讲解，对孩子们格外友善。免费入场。"},
    {"name":"PATrailRunner","rating":4,"text":"跑步者、步行者和徒步爱好者的安全天堂。树木成荫的土地一年四季皆美，园地和建筑令人叹为观止。自导式参观涵盖了故居的不同历史时期。"},
    {"name":"HistoryExplorer","rating":4,"text":"地处偏远却饶有趣味。阿尔伯特·加洛廷是汉密尔顿的继任者，曾出资资助刘易斯与克拉克探险队和国道建设。每年9月的秋日节是必参加的盛会。"},
    {"name":"RemoteAndEmpty","rating":3,"text":"庄园景色宜人，但确实地处偏僻，附近别无他物。整整两小时的游览中，我们是唯一的访客。美丽，却颇为孤寂。"},
    {"name":"LongDriveForThis","rating":2,"text":"在崎岖蜿蜒的宾夕法尼亚农村公路上驾车一个多小时，只为参观一处大多数人从未听说过的财政部长的朴素故居。园地优美，但对大多数游客而言不值得专程前往。"}],
  "general-grant-national-memorial": [
    {"name":"NYCHistoryBuff","rating":5,"text":"北美最大的陵墓！建成于1897年，150英尺高的穹顶气势磅礴，内含8000吨白色大理石和花岗岩。这是一座宏伟壮观、献给一位被忽视的总统的纪念建筑。"},
    {"name":"UWSWalker","rating":4,"text":"谁安葬在格兰特墓中？这座古典穹顶陵墓俯瞰哈德逊河。游客中心和墓室均免费开放。作为沿河边公园散步的补充打卡地不错，周三至周日开放。"},
    {"name":"MorningsideVisitor","rating":3,"text":"尤利西斯·S·格兰特的长眠之所，如果你碰巧在附近，值得前往，但并非必游之地。大约20分钟即可游览完毕，不足以让一家人消磨数小时，但历史爱好者会觉得值得。"},
    {"name":"ConfusedTourist_NYC","rating":2,"text":"在公示的开放时间内到达，马路对面的游客中心却大门紧闭。陵墓外观壮丽，但内部不过是空旷房间里的两具石棺，令人大感失望。"}],
  "george-rogers-clark-national-historical-park": [
    {"name":"IndianaHistorian","rating":5,"text":"不容错过的历史！这是华盛顿特区以外最大的国家历史地标。内部设有中央雕像和令人印象深刻的壁画。护林员学识渊博，热情友善。"},
    {"name":"VincennesVisitor","rating":5,"text":"隐藏的瑰宝！1779年克拉克率部在隆冬时节长途跋涉，攻克萨克维尔堡，使美国得以宣示对俄亥俄、伊利诺伊、印第安纳、密歇根和威斯康星地区的主权。纪念馆气势宏伟，河岸风光一览无余。"},
    {"name":"MidwestRoadTrip","rating":4,"text":"宏伟庄严的乔治·罗杰斯·克拉克纪念馆，气象颇似华盛顿特区的建筑风格。30分钟的影片将其历史意义阐释得清晰透彻，沿河地带的园区修缮精美。"},
    {"name":"QuickPassThrough","rating":3,"text":"纪念建筑令人印象深刻，但没有其他太多内容。参观纪念碑、观看影片、游览园地，约一小时即可完成。文森斯本地的景点也十分有限。"},
    {"name":"LongDriveShortVisit","rating":2,"text":"不过是印第安纳州农村里一栋带雕像和壁画的单体建筑。纪念馆不错，但对大多数人而言不值得专程驱车前往文森斯，最多算个30分钟的打卡站。"}],
  "gloria-dei-church-national-historic-site": [
    {"name":"PhillyHistoryWalk","rating":5,"text":"费城一处非常迷人的遗址。安静、祥和，位置不难找到。远离城市的喧嚣与嘈杂，是闹市中的一片绿洲。宾夕法尼亚州历史最悠久的教堂，殖民地建筑瑰宝。"},
    {"name":"ChurchHistoryBuff","rating":4,"text":"一座美丽宁静的教堂，设有楼上的画廊。不要错过悬挂在天花板上的船模，以及圣器室中的银制王冠——每位在此完婚的女士都必须佩戴它。独一无二！"},
    {"name":"OffBeatPhilly","rating":3,"text":"地处偏僻，但教堂和园地实在美丽。教堂院落随时可以参观，且允许携带宠物，这与大多数其他国家历史遗址不同。周一不开放。"},
    {"name":"StampHunter","rating":2,"text":"主要是为了盖国家公园护照章而来。这是一座不错的古老教堂，但除非你对殖民地宗教历史情有独钟，否则实在没有什么理由特意赶到费城这一带。"}],
  "lake-tahoe": [{"name":"CaliforniaDreamer","rating":5,"text":"天堂滑雪场是太浩湖周边最美如画的地方之一。缆车提供令人叹为观止的景色。无论是冬季滑雪还是夏季徒步，太浩湖从未令人失望。美不胜收。"},
    {"name":"SierraNevadaFan","rating":5,"text":"翡翠湾州立公园是一处国家天然地标，拥有巨大的花岗岩山峰和精彩的徒步路线。1929年作为避暑别墅建造的城堡是斯堪的纳维亚建筑风格的最佳范例之一。"},
    {"name":"SandHarborLover","rating":5,"text":"沙港是一个令人惊叹的地方，水质清澈，非常适合游泳、皮划艇和桨板运动。沿岸的徒步小径风景优美。夏季请早点到达以确保停车位。"},
    {"name":"WinterSkier2024","rating":3,"text":"太浩湖风景优美，但人满为患且消费昂贵，尤其是在滑雪季节。从湾区沿80号州际公路驾车可能会多花3个小时以上。请提前数月预订一切。"},
    {"name":"OverratedOpinion","rating":2,"text":"与其他山地湖泊目的地相比，老实说有些名不副实。一切都过于昂贵，夏天海滩拥挤不堪，在任何地方找停车位都是噩梦。风景虽美，但不值得这番折腾。"}],

  "african-burial-ground-national-monument": [{"name":"Mounir","rating":5,"text":"曼哈顿中心一处令人动容且充满教育意义的纪念碑。室内展览解释了这里发生的历史以及非裔墓地对美国历史的重要意义。"},
    {"name":"Hatzlacha","rating":4,"text":"这是市中心一处安静、沉思的地方。室外纪念碑设计精美。如果您在附近，值得停下来参观。"},
    {"name":"Josh D","rating":5,"text":"纽约隐藏的珍宝之一。博物馆虽小，却充满了关于殖民时期在此安葬的400多位非裔美国人的信息。"},
    {"name":"Lori M","rating":5,"text":"一段大多数人都不了解的极其重要的美国历史。工作人员对这处遗址充满热情和知识。"},
    {"name":"Eva T","rating":3,"text":"值得参观，但室内展览关闭较早，访问可能受限。室外纪念碑随时可进入，但没有内部背景介绍会显得不够丰富。"},
    {"name":"Matthias","rating":1,"text":"我们偶然得知这个纪念馆是免费参观的。影片和整个博物馆完全是夸大其词。每个城市都有几处墓地，这是完全正常的城市发展。我常常不解，这种无知怎么能达到如此程度。"}],
  "agate-fossil-beds-national-monument": [{"name":"Jerri L","rating":5,"text":"保存完好的遗址。化石层引人入胜，游客中心博物馆拥有詹姆斯·库克捐赠的精美美洲原住民文物。内布拉斯加州隐藏的珍宝。"},
    {"name":"MikeB1952","rating":4,"text":"风景优美的徒步路线可欣赏实际的化石层。往返约4英里，地形是起伏的草原。由于几乎没有遮荫，请携带水和防晒用品。"},
    {"name":"Hatzlacha","rating":5,"text":"内布拉斯加州窄颈地带美丽宁静的公园。里面的博物馆非常出色且免费。徒步时看到了一群叉角羚。"},
    {"name":"RecreationV","rating":3,"text":"化石层本身被围栏隔离，无法靠近。只能从远处观看。游客中心不错，但来这里的路程很长，收获有限。"},
    {"name":"Kathleen F","rating":5,"text":"内布拉斯加州窄颈地带意外的瑰宝。化石可追溯到1900至2000万年前。护林员带领的项目既有信息量又引人入胜。"},
    {"name":"MikeB1952","rating":2,"text":"这个国家纪念碑地处偏远。我原本期待在实地看到更戏剧性的化石展示，但没有正在进行的挖掘，原位化石早已不见。博物馆还不错，但夏季酷热、毫无遮阴的户外小径令人难以忍受。"}],
  "amistad-national-recreation-area": [{"name":"Carlos M","rating":5,"text":"阿米斯塔德国家休闲区是一处绝妙的隐藏珍宝。湖泊广阔，垂钓资源一流。水边的露营地拥有美丽的日落景色。"},
    {"name":"TxBoater","rating":4,"text":"划船和垂钓的好地方。水温暖清澈。佩科斯河游客中心有关于该地区历史的有趣展示。"},
    {"name":"Sandra K","rating":3,"text":"公园面积广阔但设施有限。我们想去的许多地方都需要乘船。游客中心规模较小。不过风景不错。"},
    {"name":"LakeFisher99","rating":2,"text":"非常失望。周末时船坞区域非常拥挤，由于干旱，水位偏低。一些船坞几乎无法使用。"},
    {"name":"RoadTripper22","rating":5,"text":"格兰德河与魔鬼河交汇处的壮丽景观。峡谷和蓝绿色的水流绝对令人叹为观止。德克萨斯州西南部的必游之地。"}],
  "arkansas-post-national-memorial": [{"name":"HistoryBuff","rating":4,"text":"阿肯色帖子是密西西比河下游最古老的欧洲定居点。公园宁静无人。博物馆规模虽小，但制作精良。"},
    {"name":"GardenStateGal","rating":5,"text":"美国历史的精彩篇章。沿小径漫步，参观了重建的要塞区。护林员非常乐于助人且博学。"},
    {"name":"MidwestTraveler","rating":3,"text":"历史有趣，但实体建筑不多。大多是平坦的草地，有标牌和一个游客中心。如果路过，值得短暂停留。"},
    {"name":"NatParksJunkie","rating":5,"text":"不要错过这里！这里的历史跨越法国、西班牙、南方邦联和联邦时期。1863年阿肯色帖子战役意义重大。工作人员很棒。"},
    {"name":"FamilyRoads","rating":2,"text":"地处偏远，几乎没什么可看的。游客中心还行，但周围只是空旷的田野。我们在这里待了大约20分钟就离开了。"}],
  "brices-cross-roads-national-battlefield-site": [{"name":"CivilWarBuff","rating":5,"text":"南北战争中战术上最出色的战役之一。福雷斯特以不足两倍的兵力击败了对手。遗址维护良好，诠释标牌出色。"},
    {"name":"battlefieldwalker","rating":4,"text":"规模不大但意义重大的战场。游客中心展览不错。场地宁静，驾车游览能带你经过几个关键阵地。"},
    {"name":"MississippiTraveler","rating":3,"text":"南北战争爱好者值得停留，但不要期待精致的设施。只有一个小游客中心，主战场如今大部分是农业用地。"},
    {"name":"SouthernHeritage","rating":5,"text":"一处出色的遗址，彰显了内森·贝德福德·福雷斯特的战术天才。新游客中心非常出色，工作人员对历史充满热情。"},
    {"name":"HistoryTeacher","rating":2,"text":"到达后发现游客中心在工作日关闭。没有解说材料，自行参观几乎无法获取信息。希望能有更好的开放时间。"}],
  "camp-nelson-national-monument": [{"name":"Landon","rating":5,"text":"纳尔逊营地是一处令人动容且极为重要的遗址。南北战争期间，这里曾是美国有色人种军队的主要招募中心。新的文化遗产中心非常出色。"},
    {"name":"Jeremy W","rating":5,"text":"肯塔基州中部精心修复的遗址。曾用于安置士兵家属的白宫已被重建。以极大的用心讲述了这段有力量的历史。"},
    {"name":"Teardrop Trailer Traveler","rating":4,"text":"文化遗产中心一流且免费。关于美国有色人种军队士兵的互动展览很好。沿肯塔基河的场地风景优美。强烈推荐。"},
    {"name":"Raintree_Thailand","rating":3,"text":"游客中心不错，但室外场地尚未充分开发。可以看到重建的白宫，但遗址大部分仍是未开发的田野。"},
    {"name":"kentuckycharliec","rating":5,"text":"大多数人不知道的瑰宝。南北战争期间，数千名被奴役的人在这里获得自由。展览情感震撼人心。"},
    {"name":"Raintree_Thailand","rating":2,"text":"战争时期遗址上曾有300多栋建筑，但现在只剩一栋。除了游客中心和一座并不十分真实的重建营房，实际上没什么可看的。公园内的小径标识也相当混乱。"}],
  "buck-island-reef-national-monument": [{"name":"Sarah F","rating":5,"text":"浮潜体验绝对令人惊艳！穿越麋鹿角珊瑚的水下游览路线令人叹为观止。海滩纯净，海水清澈见底。圣克罗伊岛的必游之地。"},
    {"name":"Dawn S","rating":5,"text":"我一生中最棒的浮潜体验之一。海洋生物丰富，指定路线标识清晰。自带装备或在船上租用均可。"},
    {"name":"Laura K","rating":5,"text":"乘双体帆船出海度过了一整天。珊瑚礁美丽健康。看到了海龟、鳐鱼和数百种热带鱼。物有所值。"},
    {"name":"Passenger65853099881","rating":2,"text":"出海过程还好，但浮潜区域挤满了其他旅游团。回程时还晕船了。珊瑚礁不错，但不值得这番折腾。"},
    {"name":"Ljctravelers","rating":5,"text":"这是真正的国家珍宝。受保护的珊瑚礁生机勃勃。穿越岛屿到达另一侧海滩的步行也非常值得。"}],
  "canyon-de-chelly-national-monument": [{"name":"George A","rating":5,"text":"美国最壮观的地方之一。峡谷壁高达数百英尺，内部的纳瓦霍遗址令人叹为观止。沿峡谷边缘驾车游览的景色令人屏息。"},
    {"name":"Cindy S","rating":5,"text":"乘坐吉普车与纳瓦霍向导进入峡谷，这是我们整个旅途中最精彩的体验。没有向导不得入内，而且绝对值得。"},
    {"name":"Carol N","rating":5,"text":"日落时分的蜘蛛岩是我见过的最美的景色之一。白屋遗址小径是唯一一条无需向导即可徒步的路线。不要错过。"},
    {"name":"psicokitty","rating":5,"text":"在一个活着的纳瓦霍社区内的古老阿纳萨齐悬崖民居。与博学的纳瓦霍向导一同探索这座峡谷的体验是无可替代的。"},
    {"name":"Claudia H","rating":3,"text":"峡谷很美，但附近的钦利镇非常破旧，该地区的设施有限。请为餐饮和住宿做好充足预算。"},
    {"name":"sandramR8284OH","rating":2,"text":"南缘驾车道铺了新碎石却没有任何提示——我们行驶了数英里，才发现一半的观景台都关闭了。当地人似乎不喜欢游客。一对可怜的德国夫妇的后车窗被弹出的碎石砸碎。进出钦利的道路上到处是死狗。非常令人沮丧的旅行。"}],
  "castle-mountains-national-monument": [{"name":"DesertHiker2023","rating":4,"text":"一座安静偏远的公园，拥有美丽的约书亚树林和淘金时代的矿山遗址。这里很可能只有你一人。城堡山小径值得一走。"},
    {"name":"Mojave_Fan","rating":3,"text":"非常偏远，难以到达。道路崎岖，需要高底盘车辆。风景不错，但与周边莫哈韦地区相比没有显著不同。"},
    {"name":"KathleenNPS","rating":5,"text":"国家公园系统中最新且访客最少的单元之一。从沙漠灌木到矮松-刺柏林地的过渡令人着迷。历史矿山建筑增添了趣味。"},
    {"name":"AZtraveler2","rating":2,"text":"完全没有任何设施。没有游客中心，没有卫生间，没有饮用水。泥土路崎岖难行。除非你特意寻求独处，否则其他莫哈韦景点能提供更多。"}],
  "blackstone-river-valley-national-historical-park": [{"name":"NewEnglandExplorer","rating":5,"text":"布莱克斯通河谷是美国工业革命的发源地。帕特基特游客中心将这段历史讲述得非常精彩。沿运河的自行车道非常棒。"},
    {"name":"RIhistorybuff","rating":4,"text":"斯莱特纺纱厂是这里的必游之地。早期纺织机械的演示令人着迷。国家公园护林员对劳工和工业历史非常了解。"},
    {"name":"cycleBKVP","rating":4,"text":"沿布莱克斯通谷自行车道骑行了20英里，体验极佳。沿途穿越历史悠久的磨坊村、运河船闸和美丽的河岸风光。"},
    {"name":"TouristFromMA","rating":2,"text":"遗产走廊横跨大片区域，没有中心起点。国家公园服务的存在感极弱。我们开了几个小时的车，没有找到多少实质性的内容。"},
    {"name":"MassTravels","rating":3,"text":"历史有趣，但作为统一的公园体验难以把握。更像是各自独立景点的集合。提前做好功课会有收获，否则会一头雾水。"}],
  "tule-lake-national-monument": [{"name":"WW2HistoryFan","rating":5,"text":"图利湖隔离中心是二战期间所有日裔美国人拘禁地点中规模最大、争议最多的一处。博物馆设计周到，令人深受触动。"},
    {"name":"SacramentoTraveler","rating":4,"text":"重要却被忽视的历史。该营地曾关押超过18000名日裔美国人。营地内监狱的参观尤为令人难忘。护林员非常出色。"},
    {"name":"CalNatParks","rating":3,"text":"地处北加利福尼亚州俄勒冈边境附近的偏远位置。设施简陋。历史重要，但呈现方式有待改进。如果在附近值得停留。"},
    {"name":"PacificNWexplorer","rating":2,"text":"很难找到，到达时指示牌也很差。仅剩一栋建筑。考虑到历史意义，原本期待更多。"}],
  "cape-krusenstern-national-monument": [{"name":"AlaskaAdventurer","rating":5,"text":"地球上最偏远、最原始的地方之一。114条海滩脊包含6000年的人类居住历史。乘坐小型飞机或船只抵达本身就是一场冒险。"},
    {"name":"WildernessSeeker","rating":4,"text":"令人叹为观止的北极荒野，拥有包括驯鹿、海豹和北极熊在内的丰富野生动物。没有小径或设施，但这正是其魅力所在。仅适合严肃的荒野探险爱好者。"},
    {"name":"ArcticTraveler","rating":3,"text":"非凡的地方，但对大多数人来说完全无法到达。从科策布来这里的费用相当可观，天气可能导致几天无法进入。请仔细规划。"},
    {"name":"avidNHtraveler","rating":2,"text":"您需要从科策布包租一架小型飞机——费用昂贵——到达后只能靠自己，没有设施、没有小径、没有游客中心，也没有任何服务。对大多数游客来说并非实际可行的目的地。"}],
  "grand-canyon-parashant-national-monument": [{"name":"UTwilderness","rating":5,"text":"48个相邻州中面积最大、最偏远的国家纪念碑之一。进入需要高底盘四驱车，但回报是绝对的孤独和令人难以置信的风景。"},
    {"name":"AZbackcountry","rating":4,"text":"纪念碑内的白口袋是其他地方无与伦比的层叠砂岩地貌。没有设施，没有护林员，只有原始荒野。请自备所有所需物资。"},
    {"name":"OverlandExpedition","rating":3,"text":"纪念碑面积广阔，但极难进入。大部分地区需要严肃的越野能力，道路经常被冲毁。需要多天才能充分探索。"},
    {"name":"NVnomad","rating":2,"text":"来这里是为了从北缘地区欣赏大峡谷的景色，但近期降雨后道路无法通行。附近没有任何信息站或援助。"}],
  "aniakchak-national-monument-and-preserve": [{"name":"AlaskaVolcanoExpedition","rating":5,"text":"阿尼亚克查克破火山口是北美最壮观的地质景观之一。直径10英里的破火山口内有一座火山口湖、活跃的火山口和令人叹为观止的野生动物。"},
    {"name":"RemoteAK","rating":4,"text":"绝对偏远，进入极具挑战性。从金萨蒙乘小型丛林飞机飞入。破火山口内的感觉如同另一个世界。没有小径，没有设施，纯粹的荒野。"},
    {"name":"AKbackcountry","rating":3,"text":"如果能到达，景色壮观。天气使进入非常不可靠——我们被困了额外两天。进入费用昂贵。仅适合有经验的阿拉斯加荒野旅行者。"},
    {"name":"Forest_R","rating":2,"text":"天气变差——限制了我们能做和看到的东西。我们包租了昂贵的航班，结果在地面上的时间极为短暂。这是访客最少的国家公园系统单元是有原因的：极度偏远、进入成本高昂，而且很有可能根本无法降落。"}],
  "lake-clark-national-park-and-preserve": [{"name":"AlaskaExplorer","rating":5,"text":"国家公园系统中最多元的公园之一。我们飞入波特阿尔斯沃斯，沿海岸徒步、划皮艇并观看棕熊。绝对一流的体验。"},
    {"name":"BearWatcher","rating":5,"text":"观看棕熊在奇利卡德罗特纳河中捕捞红鲑鱼。山脉、冰川、海岸、苔原——克拉克湖拥有阿拉斯加的一切。"},
    {"name":"AKflyIn","rating":4,"text":"偏远且进入费用高昂，但物有所值。公园几乎没有任何基础设施，意味着真正的荒野体验。从安克雷奇包租水上飞机前往。"},
    {"name":"NorthernLights_AK","rating":3,"text":"风景优美，但到达这里的成本和复杂程度相当高。仅交通费用每人就需预算1500至2000美元。天气取消情况很常见。请多预留几天时间。"},
    {"name":"Eternal_Wanderer","rating":2,"text":"到达这里需要从安克雷奇或霍默包租水上飞机，费用令人咋舌。我们在机票上花了一大笔钱，结果在降落点附近的地区被浓雾笼罩了整整两天。有时这就意味着既昂贵又令人沮丧。"}],
  "yucca-house-national-monument": [{"name":"MesaVerdeHiker","rating":3,"text":"尤卡屋是一处未经挖掘的祖先普韦布洛人遗址，看起来像田野中的一个大土丘。除非你知道自己在看什么，否则几乎没什么可看的。还是去梅萨维德更好。"},
    {"name":"ArchaeologyBuff","rating":4,"text":"对于考古爱好者来说，知道这个土丘内含有一个尚未发掘的主要祖先普韦布洛人村落是令人着迷的。该遗址被刻意保持自然状态。"},
    {"name":"ColoradoNPS","rating":2,"text":"基本上是一个私人牧场土地上覆盖着草的土丘。进入需要提前安排。没有游客中心，没有设施，现场没有解说材料。非常令人扫兴。"},
    {"name":"SWarchaeologist","rating":5,"text":"刻意不对尤卡屋进行挖掘的选择是为子孙后代保留它。沿周边漫步，想象曾经在这里繁荣生活的社区。"}],
  "tule-springs-fossil-beds-national-monument": [{"name":"LasVegasLocal","rating":4,"text":"拉斯维加斯市内绝佳的逃离赌场之地。公园建立时间不长，仍在发展中。有不错的步行和骑行小径、良好的观鸟环境，以及有趣的化石历史。"},
    {"name":"PaleoFan","rating":5,"text":"该地区包含猛犸象、骆驼和美洲马的冰河时代化石。游客中心仍在发展中，但自然区域美丽且不拥挤。"},
    {"name":"NVhiker","rating":3,"text":"不错的自然区域，但设施简陋。没有遮阴设施，停车位有限，小径标识不够清晰。夏季最好在冬天或清晨前往。"},
    {"name":"Disappointed_visitor","rating":2,"text":"原以为会有真正的化石遗址体验。公园内根本看不到化石。游客中心很小。基于那些宣传，感觉名不副实。"}],
  "carlisle-federal-indian-boarding-school-national-monument": [{"name":"Ridge66","rating":5,"text":"这里的历史深刻而沉重。那座葬着远离家人而死去的孩子们的墓地令人心碎。吉姆·索普等人的故事栩栩如生。勒托特泉为这处肃穆的遗址增添了几分美丽。"},
    {"name":"Kevin C","rating":3,"text":"作为现役国防部设施，向公众开放的区域并不多。开放区域，尤其是墓地，对历史学生来说很有意义。"},
    {"name":"DMGAmes_Iowa","rating":3,"text":"历史建筑和重要历史，但入场限制使参观困难重重。警卫让我们交出证件并等待20分钟进行安全审查。"},
    {"name":"nancydto","rating":5,"text":"兵营讲述了从独立战争时期至今的历史故事。印度学校墓地是一段黑暗历史的警醒提示。"},
    {"name":"garykramlich","rating":2,"text":"如果没有现役军人证，几乎不可能进入。他们在大门口拒绝了我们。对于如此具有历史意义的场所，向公众开放的区域极为有限。"}],
  "emmett-till-and-mamie-till-mobley-national-monument": [{"name":"Kate","rating":5,"text":"我在解说中心开放前的一个星期六参观，整个小镇的牌匾和信息生动有力地还原了这里发生的历史。"},
    {"name":"Julie W","rating":5,"text":"一个比任何书籍都更能震撼人心的地方，以真实和现实呈现了那个美丽男孩最后旅程的全貌。向导没有回避这段痛苦的历史。"},
    {"name":"Pittsburgh_cyclist","rating":4,"text":"博物馆就在埃米特·蒂尔凶手被宣判无罪的法院对面。看到如此不公正发生的地方，至今仍令人感到不安。"},
    {"name":"Aerowing","rating":4,"text":"我在工作日前往时解说中心已关闭。对面的法院充满历史。该地区还有其他几处埃米特·蒂尔相关遗址可参观。"},
    {"name":"retrobolted1","rating":3,"text":"预约的导览感觉有些仓促。向导很友善，但某些方面的介绍缺乏深度。对于理解美国历史来说仍然非常值得且重要。"},
    {"name":"PurpleAnkh","rating":2,"text":"展览信息量很大，但不是我迫切需要再次参观的地方。介绍视频太长了。不允许拍照。这是一个社区展览，看起来确实如此——展示方式感觉过时且资金不足。"}],
  "frances-perkins-national-monument": [{"name":"Sue L","rating":5,"text":"场地打理得一丝不苟，种满了各种开花植物。工作人员和志愿者非常友好和热情。这是一处纪念一位先驱女性的重要遗址。"},
    {"name":"Sojourner08033","rating":4,"text":"位于纽卡斯尔，这处国家历史地标是弗朗西斯·珀金斯的祖籍，她是美国第一位女性内阁成员。目前正在翻修，但有自助参观展览可供参观。"},
    {"name":"westie2","rating":3,"text":"中心的建筑与弗朗西斯并无直接关联，但我们被告知她家附近的农场正在修复中。具有教育意义的参观，但与遗址的联系感觉较为牵强。"},
    {"name":"RJR","rating":4,"text":"国家公园管理局最新的财产之一。谷仓里有关于她的生平和职业的展览。主楼预计不久将向公众开放参观。"},
    {"name":"Sylvie07","rating":4,"text":"小型单间博物馆，展有关于这位先驱女性的文物。考虑到她对美国劳工政策的重大贡献，没有至少再增加一个房间实在可惜。"},
    {"name":"Sojourner08033","rating":2,"text":"我们参观时，主楼因持续翻修而关闭，没有明确的重新开放日期。场地环境宜人，但实际上几乎没什么可看或可做的。考虑到前往缅因州海岸这处偏僻地点所需的驾车距离，普通游客可能会觉得此次绕道不值得。"}],
  "freedom-riders-national-monument": [{"name":"Sydney","rating":4,"text":"国家公园服务中心现已开放，但开放时间非常有限。大量描述性标牌配有自由乘客的壁画。美国民权历史的重要篇章，以精彩的方式被纪念。"},
    {"name":"valliam13","rating":5,"text":"旧汽车站正在改建，以复现其20世纪60年代的原貌。驻场护林员知识渊博，对这段历史充满热情。"},
    {"name":"dkorwood","rating":4,"text":"只参观了公共汽车遗址，但制作非常精良。具有历史意义的诺布尔大街是灰狗和短途汽车壁画的核心地点。这是一处非常有意义的民权停留点。"},
    {"name":"E&J50","rating":3,"text":"是我们阿拉巴马州民权之旅的重要一站。旧汽车站内的国家公园服务中心开放时间有限，游客有时会被引导前往卡尔霍恩县商会。"},
    {"name":"Corrie P","rating":2,"text":"这个小镇有大量历史，但城市本身有些破旧。很多废弃的店铺，纪念碑周边地区感觉不太安全。纪念碑本身令人感动。"}],
  "medgar-and-myrlie-evers-home-national-monument": [{"name":"clr2015","rating":5,"text":"民权历史在这栋房子里栩栩如生。射杀梅德加·埃弗斯的子弹穿过前窗，射入了墙壁。家人曾把床垫铺在地板上睡觉，以求保护。"},
    {"name":"Kate","rating":5,"text":"这是一次令人震撼的参观，深刻体现了密西西比州民权运动和种族主义的紧迫性。我从公园护林员那里获得了一次精彩的导览。"},
    {"name":"Robin B","rating":5,"text":"这栋房子现由国家公园管理局管理，因此开放时间更长。家具符合时代特点，故事有趣且深刻感人。"},
    {"name":"Hatzlacha","rating":4,"text":"驾车经过这栋房子绝对令人大开眼界。我不确定这个社区是否足够安全。但我认为值得去看看。请提前预约，因为需要导览。"},
    {"name":"subterranean_jack","rating":3,"text":"如果您对民权运动感兴趣，这是一个重要的停留点。但进入需要提前预约，周日无法参观。仅仅站在这里就已令人动容。"},
    {"name":"subterranean_jack","rating":2,"text":"遗址从主路上几乎看不到标识——我们开车路过了两次。作为国家纪念碑，它仍然严重欠开发，没有合适的游客中心，停车位有限，也没有定期发布的导览时间表。"}],
  "mill-springs-battlefield-national-monument": [{"name":"Harley Hedgehog","rating":5,"text":"米尔斯普林斯是一处相对较新的国家纪念碑，拥有组织完善且内容详尽的博物馆，详述了这场战役。配合国家公园服务应用程序的10站自助驾车游览非常出色。"},
    {"name":"Partsman123","rating":5,"text":"工作人员都非常友好、博学、乐于助人。这里是南北战争中联邦军第一次决定性胜利的地点。非常被低估的遗址。"},
    {"name":"Teardrop Trailer Traveler","rating":4,"text":"前两站不错，有几条小径。驾车游览的第三和第四站除了田野中的标志牌外，几乎没什么可看的。"},
    {"name":"Dewayne P","rating":4,"text":"不错的停留点，尽管有点绕路。建议先从游客中心开始，观看短片并参观博物馆，再进行驾车游览。"},
    {"name":"Paul K","rating":3,"text":"这场南北战争早期战役通过展览、文物和视觉材料得到了很好的呈现。然而，驾车游览的许多站点提供的只是一块参考牌。"},
    {"name":"Paul_K","rating":2,"text":"战场自助驾车游览令人失望。十个站点中有几个只提供路边空旷田野中的一块牌匾。一些站点的信息牌严重过时。希望像葛底斯堡那样丰富战场体验的游客会感到失望。"}],
  "amache-national-historic-site": [{"name":"Hatzlacha","rating":5,"text":"很难想象美国公民曾在战时被关押于此。遗址内各处的信息标牌非常出色。这次体验有效传达了美国历史这段黑暗篇章的规模。"},
    {"name":"MNice","rating":4,"text":"原计划只参观15分钟，结果待了一个多小时。博物馆首先提供了良好的背景信息。开放遗址上没有游客设施，但隔绝的氛围增强了参观的震撼感。"},
    {"name":"Bill K","rating":5,"text":"我们历史上可耻的一页，当地团体做了令人惊叹的工作来重新认领和重建这里。自助驾车游览非常有助于理解营地生活。"},
    {"name":"Vincent L","rating":3,"text":"在承认遗址历史重要性的同时，除了几块简单的标牌外，没有任何游客设施。不提前做功课的话，参观体验缺乏背景感。"},
    {"name":"RandySessions","rating":2,"text":"这个地方很难到达，位于科罗拉多州东南部靠近堪萨斯边境，距科罗拉多斯普林斯约三小时车程。几乎没有实物遗存。仅适合二战历史爱好者。"}],
  "baltimore-washington-parkway": [{"name":"dbinhou7511","rating":4,"text":"比95号州际公路风景更优美，有迷人的树木成荫路段。可通往国家安全局和国家野生动物管理局总部。非高峰时段驾车的好选择。"},
    {"name":"Maurene_K","rating":3,"text":"沿途有许多景点，包括美国宇航局和航空博物馆。秋季叶色迷人。但与乔治华盛顿公园大道相比还是有差距。"},
    {"name":"trixietrix","rating":3,"text":"靠右行驶！并排行驶的司机阻塞了所有交通。公园大道的双车道设计使任何拥堵时这个问题都尤为突出。"},
    {"name":"Mitchell S","rating":2,"text":"似乎总是堵车。轻微事故就会造成严重拥堵。汇入困难使这条路与直接走95号州际公路相比非常令人沮丧。"},
    {"name":"GlennW0147","rating":1,"text":"过时、拥堵，路况极差。197号公路与32号公路之间的路段坑坑洼洼。完全避开这条路，直接走95号州际公路，保住你的理智。"}],
  "blackwell-school-national-historic-site": [{"name":"MarfaVisitor","rating":5,"text":"布莱克韦尔学校讲述了德克萨斯州墨西哥裔美国儿童实际上被种族隔离的故事。1909年的原始土坯校舍是那段历史的有力见证。"},
    {"name":"TexasCultural","rating":5,"text":"一处新指定的国家历史遗址，理应获得更多认可。那些被禁止说西班牙语的前学生的故事令人痛心，也至关重要。"},
    {"name":"WestTexasRoadTrip","rating":4,"text":"马尔法一处规模小但意义深远的遗址。国家公园管理局刚刚接管运营，设施仍在完善中。拉丁裔学生种族隔离教育的历史需要被讲述。"},
    {"name":"MarfaWeekend","rating":3,"text":"有趣的遗址，但由于最近才成为国家公园管理局管理的遗址，游客体验仍然非常有限。如果您已经在马尔法参观贾德基金会或奇纳蒂，值得顺道一看。"},
    {"name":"SouthTexas_History","rating":2,"text":"到达后发现开放时间非常有限，展览极少。这所学校最近才成为国家历史遗址，实际上尚未做好迎接游客的准备。前往前请查询开放时间。"}],
  "bluestone-national-scenic-river": [{"name":"JenniferandAlan","rating":5,"text":"一片美丽宁静、不可错过的蓝色湖泊。蓝石河及周边的州立公园提供令人叹为观止的风景、良好的垂钓环境，以及紧邻水边的小屋出租。"},
    {"name":"Jay O","rating":5,"text":"我们爱上了蓝石，这是我们第二次在这里的小屋度夏。简朴而舒适，方便前往附近的派普斯坦姆度假村活动。"},
    {"name":"Karen123WV","rating":3,"text":"公园不错，但小径难度标识有误导性。一条被描述为简单/中等的小径坡度极陡，路面极窄，非常危险。游客服务在管理预期方面可以做得更好。"},
    {"name":"Tammy W","rating":1,"text":"在码头的糟糕体验。服务态度极差。我不建议从码头工作人员那里租用设备。公园风景很美，但服务毁了整个体验。"},
    {"name":"Cheryl677","rating":4,"text":"非常不错的大湖，可以免费下水。沿河有风景优美的步道。小径上有一些维护问题，但自然美景使其物有所值。"}],
  "ice-age-national-scenic-trail": [{"name":"retirees2011","rating":5,"text":"冰河时代步道沿着最近一次冰川期的边缘延伸。麦迪逊附近的谷景路段提供了令人印象深刻的林地和开阔视野。一段非凡的地质之旅。"},
    {"name":"Kendall S","rating":5,"text":"直布罗陀岩是步道上最受欢迎的地点，有一段具有挑战性的上坡路段，视野开阔令人赏心悦目。全长1100英里的步道是威斯康星州的瑰宝。"},
    {"name":"mgomez2468","rating":5,"text":"步道以黄色标记清晰标识，风景多样，包括草甸、森林和冰碛丘。夏季请携带驱虫剂并穿着防护服。"},
    {"name":"TJ O","rating":3,"text":"这是一处适合慢跑和徒步的宜人自然区域，但我质疑它是否真的可以算作单一景点，因为它分散在整个州。"},
    {"name":"jason l","rating":2,"text":"某些路段维护不佳，植被过度生长，遮挡了道路。部分地区的步道标识不一致。还发现一些近期的命名更改令人困惑，且没有得到很好的沟通。"}],
  "lower-delaware-national-wild-and-scenic-river": [{"name":"Reggie C","rating":5,"text":"游览该地区的绝佳方式。沿纽约97号公路驾车行驶，欣赏下特拉华河沿岸风光。有很多地方可以停下来欣赏河景。秋叶季节尤为壮观。"},
    {"name":"Benshi R","rating":4,"text":"美丽的参观地点，但要小心驾驶。河边停车位有限，部分路段道路狭窄。整个河谷风景优美。"},
    {"name":"gostartraveler","rating":3,"text":"普朗克路段以后的河边公路极为狭窄，标识也有警示。绝对只适合白天驾驶。风景优美，但需要耐心和谨慎驾驶。"},
    {"name":"zodreb","rating":2,"text":"与美国其他任何地方的驾车体验相比并无特别之处。这是一个户外活动目的地，本身并不是非看不可的风景驾车路线。"},
    {"name":"M Jay","rating":5,"text":"中大西洋地区最佳风景驾车路线之一。花了一整天探索该地区。在特拉华河上皮划艇和独木舟的体验极为精彩。"}],
  "new-england-national-scenic-trail": [{"name":"nbend1","rating":5,"text":"这样的步道正是吉尔福德和新英格兰的魅力所在。从海岸线向北穿越康涅狄格州森林的新英格兰步道无疑值得一走。"},
    {"name":"James C","rating":4,"text":"从奇滕登公园到步道起点的公路步行带您穿越一些历史地区并经过博物馆。步道本身蜿蜒穿过迷人的新英格兰林地。"},
    {"name":"Steve N","rating":4,"text":"步道从吉尔福德的海岸线开始，穿越小镇后进入森林。经典新英格兰风景中维护良好、标识清晰。"},
    {"name":"957mimi","rating":5,"text":"这是一片美丽的森林，展示了什么是优质的林业管理。步道穿越山脊、湿地和历史景观。"},
    {"name":"CTHiker22","rating":3,"text":"不错的步道，但康涅狄格州南部路段感觉不连贯，需要一些公路步行。进入马萨诸塞州高地后步道体验更好。"},
    {"name":"James_C","rating":2,"text":"穿越吉尔福德等小镇的公路步行路段说实话相当无聊——沿繁忙的1号公路与汽车同行，而非穿越如画的乡村。穿越1号公路实际上相当危险。步道还存在标识不一致的问题。"}],
  "niobrara-national-scenic-river": [{"name":"JoAnn H","rating":5,"text":"这是一条宽浅的河流，情人节附近的景色最佳。穿越峡谷地带的美丽漂流之旅。沿途的瀑布是令人愉快的惊喜。"},
    {"name":"whoknows987","rating":5,"text":"很棒的河流，足够平缓，让我毫不担心地带着三个十几岁的外孙划独木舟。中西部最棒的漂流体验之一。"},
    {"name":"Gregory B","rating":3,"text":"内布拉斯加州情人节地区一处不错且有教育意义的停留点。非常独特有趣，但对于这样高品质的国家风景河流，游客中心实在太小了。"},
    {"name":"aussiewanderers","rating":4,"text":"极少有超过成人膝盖深度的地方，只有缓和的激流。非常适合保守型桨手或老年游客。峡谷风景宜人。"},
    {"name":"Judy7751","rating":3,"text":"风景优美，但部分河段非常浅，划皮划艇困难重重。夏末水位可能相当低。前往前请查询水况。"},
    {"name":"Judy7751","rating":2,"text":"部分河段非常浅，划皮划艇困难重重——我们不断触底。我们使用的户外运营商组织混乱，返回的班车也严重延误。夏季周末的河流也越来越成为嘈杂团体和垃圾随处可见的'派对漂流'场景。"}],
  "north-country-national-scenic-trail": [{"name":"valliam13","rating":5,"text":"这是一条美丽的步道，非常美丽且维护良好。木栈道路段带您穿越一些非常潮湿的沼泽地带。冬季雪景中尤为美丽。"},
    {"name":"Heather A","rating":5,"text":"已经得到了很好的开凿和改善！感谢所有参与建设的人！这是美国最长的国家风景步道，值得获得更多认可。"},
    {"name":"Eisme77","rating":5,"text":"这条步道在某些地方真的令人叹为观止——它带您穿越开阔草甸、阔叶林和壮观的五大湖风景。从纽约到北达科他州超过4600英里。"},
    {"name":"NCTsection_hiker","rating":3,"text":"部分路段出色，但其他路段标识极少，方向标记不清晰。步道质量因州和维护章节差异极大。前往前请研究具体路段。"},
    {"name":"MichiganBackpacker","rating":2,"text":"徒步了密歇根州的一段，原以为会有维护良好的步道，却发现大量倒木和植被过密的路段。步道协会由志愿者运营，部分路段明显需要关注。"}],
  "potomac-heritage-national-scenic-trail": [{"name":"Anthony-Susan","rating":5,"text":"华盛顿特区对于对自然、精彩历史和挑战感兴趣的徒步者来说最隐秘的宝藏。麦克莱恩附近的4英里路段特色鲜明，有倒落的树木、花岗岩巨石和马西堡。"},
    {"name":"Richard S","rating":4,"text":"华盛顿特区附近地形崎岖的步道。阵亡将士纪念日周末徒步了近一个小时没有遇到其他人。将车停在火鸡奔公园的C停车场可以方便进入步道。"},
    {"name":"Kelly D","rating":3,"text":"沿波托马克河轻松愉快地换换心情。炎热天气里遮阴极好，但较窄路段有一些毒藤需要注意。适合有活跃年长孩子的家庭。"},
    {"name":"Stuart S","rating":5,"text":"沿波托马克河的美丽徒步，挑战性不大，适合家庭出行。植物多样性和河岸风景令人叹为观止。"},
    {"name":"Martha W","rating":4,"text":"从平坦宽阔到沿河崎岖路段，植被和景观多样性令人叹为观止。春季野花在这里尤为美丽。"},
    {"name":"583liza","rating":1,"text":"我们试图找到进入波托马克遗产国家风景步道的入口，但找不到。就连公园管理局的护林员也无法解释地图！步道是由不连贯路段拼凑而成的，没有清晰的入口，标识在某些路段完全消失。"}],
  "charles-young-buffalo-soldiers-national-monument": [{"name":"CivilRightsHistory","rating":5,"text":"查尔斯·扬上校是美国历史上一位杰出人物。他在俄亥俄州威尔伯福斯的故居保存完好，护林员的导览出色且令人动容。"},
    {"name":"OhioHistory_Fan","rating":5,"text":"美国历史上第一位非裔美国国家公园负责人。他被强制退休以及为证明自己体能而进行的著名骑行故事非凡传奇。必游之地。"},
    {"name":"WilberforceVisitor","rating":4,"text":"规模小但震撼人心的遗址。护林员显然热爱这段历史，这在导览质量上一览无余。扬上校在吉姆·克劳法下取得的成就令人振奋。"},
    {"name":"OH_Roadtrip","rating":3,"text":"有趣的遗址，但游客设施有限。导览需要提前预约，开放时间受限。对于历史爱好者来说，值得提前规划。"},
    {"name":"MilitaryHistory_Buff","rating":2,"text":"驱车2小时发现遗址关闭，没有任何解释。提前致电时也无人接听。这处具有重要历史意义的遗址需要更好的沟通和人员配置。"}],
  "chickasaw-national-recreation-area": [{"name":"OklahomaFamily","rating":5,"text":"奇卡索国家休闲区被誉为平原上的游乐场，实至名归。硫磺泉附近的泉水、游泳洞和步道非常适合家庭出游。"},
    {"name":"TrailRunner_OK","rating":4,"text":"各个泉眼和湖泊周围有很棒的步道。石灰华溪美丽动人，有天然游泳洞。岩石景观和淡水泉在俄克拉荷马州独一无二。"},
    {"name":"LakeVisitor","rating":4,"text":"湖上有不错的露营和划船活动。阿巴克尔水库是很好的逃离去处。硫磺镇附近的泉水区是亮点——清澈凉爽。"},
    {"name":"SummerSwimmer","rating":3,"text":"夏季周末极为拥挤。石灰华溪的游泳洞可能需要排队。设施还算不错，但人群大大降低了体验感。"},
    {"name":"OK_Weekend_Trip","rating":2,"text":"劳动节周末前往，公园绝对人满为患。没有可用的露营地，停车位到处溢出，溪流被游客丢下的垃圾污染。令人失望。"}],
  "el-malpais-national-monument": [{"name":"NM_Explorer","rating":5,"text":"埃尔马尔帕伊斯意为'荒地'，广阔的熔岩原野与冰洞和火山拱门令人惊叹。穿越熔岩的祖尼-阿科马步道令人难忘。"},
    {"name":"LavaTuber","rating":5,"text":"接合洞熔岩管需要提灯探索，但这是我进入过的最令人印象深刻的熔岩管洞穴之一。大管区有多条熔岩管可供探索。"},
    {"name":"NewMexicoRoadtrip","rating":4,"text":"紧邻埃尔莫罗的绝佳自然区域。拉文塔纳天然拱门壮观且易于到达。火山地貌多样，生态系统各异。"},
    {"name":"HighDesert_Adventurer","rating":3,"text":"面积广阔，有多个入口。部分最佳景观需要走原始道路。格兰茨的游客中心距主要熔岩地貌较远。"},
    {"name":"NM_Roadtrip","rating":2,"text":"低估了在熔岩原野徒步的酷热和暴晒程度。没有任何遮阴，黑色熔岩散发着强烈热量。被严重晒伤。设施极少。"}],
  "el-morro-national-monument": [{"name":"SandstoneHistory","rating":5,"text":"一座令人惊叹的200英尺高砂岩台地，上面铭刻着数百年来的人类签名，包括西班牙征服者、美洲原住民和早期美国定居者。一本露天的历史书。"},
    {"name":"NM_History_Fan","rating":5,"text":"埃尔莫罗底部的水池是它成为地标的原因。几百年来，探险家和旅行者在这里刻下了自己的名字。铭文可追溯到1605年。非凡绝伦。"},
    {"name":"Road_to_Ruins","rating":4,"text":"台地顶部步道通向祖先普韦布洛人遗址，可俯瞰周边高原。铭文是主要看点，绝对不会让您失望。"},
    {"name":"NMtraveler2024","rating":3,"text":"有趣但参观时间很短。铭文步道只有约2英里。如果您在进行新墨西哥州公路旅行，值得停留一个小时，但本身并不是一个目的地。"},
    {"name":"Off_the_beaten_path","rating":2,"text":"地处非常偏远，游客中心开放时间极为有限。下午4点到达时发现已关闭，步道据说同时也关闭。几乎什么都没看到。"}],
  "gauley-river-national-recreation-area": [{"name":"WhiteWater_WV","rating":5,"text":"戈利河是北美最具挑战性的激流漂流河段之一。萨默斯维尔大坝秋季放水制造了传奇般的五级激流。一条值得列入愿望清单的河流。"},
    {"name":"KayakPro","rating":5,"text":"枕头岩、迷失桨、铁环——戈利河的激流是世界上最著名的之一。峡谷内的风景壮观。仅适合有经验的桨手。"},
    {"name":"AdventureGuide","rating":4,"text":"下戈利比上戈利更容易进入，但仍有出色的激流体验。周边国家休闲区有良好的徒步小径，可俯瞰峡谷。"},
    {"name":"WV_Outdoors","rating":3,"text":"河流本身壮观，但国家公园管理局的存在感和设施极为有限。大多数活动由私人运营商承办。不划船的游客会发现基础设施不足。"},
    {"name":"FamilyVacationer","rating":1,"text":"这绝对不适合家庭或初学者。我们通过商业运营商报名，五级激流令人胆战心惊。我们的向导本应更好地审查我们的经验水平。"}],
  "new-river-gorge": [
    {"name":"WhitewaterWest","rating":5,"text":"新河峡谷的急流令人肾上腺素飙升——从四级到五级激流应有尽有，幸好每个弯道都有顶级导游陪同。峡谷本身宛如壮丽的瀑布，令人叹为观止。"},
    {"name":"NPS_Weekender","rating":4,"text":"公园刚升级为国家公园，但配套设施尚未跟上。远足步道参差不齐，许多地方标识不清。不过峡谷景色无与伦比，漂流绝对物超所值。"},
    {"name":"FamilyVacationer","rating":1,"text":"这里完全不适合家庭或初学者。我们通过商业运营商报名参加了这次活动，五级急流令人胆战心惊。导游本该在出发前了解我们的经验水平。"}],
  "governors-island-national-monument": [
    {"name":"NYC_Explorer","rating":5,"text":"总督岛是纽约港中一颗隐藏的明珠。周末渡轮免费，岛上禁止汽车，可以租自行车，公园里有吊床，还能欣赏曼哈顿和自由女神像的美景。"},
    {"name":"HarborViews","rating":5,"text":"从总督岛的港湾坡地眺望下曼哈顿的景色，美得令人窒息。这些小山丘是用二大道地铁施工的挖掘土方堆积而成，本身就是一项工程奇迹。"},
    {"name":"SummerNYC","rating":4,"text":"夏天从曼哈顿来这里避暑再完美不过。艺术活动、餐饮摊位和悠闲的氛围都很棒。渡轮每三十分钟一班，建议早点去抢占吊床位置。"},
    {"name":"HistoryFirst","rating":3,"text":"堡垒和历史建筑很有意思，但非特别活动期间，室内的开放程度相当有限。新建的公园区域很有趣，但更像一座城市公园，而非国家景区。"},
    {"name":"WeekdayVisitor","rating":2,"text":"周二去了一趟，几乎什么都关着。没有餐饮摊位，没有自行车出租，渡轮班次也非常少。小岛风景不错，但在周末和活动之外简直死气沉沉。"}],
  "hovenweep-national-monument": [
    {"name":"DesertArchaeology","rating":5,"text":"霍文威普非凡至极。祖先普韦布洛人在一千年前建造的这些圆形和方形塔楼矗立于峡谷边缘，神秘而美丽，是保存最为完好的遗址之一。"},
    {"name":"SW_RuinsLover","rating":5,"text":"古人峡谷和霍文威普合在一起，让四角地区的这一天变得精彩绝伦。落日余晖洒在塔楼上，景色壮观，游客极少。"},
    {"name":"UTA_Explorer","rating":4,"text":"两英里环形步道可经过六组主要塔楼群。与世隔绝的环境和荒漠风光更增添了这处遗址的神秘气质。请务必带足水。"},
    {"name":"FourCorners_Roadtrip","rating":3,"text":"塔楼令人印象深刻，但游客中心非常小，设施有限。通往此地的土路有些崎岖。对考古爱好者来说值得一来，但仅此而已。"},
    {"name":"DesertTraveler","rating":2,"text":"对一处国家纪念地而言，期望有些落空。塔楼确实有趣，但整个游览不过是一条两英里的环形步道加上一些石砌遗迹。偏远的地理位置意味着要开很长的车，收获却十分有限。"}],
  "john-day-fossil-beds-national-monument": [
    {"name":"PaleoFan_OR","rating":5,"text":"彩绘山单元是俄勒冈州摄影最多的地貌之一。清晨阳光照射在山丘上，景色令人叫绝。克拉诺和羊岩单元同样有出色的化石层。"},
    {"name":"FossilHunter","rating":5,"text":"三千五百万年的太平洋西北化石历史，在这里得到精彩诠释。羊岩单元的托马斯·康顿古生物学中心堪称一绝。"},
    {"name":"OR_Roadtripper","rating":4,"text":"三个单元分布于俄勒冈州东部偏远地区，驾车距离相当长。彩绘山是最易到达且最上镜的地点。若要三处全部游览，请安排两天时间。"},
    {"name":"CentralOR_visitor","rating":3,"text":"彩绘山风景优美，但三个单元之间的车程很长。羊岩的化石层和博物馆很精彩，但合在一起游览就是漫长的一整天。"},
    {"name":"EasternOR_Summer","rating":2,"text":"七月的高温令人难以忍受，步道完全没有遮阴。彩绘山固然美丽，但我们在户外撑不了超过二十分钟。建议春季或秋季前来。"}],
  "upper-delaware-scenic-and-recreational-river": [
    {"name":"PA_NY_Riverine","rating":5,"text":"上特拉华河是东部最美丽的风景河之一。纽约州一侧的97号公路沿河蜿蜒，居高临下俯瞰峡谷，是全州最美的公路之一。"},
    {"name":"Delaware_Paddler","rating":5,"text":"乘独木舟或皮划艇在上特拉华河漂流，可以体验真正的荒野河流，而且距纽约市驾车可达。秃鹰随处可见，河上船只稀少。"},
    {"name":"Birder_PA","rating":4,"text":"特拉华河沿线观鸟绝佳，秃鹰巢穴随处可见。清澈冰凉的河水也是钓鱼的好去处。任何季节景色都很怡人。"},
    {"name":"NY_Daytrip","rating":3,"text":"河流风景优美，但入水点和停车场有限，有时状况不佳。下水前需要提前研究好下水点。"},
    {"name":"CampTrip_Fail","rating":2,"text":"试图在特拉华河沿岸露营，结果发现国家公园管理局指定的营地从水上几乎无法找到。没有详细河流地图的情况下，整个过程非常令人沮丧。"}],
  "kings-canyon": [
    {"name":"dinfamily2009","rating":5,"text":"国王峡谷拥有约塞米蒂曾经的一切——壮阔的花岗岩崖壁、奔腾的河流，却几乎没有游客。沿着发卡弯公路驶入峡谷，每个转弯处都是令人窒息的绝美景色。"},
    {"name":"CDTrip72","rating":4,"text":"公园很美，但地处偏远，服务设施有限，通往雪松林区的道路漫长而蜿蜒。进入公园前务必加满油。到达峡谷底部后，景色令人惊叹。"},
    {"name":"Mark H","rating":3,"text":"我们满怀期待约塞米蒂级别的风景，却发现这里更像一座幽静的荒野公园。主要观景点不错，但对于普通游客来说，可玩的东西不多。冬季道路封闭，也大大压缩了游览季节。"},
    {"name":"brit b","rating":2,"text":"开了四小时车，结果发现五月初大部分设施都关闭了。通往雪松林的路要到春末才开放，入口处也没人提醒我们。我们基本上只看了格兰特树林就离开了。为这么远的路程，实在令人失望。"}],
  "katmai-national-park-and-preserve": [
    {"name":"JDSoui","rating":5,"text":"在布鲁克斯瀑布观看棕熊捕鱼是一生难忘的体验。观景台设计合理，护林员确保所有人的安全。从国王三文鱼乘水上飞机过来，每一分钱都值得。"},
    {"name":"Melissa B","rating":5,"text":"令人叹为观止的野生动物观赏体验。我们在布鲁克斯营地一天之内看到了二十多头熊。万烟谷之旅同样引人入胜——那是一片独一无二的火山地貌。"},
    {"name":"CapnJD","rating":4,"text":"体验令人惊叹，但费用极其高昂。三天行程包括机票、小屋和装备，人均花费超过三千美元。布鲁克斯营地许可证的抽签制度也让人抓狂。"},
    {"name":"PLG1951","rating":2,"text":"飞进去后，三天连续下雨。只远远看到两头熊。按他们收取的价格，小屋条件很一般，餐饮选择极为有限。如果天气不配合，你花了几千美元，只能坐在小屋里发呆。"}],
  "belmont-paul-womens-equality-national-monument": [
    {"name":"Lynette R","rating":5,"text":"距国会山几步之遥的隐藏宝地。室内讲解员对妇女参政权运动了如指掌，讲解细致入微。珍贵文物和旗帜的收藏令人叹为观止。"},
    {"name":"litterpicker1993","rating":4,"text":"规模虽小却震撼人心的博物馆。导览让参政权运动跃然眼前。值得与国会山参观一并安排，但请提前确认开放时间，并非每天都开放。"},
    {"name":"rose4718","rating":2,"text":"参观这座小宅邸大约只需二十分钟。展览有限，也没有互动设施。讲解员显得急躁、兴致寥寥。作为国家纪念地，与华盛顿特区其他景点相比，实在相形见绌。"},
    {"name":"Emma C","rating":2,"text":"从国家广场一路走来，却发现周一闭馆。外面没有任何清晰的告示，国家公园管理局网站上的开放时间也已过时。这次经历令人非常沮丧。"}],
  "birmingham-civil-rights-national-monument": [
    {"name":"Hatzlacha","rating":5,"text":"这是我参观过的最震撼人心的国家公园管理局景点之一。凯利·英格拉姆公园和第十六街浸信会教堂讲述了美国历史上不可或缺的故事。每一位美国人都应该来这里走一走。"},
    {"name":"KK78","rating":4,"text":"历史保存完好的街区，拥有多处重要的民权运动地标。自助游览路线设计出色。请至少留出半天时间，用心感受这里的一切。"},
    {"name":"Teach67k","rating":3,"text":"重要的历史，但纪念地本身大多是户外标牌和铭牌。真正的亮点是附近的民权研究所，但那需要单独购票。单凭国家公园管理局的部分，内容还是偏少。"},
    {"name":"BillinDothan","rating":1,"text":"周日前往，一切都关门大吉。没有护林员值班，游客中心上锁。公园里只有几座雕像。周围环境让我们全家感到不安全。国家公园管理局对这处景点的管理实在太差。"}],
  "booker-t-washington-national-monument": [
    {"name":"Crissy K","rating":5,"text":"这是一处美丽而宁静的地方，讲述了布克·T·华盛顿在奴役中度过的童年。重建的农场建筑和穿越林间的步道令人心境平和、深思沉想。"},
    {"name":"Lauren O","rating":5,"text":"这里的护林员主导项目非常出色。我们对这位重要历史人物有了深入的了解。种植园的复原让他的自传《从奴役到自由》变得鲜活而真实。"},
    {"name":"Randy W","rating":4,"text":"园区景致宜人，展览内容不错，但规模相当小——大约一个小时就能全部游览。野餐区环境十分怡人。如果路过此地值得一停，但不值得专程前来。"},
    {"name":"Katie B","rating":2,"text":"地处偏远，可看的东西极少。几栋复原建筑和一条短短的步道。游客中心的影片还算不错，其余部分基本就是一座挂了几块历史标牌的农场。不值得在弗吉尼亚乡间小路上长途跋涉来此。"}],
  "capulin-volcano-national-monument": [
    {"name":"Whistle-pig","rating":5,"text":"驱车登上死火山顶，沿火山口边缘漫步——可以360度俯瞰四个州的壮阔景色。这是我们游览过的最独特的国家公园管理局景点之一，走入火山口的步道也非常值得。"},
    {"name":"AHinz","rating":5,"text":"这地方真是太酷了！盘旋而上的螺旋公路本身就是一段冒险。站在火山口边缘，向下俯视火山口，向外眺望广阔平原，那种感觉令人终生难忘。非常适合带孩子来。"},
    {"name":"Connie L","rating":3,"text":"停留三十分钟是不错的体验，但除了开车上山和走短短一段火山口步道，也没有太多别的可做。游客中心很小。如果你不是顺路经过这段公路，没有必要专程绕路来此。"},
    {"name":"Crystal L","rating":2,"text":"令人失望。不过是一座长满草的小山，中间有个洞。四周都是一望无际的平原。为此绕行两小时，最终只待了大约四十五分钟。如果恰好经过87号公路，顺带停一下就够了。"}],
  "casa-grande-ruins-national-monument": [
    {"name":"Sue L","rating":5,"text":"霍霍卡姆文化的古代建筑令人着迷，讲解展示也非常出色。护林员会对建造者的工程技术和文化背景进行精彩解说。覆盖在大屋上方的保护性屋顶已成为这里标志性的风景。"},
    {"name":"Great_Beer_Now","rating":4,"text":"保存较好的史前遗址，说明标识清晰，历史背景一目了然。大屋令人印象深刻，虽然不能进入内部。参观约需一小时，持国家公园年票免费入场。"},
    {"name":"Kevin B","rating":3,"text":"遗址很有趣，但规模比预想的小很多。隔着栅栏观看，二十分钟就能看完全部。周围环境也不怎么迷人——地处炎热的平坦农业小镇中央。不值得专程绕道而来。"},
    {"name":"George A","rating":2,"text":"为此绕路，本以为能看到像梅萨维德那样的景象。结果不过是一栋金属棚顶下一座已残破的泥砖建筑，外围是链式围栏。令人大失所望。自助游览小径十五分钟走完。"}],
  "castillo-de-san-marcos-national-monument": [
    {"name":"kkaarrll","rating":5,"text":"美国最古老的石质堡垒，保存状况极为完好。贝壳灰岩城墙、海湾美景和大炮演示，让这里成为圣奥古斯丁的必游之处。务必涂抹防晒霜——城垛上毫无遮阴。"},
    {"name":"MichiganMelissa04","rating":5,"text":"穿行于各个房间并登上炮台的感觉很棒，可以俯瞰港口和城市全景。身着历史服装的护林员更添一份氛围。这是我们圣奥古斯丁之行的一大亮点。"},
    {"name":"Connie SkandiLady","rating":4,"text":"历史悠久且上镜的堡垒，紧邻滨水区。大约一小时便可游览完毕。内部的博物馆房间对堡垒历史介绍得很好。附近停车是个难题。"},
    {"name":"Paul G","rating":3,"text":"这是一座不错的老堡垒，但走过城墙、看过各个房间后，也就没什么别的了。我们去的时候没有大炮演示。语音导览内容也比较基础。圣奥古斯丁市区比单独参观堡垒更有看头。"},
    {"name":"exploration822408","rating":2,"text":"旺季时游客摩肩接踵，简直像个过度商业化的旅游景点。入场排队时间长，进去后又在昏暗的房间里跟着两百人移动。礼品店比某些展览室还大。附近停车费贵得离谱。"}],
  "castle-clinton-national-monument": [
    {"name":"Cjmastic","rating":5,"text":"炮台公园里一段迷人的纽约市历史。大多数人路过这里只是为了买自由女神像的渡轮票，却不知道这里曾是一座要塞、一座剧院、一处移民接待中心，后来还是一座水族馆。请停下脚步，好好阅读展板。"},
    {"name":"Eileen19","rating":4,"text":"免费参观的迷人历史遗址。圆形堡垒城墙很有趣，护林员的讲解也很翔实。在前往自由岛的渡轮出发前，停留二十分钟很值得。"},
    {"name":"Steve-and-Andie","rating":3,"text":"基本上就是现在自由女神像渡轮的售票处。历史展览很简单——几块说明牌和展板，大多数人直接走过不看。本身不是一个值得专程来的景点。"},
    {"name":"Hatzlacha","rating":2,"text":"不注意的话，根本不会意识到这是一处国家纪念地。几乎没有什么可看的——一圈石砌圆墙和几块说明牌。所谓的\"展览\"就是几块展示板。称之为国家纪念地，实在有些言过其实。"}],
  "cedar-breaks-national-monument": [
    {"name":"JimT","rating":5,"text":"游客寥寥的迷你布莱斯峡谷！圆形剧场景色壮观，同样有红岩石林，海拔却高达一万英尺。七月的野花季节美得无与伦比。"},
    {"name":"Lesley H","rating":5,"text":"这是我们犹他州之行意外的亮点。沿着崖顶的几处观景台景色令人屏息，几乎只有我们自己。夜间的观星活动更是叹为观止。"},
    {"name":"DAuntDeb","rating":4,"text":"景色优美，但高海拔意味着仅在六月至十月开放。即使是初夏，道路也可能结冰。园区内设施有限——没有加油站、餐饮或住宿。"},
    {"name":"rdsm77","rating":2,"text":"不过是沿着短短一段公路排列的四处观景台，每处看起来大同小异。在布莱斯峡谷之后，这里感觉像一个逊色的复制品。没有真正意义上的徒步路线。我们三十分钟就离开了，绕道而来实在不值。"}],
  "cesar-e-chavez-national-monument": [
    {"name":"Charlotte S","rating":5,"text":"这是向塞萨尔·查韦斯和农场工人运动致敬的感人场所。纪念花园宁静祥和，游客中心讲述的故事引人入胜。这是美国劳工权利的圣地。"},
    {"name":"Yvette","rating":3,"text":"重要的历史遗址，但规模很小，地处偏僻。游客中心展览有限，园区陈设也比较朴素。如果对查韦斯的故事不太了解，这里提供的背景信息相当有限。"},
    {"name":"Jim W","rating":2,"text":"开车翻山越岭一小时，满以为能看到博物馆级别的体验。结果不过是一个小院，一处墓地，几个房间的展览。开车下山时那段蜿蜒的山路，才是最令人难忘的部分。"},
    {"name":"Jeremiah M","rating":1,"text":"网站明明显示开放，到了却发现已关门。没有护林员值班，大门紧锁。打了网站上列出的电话，只接到了语音信箱。为此白白驱车两小时，一无所获。"}],
  "devils-postpile-national-monument": [
    {"name":"H99","rating":5,"text":"这处柱状玄武岩地貌是加利福尼亚州最独特的地质奇观之一。从班车停靠点走过去很轻松，彩虹瀑布的支线也美不胜收。从马默斯湖出发必去的地方。"},
    {"name":"sandbeachandsun","rating":5,"text":"令人叫绝的六边形玄武岩石柱，仿佛经过人工雕刻。石柱顶部平整如瓦片拼成的地板。光是彩虹瀑布就值回这趟旅程。"},
    {"name":"John K","rating":4,"text":"地质景观美丽，但强制乘坐班车的规定令人烦恼，而且价格不菲。班车费和景区门票需要分开支付。游览石柱本身大约只需二十分钟。"},
    {"name":"Suzanne M","rating":2,"text":"乘坐班车每人还要额外支付八美元，而且班车只运行到下午七点。加上石柱本身比照片看起来小，从我们抵达、乘车进入、徒步到达景区，再乘车返回，花了半天时间，真正观光只有三十分钟。"},
    {"name":"Philippe A","rating":1,"text":"我们参观时道路因施工封闭。在395号公路入口处没有任何通告。还是从另一位游客那里得知道路已封闭数周。精心策划的行程就此白白浪费。"}],
  "fort-frederica-national-monument": [
    {"name":"ExploringontheRoad","rating":5,"text":"圣西蒙斯岛上一处极具魅力且鲜为人知的殖民时代堡垒。遗址氛围浓郁，护林员关于血腥沼泽之战的讲解非常精彩。西班牙苔藓垂挂的环境美不胜收。"},
    {"name":"Nick_Bonarek","rating":5,"text":"我深爱圣西蒙斯岛上这处隐藏的瑰宝。漫步于贝壳灰岩遗迹之间，让人真切感受到1740年代佐治亚州的风貌。游客中心的短片提供了很好的历史背景。"},
    {"name":"margej2013","rating":4,"text":"环境怡人，遗址有趣。自助游览步道标识清晰，说明牌内容翔实。大约需要一小时。可以俯瞰河流的野餐区也很惬意。"},
    {"name":"GolfUMK","rating":3,"text":"原始堡垒留存不多，基本上是地基和半截残墙。如果你不是殖民历史爱好者，这里很难长时间吸引你的兴趣。环境挺美，但遗迹很稀少。"},
    {"name":"807DavidG807","rating":2,"text":"一片旷野，几段残垣断壁。解说也十分有限，几块牌子就是全部。游客中心的短片是最有价值的部分。我们花了三十分钟便觉得已经看遍了一切。圣西蒙斯岛本身比这里更有意思。"}],
  "fort-matanzas-national-monument": [
    {"name":"Dave C","rating":5,"text":"圣奥古斯丁南部一处隐藏的宝地。免费渡轮摆渡到对岸的西班牙小瞭望塔，颇具情趣。大陆一侧有美丽的海滩和自然步道。护林员友善热情，介绍详尽。"},
    {"name":"MichiganMelissa04","rating":5,"text":"真是令人惊喜的发现！渡轮之旅十分有趣，贝壳灰岩塔楼非常上镜，整个体验包括渡轮都完全免费。这里的海滩比圣奥古斯丁的人少得多。"},
    {"name":"Linda K","rating":4,"text":"渡轮受天气影响，每天只在特定时段运行——出发前请务必确认。堡垒本身大约十五分钟就能看完。大陆一侧的自然步道木栈道值得一走。"},
    {"name":"LynCherie","rating":1,"text":"在一个风平浪静的天气里，渡轮以\"大风\"为由停运。护林员耸耸肩说明天再来。我们从圣奥古斯丁开了四十五分钟的车，却一无所获。大陆一侧只是一片没有堡垒视野的小海滩。实在让人沮丧。"}],
  "fort-mchenry-national-monument-and-historic-shrine": [
    {"name":"bhlraven1916","rating":5,"text":"站在《星条旗》诞生的地方，心中充满震撼。堡垒保存完好，护林员项目精彩纷呈，眺望巴尔的摩港的景色也令人心旷神怡。对美国历史爱好者来说是必游之地。"},
    {"name":"Ace T","rating":5,"text":"换旗仪式令人感动，堡垒建筑内的博物馆展览做得很好。从市区可以轻松抵达。请留出一至两小时的游览时间。"},
    {"name":"Joni P","rating":4,"text":"历史保存完好，解说材料丰富。关于炮击事件的影片制作精良。周末停车场很快就满了——请早点到。"},
    {"name":"marilyn d","rating":3,"text":"堡垒不错，但比预想的要小。大多数建筑只是摆放了一些展品的空房间。走过城墙、看过旗帜之后，也就没有别的了。周围的公园不过是一片草地。"},
    {"name":"ASGLondon","rating":2,"text":"来自一个有真正中世纪城堡的国家，这里实在让我提不起劲。一座星形砖砌堡垒，加上一面大旗。博物馆内容基础，语音导览单调乏味。除非你是1812年战争的爱好者，否则从内港打车过来实在不值。"}],
  "fort-monroe-national-monument": [
    {"name":"Karen J","rating":5,"text":"美国有史以来建造的最大石质堡垒，就坐落在切萨皮克湾畔。穿越护城河、沿着城垛和炮台行走，令人回味无穷。博物馆讲述了杰斐逊·戴维斯被囚于此的故事。海景也令人陶醉。"},
    {"name":"PAYEMD","rating":5,"text":"从独立战争到南北战争，这里承载了美国军事史上惊心动魄的一页。\"自由堡垒\"的历史令人动容。傍晚时分沿海滨步道漫步，景色美不胜收。"},
    {"name":"Hal C","rating":4,"text":"这是一处规模宏大、值得细细探索的综合建筑群。部分区域仍是活跃的军事设施或正在改建中。我们参观时，国家公园管理局的配套设施尚在发展阶段，还没有正式的游客中心。"},
    {"name":"Laks V","rating":2,"text":"布局混乱，既无清晰的游客入口，也没有指路标识。堡垒内有一半区域似乎是私人住宅或限制进入区域。炮台博物馆规模很小。开车找来找去，十分令人沮丧。国家公园管理局需要对这处遗址进行大力整改。"}],
  "fort-pulaski-national-monument": [
    {"name":"Clinton C","rating":5,"text":"这是保存最好的南北战争堡垒之一。高大的砖砌城墙、膛线炮留下的弹孔，还有护城河，置身其中仿佛穿越回那个年代。护林员项目一流。"},
    {"name":"scottfromerie","rating":5,"text":"前往泰比岛途中必经的壮观堡垒。建筑工程令人叹为观止，这场炮击战永远改变了战争形态，其历史意义发人深省。"},
    {"name":"Jenny A","rating":4,"text":"堡垒保养良好，园区环境优美。沿外围穿越湿地的步道非常适合观鸟。内部各房间展览内容充实。请留出一至两小时游览。"},
    {"name":"Paige B","rating":2,"text":"一座砖砌堡垒，四周是满是蚊子的湿地。入口处的防虫喷雾警示牌已经说明一切了。内部是昏暗潮湿的房间，摆着一些大炮和人偶。除非你真的钟情于南北战争工事，泰比岛的海滩才是更好的去处。"}],
  "fort-stanwix-national-monument": [
    {"name":"esprouls47","rating":5,"text":"位于纽约州罗马市中心一座完整重建的独立战争堡垒。身着历史服装的讲解员进行的活态历史演示非常出色。孩子们特别喜欢动手参与的活动环节。"},
    {"name":"Maltipoo16","rating":5,"text":"在萨拉托加战役中发挥关键作用的堡垒，重建得相当令人印象深刻。护林员热情而博学。免费入场是一大加分项。"},
    {"name":"Queenstravelbuff","rating":4,"text":"重建质量上乘，项目内容丰富。堡垒内的博物馆规模不大，但内容翔实。罗马市本身吸引力有限，建议结合莫霍克河谷的其他景点一并游览。"},
    {"name":"Glen M","rating":3,"text":"这是复原建筑，并非原始堡垒，多少削弱了历史真实感。木制栅栏墙看起来崭新，因为确实是新建的。历史很有意思，但实物遗址很难传达出事件所发生年代的厚重感。"},
    {"name":"VillagerRick","rating":2,"text":"市中心停车场里的一座木质仿制堡垒。讲解人员很热情，但一座现代复原建筑终究有其局限。我们三十分钟便游览完毕。不值得专程前来。"}],
  "fort-union-national-monument": [
    {"name":"Rebecca W","rating":5,"text":"这里有圣塔菲小径上最壮观的马车车辙遗迹，还有西南部最大边疆军事驻地令人心旷神怡的废墟。漫步于残破的土坯墙之间，背后是桑格里·德·克里斯托山脉，仿佛置身梦境之中。"},
    {"name":"Jen W","rating":5,"text":"最被低估的国家公园管理局景点之一。横跨数十年边疆军事史的三处各具特色的堡垒遗址，规模令人印象深刻，而且几乎只有我们自己在这里游览。"},
    {"name":"Steven P","rating":4,"text":"废墟引人入胜，但地处极为偏远——从新墨西哥州拉斯维加斯沿乡间公路驱车需要整整一小时。游客中心内容不错，穿越废墟的1.6英里步道解说丰富。请带好饮用水和防晒用品。"},
    {"name":"Michelle G","rating":2,"text":"土坯墙正慢慢融回大地。这基本上就是你所能看到的一切。解说牌努力让遗址活起来，但需要大量想象力。这里路途遥远，附近也没有别的可去。仅供历史爱好者。"}],
  "fossil-butte-national-monument": [
    {"name":"BurienTraveler2014","rating":5,"text":"令人叹为观止的化石采石场，出土了世界上保存最完好的始新世鱼类、植物和昆虫化石。游客中心博物馆一流，夏季的护林员导览化石挖掘徒步是独特的体验。"},
    {"name":"Dave C","rating":5,"text":"古生物爱好者的梦想之地。展出的化石达到博物馆级别，远古湖床的景观在荒远中别有一番美丽。如果研究采石场开放，切勿错过。"},
    {"name":"kevan j","rating":4,"text":"规模不大但质量上乘的国家公园管理局景点。游客中心的化石令人印象深刻，自然步道视野开阔。地处怀俄明州西南偏远地带，建议与熊湖或俄勒冈小径遗址联合游览。"},
    {"name":"bandm0m51","rating":2,"text":"从州际公路绕了两小时来到这里。游客中心有几块精美的化石陈列在玻璃后面，户外步道不过是鼠尾草山坡。除非你对五千万年前的鱼类着迷，否则建议跳过。周边地区什么都没有。"}],
  "george-washington-birthplace-national-monument": [
    {"name":"HistoryLover_VA","rating":5,"text":"这是波托马克河畔一处宁静而美丽的遗址，正是我们的第一任总统的出生地。殖民时代农场的复原和沿河的自然步道都令人愉悦。护林员关于华盛顿早年生活的讲解非常出色。"},
    {"name":"Brendan S","rating":3,"text":"园区景色宜人，但出生地的房屋早已不复存在——只剩一块纪念标志。复原的殖民农场较为通用，换个地方也说得通。除非你是华盛顿研究爱好者，弗吉尼亚有更好的殖民时代遗址可以参观。"},
    {"name":"Kathleen D","rating":2,"text":"路途遥远，收获有限。一片曾经有过房屋的旷野，几栋农场建筑，一条自然步道。驾车沿北颈公路前往需要很长时间。乔治·华盛顿的弗农山庄要值得参观得多。"}],
  "george-washington-carver-national-monument": [
    {"name":"Herman02","rating":5,"text":"对一位伟大美国人的感人致敬。博物馆将卡弗从奴役到科学名声的故事诠释得令人动容。穿越草原的自然步道宁静祥和，\"1240男孩\"雕像令人印象深刻。"},
    {"name":"drwatson32","rating":4,"text":"园区维护良好，博物馆内容不错。工作人员友善，知识丰富。步道宜人但较短。如果你在密苏里州西南部，值得停留一小时。"},
    {"name":"RoadScholar","rating":2,"text":"博物馆规模很小，对于这位如此迷人的历史人物来说，呈现实在有些单薄。所谓的\"出生地\"不过是一块标有出生地的旷野。自然步道也只是平淡无奇的奥扎克山地景观。不值得从乔普林开车三十分钟来此。"}],
  "gila-cliff-dwellings-national-monument": [
    {"name":"NMexplorer","rating":5,"text":"这些有七百年历史的崖居建筑令人叹为观止，通往崖居的徒步路线也非常美丽。你可以实际走入各个房间。这是西南部最原汁原味、人流最少的古代居所遗址之一。"},
    {"name":"mary m","rating":3,"text":"崖居很酷，但前往之路极为艰难——从银城出发要走两小时蜿蜒的山路。途中手机信号完全消失。崖居本身大约三十分钟就能看完。"},
    {"name":"NMtraveler22","rating":2,"text":"如果你去过梅萨维德或班德利尔，这里相比之下规模小、印象平淡。悬崖上只有五间房。真正的考验是那段路——每个方向各有四十四英里令人反胃的盘山公路。我同伴两个方向都晕车了。"}],
  "grand-portage-national-monument": [
    {"name":"MNhistory","rating":5,"text":"苏必利尔湖畔一处重建得颇为精美的毛皮贸易驿站。八月的会合节盛况空前，身着历史服装的再现者、独木舟演示和传统工艺一应俱全。大搬运步道本身也是一段颇具挑战、令人回味的徒步体验。"},
    {"name":"Cynthia K","rating":4,"text":"北岸驾车途中的一处好站。栅栏复原建筑和大厅都做得很好，奥吉布韦文化展览提供了重要的历史背景。最好与附近的大搬运州立公园一同游览。"},
    {"name":"Sandra D","rating":2,"text":"主要是一处复原的木质栅栏，内有一些历史家具。除非在年度会合活动期间来访，这里相当清冷。护林员给了我们一本宣传册就没了别的。最多停留十五分钟。"}],
  "hagerman-fossil-beds-national-monument": [
    {"name":"IdahoFan","rating":5,"text":"一处被低估的古生物学遗址，哈格曼镇中心有一座出色的游客中心。哈格曼马化石举世闻名。从纪念地俯瞰蛇河的俄勒冈小径观景台，视野令人叹为观止。"},
    {"name":"jjgautreau","rating":3,"text":"镇上的游客中心有一些不错的化石展品，但实际的纪念地沿河分布，没有特别许可证无法进入。你基本上是从远处眺望一段悬崖。内容有趣，但十分有限。"},
    {"name":"baker635","rating":2,"text":"开车来这里，以为能看到化石采掘场。结果是一个位于购物街的游客中心，以及远眺悬崖的景色。没有化石挖掘，没有挖掘现场可以参观，也没有真正的步道。所谓的\"纪念地\"是蛇河边无法进入的悬崖。名字极具误导性。"}],
  "katahdin-woods-and-waters-national-monument": [
    {"name":"MaineExplorer","rating":5,"text":"缅因州最新的国家纪念地是一片原始的荒野天堂。环路公路提供了卡塔赫丁山的绝美视野，秋叶色彩举世无双。与阿卡迪亚相比，这里几乎没有游客。这才是真正的缅因州腹地。"},
    {"name":"Sue K","rating":3,"text":"荒野风光迷人，但几乎没有任何设施或服务。砾石路、无手机信号、数英里内没有卫生间。你需要完全自给自足。不适合期望体验成熟国家公园管理局服务的普通游客。"},
    {"name":"J & C","rating":1,"text":"沿着越来越难走的路开了三小时，来到这处所谓的\"纪念地\"，结果什么都没有——没有游客中心，没有护林员站，没有标记的徒步出发点，甚至连厕所都没有。只有树林和一条砾石路。掉头就走了。这个地方完全没有准备好向公众开放。"}],
  "navajo-national-monument": [
    {"name":"SWexplorer","rating":5,"text":"贝塔塔金是西南部最壮观的崖居建筑之一，护林员带领徒步下行的体验令人终生难忘。免费营地拥有绝美的景色，与梅萨维德相比，这里人少得多，是绝佳的替代选择。"},
    {"name":"DAuntDeb","rating":4,"text":"崖顶俯瞰贝塔塔金的观景点免费且令人印象深刻。进入峡谷的导览徒步需要提前预约，有一定体力要求，但十分值得。地处偏远，但设施维护良好。"},
    {"name":"mimastech","rating":2,"text":"我专程来参加贝塔塔金的导览徒步，结果接下来三天都已预订满了。从崖顶观景台看，崖居只是巨大崖壁上一个小小的黑点，不带望远镜根本看不清楚。仅凭峡谷观景点，不值得从任何方向长途驱车而来。"}],
  "pipe-spring-national-monument": [
    {"name":"AZroadtripper","rating":5,"text":"亚利桑那带一处迷人的小型边疆驿站，砌有泉水的堡垒坐落于此。护林员对温莎城堡的讲解精彩绝伦，生动呈现了摩门族拓荒者与凯巴布派尤特人之间复杂的历史关系。"},
    {"name":"gt6243c","rating":3,"text":"历史有趣，但规模非常小。堡垒导览二十分钟，园区逛逛再加十分钟。凯巴布派尤特文化部分增添了深度，但整体景点仍然很小。前往北缘途中顺道停留即可。"},
    {"name":"entropy43","rating":2,"text":"荒郊野外的一座两间房石屋，被称为\"城堡\"。我们因为顺路去大峡谷北缘而停了下来，现在后悔没有直接开过去。博物馆只有一个房间。礼品店比整个纪念地还大。"}],
  "pipestone-national-monument": [
    {"name":"MNnaturelover","rating":5,"text":"印第安人在这里采掘卡特莱尼特岩石已有数百年，是他们的圣地。经过采石场和温尼韦萨瀑布的圆形步道非常美丽。文化中心展示了当地工匠令人赞叹的管道雕刻演示。"},
    {"name":"Hatzlacha","rating":3,"text":"文化景点颇具价值，但规模相当小。环形步道走完约需四十五分钟。游客中心有一些关于管道石雕刻的不错展品。如果你在明尼苏达州西南部，值得顺道一游，但不值得专程前来。"},
    {"name":"JEBtravel2018","rating":2,"text":"对一处国家纪念地的期望有些落空。基本上是草地上一条经过几个采掘坑的步道。我们参观时，所谓的\"瀑布\"细如涓流。文化演示那天也没有进行。最多停留三十分钟。"}],
  "poverty-point-national-monument": [
    {"name":"LAhistory","rating":5,"text":"这处有三千四百年历史的土方建筑群同时也是联合国教科文组织世界遗产。土丘规模宏大，博物馆生动诠释了这些古代建造者精湛的工程技艺。这是北美最重要的考古遗址之一。"},
    {"name":"Brian M","rating":3,"text":"土方建筑规模如此之大，从地面根本无法欣赏其全貌，看起来就像起伏的山丘和田野。博物馆不错，但户外体验差强人意，缺乏俯瞰视角难以感受其震撼。有轨电车导览有所帮助，但土丘看起来仍然像草坡。"},
    {"name":"Ron T","rating":2,"text":"开了两小时车进入路易斯安那州腹地，就为了看一堆长满草的土丘。没有博物馆的解说，根本不会知道这些是古代土方建筑。夏天来这里又热又多蚊子，有轨电车带你看的不过是一片坑洼的旷野。不值得专程来此。"}],
  "russell-cave-national-monument": [
    {"name":"ALcaver","rating":5,"text":"一处迷人的考古遗址，人类在这里居住了一万多年。洞穴庇护所令人印象深刻，护林员关于人类居住历史层叠的讲解引人入胜。阿拉巴马州东北部一处隐藏的瑰宝。"},
    {"name":"Hatzlacha","rating":3,"text":"有趣的洞穴，护林员讲解很好，但你无法进入——只能从栅栏后面观看。步道较短，游客中心也很小。游览约需三十至四十五分钟。驱车穿越阿拉巴马州农村前来，才是真正的探险。"},
    {"name":"amydcrnp","rating":2,"text":"根本进不了洞穴。你只能站在栅栏后面看一处岩石悬挑。所谓的\"步道\"是一条十分钟的铺装小路。游客中心展示了几件箭头和陶器碎片。不值得开车来到阿拉巴马州偏远地区。"}],
  "salinas-pueblo-missions-national-monument": [
    {"name":"NMhistorian","rating":5,"text":"新墨西哥州中部散布着三处普韦布洛人聚落和西班牙传教站遗址。夸莱的红砂岩教堂外墙高耸，是最上镜的地方。普韦布洛人与西班牙殖民历史的交融在这里独一无二。"},
    {"name":"anotheruxguy","rating":4,"text":"阿博和夸莱的遗址令人印象深刻，但格兰基维拉是最为完整的。三处遗址相距甚远，请规划充裕的一整天用于驾车游览。芒廷艾尔的游客中心提供了很好的历史背景。"},
    {"name":"Dillon L","rating":2,"text":"三处地点分散在五十英里空旷的新墨西哥沙漠中。每处都是土坯残墙和地基。没有游客中心的背景知识，不过是一堆石头。我们看完三处，感觉在沉闷的遗址之间驾车奔波，白白浪费了一天。"}],
  "starved-rock": [
    {"name":"ChicagoDayTrip","rating":5,"text":"伊利诺伊州的明珠——十八条峡谷，瀑布飞泻，砂岩峭壁耸立，伊利诺伊河谷尽收眼底。圣路易斯峡谷和法国峡谷是我们的最爱。从芝加哥出发的一日游必选之地。"},
    {"name":"Valerie Darling","rating":3,"text":"公园风景优美，但周末极度拥挤。最受欢迎的峡谷步道变成了徒步者单列排队缓行的长龙。上午十点停车场已满。旅馆价格虚高。春天工作日前往效果最佳。"},
    {"name":"Frugalmama57","rating":2,"text":"名不副实，人满为患。八月的\"瀑布\"只是细细的涓流。步道泥泞，陡峭的木制台阶湿滑危险。旅馆以度假村价格提供州立公园级别的服务。我们走遍中西部，这里实在算不上特别。"}],
  "stonewall-national-monument": [
    {"name":"NYChistory","rating":5,"text":"这是LGBTQ+权利运动和美国公民权利运动的重要历史见证。石墙酒吧对面的克里斯托弗公园是一处安静的沉思之地。周末的护林员导览非常出色。"},
    {"name":"Kevin M","rating":3,"text":"基本上就是一间酒吧（石墙酒吧）和对面一块小公园。没有游客中心——最近的国家公园管理局信息点在炮台公园的克林顿城堡。如果没有导览或背景知识，其实没有什么特别可看的。"},
    {"name":"Jack","rating":2,"text":"原本期待有博物馆或展览空间。什么都没有——就是一间可以路过的酒吧和一个有长凳的公园。没有国家公园管理局的标识，没有展示板，遗址本身也没有任何解说材料。作为\"国家纪念地\"，这处遗址几乎隐而不见。"}],
  "tuzigoot-national-monument": [
    {"name":"AZarchaeology","rating":5,"text":"一处俯瞰弗德谷的西纳瓜人山顶聚落遗址，360度视野开阔。博物馆藏有精美文物，可以进入的重建房间是一大亮点。比道路下方的蒙特祖马城堡人少得多。"},
    {"name":"George A","rating":3,"text":"小型聚落遗址坐落于山丘之上。走上去，看一圈，十五分钟后下来。博物馆比遗址本身更有意思。可轻松与附近的蒙特祖马城堡或死马农场州立公园合并游览。"},
    {"name":"Jim W","rating":2,"text":"与梅萨维德甚至附近的蒙特祖马城堡相比，这里令人失望。山丘上几段崩落的石墙，立有解说牌。所谓的\"全景视野\"其实对着克拉克代尔和一座水泥厂。包括博物馆在内，二十分钟就能看完一切。"}],
  "virgin-islands-coral-reef-national-monument": [
    {"name":"SnorkelFan","rating":5,"text":"巴克岛的水下浮潜步道是国家公园体系中独一无二的体验。跟随编号水下说明牌游览原始珊瑚礁，宛如身处仙境。到处都是海龟、魟鱼和五彩斑斓的鱼群。"},
    {"name":"needham","rating":3,"text":"珊瑚礁美丽，但从圣克罗伊岛前往需要支付昂贵的游船租赁费用。浮潜步道标志牌已经褪色，难以辨认。巴克岛上的海滩不错但偏小。在美属维尔京群岛来说，性价比并不突出。"},
    {"name":"Ken R","rating":2,"text":"花了一百美元乘船前往，却看到一片已大面积白化的珊瑚礁。水下步道标识几乎无法辨认，有一半的珊瑚已经死亡或濒临死亡。船长急着赶去接下一批游客，根本没让我们好好看。花了这么多钱，实在令人失望。"}],
  "waco-mammoth-national-monument": [
    {"name":"TXfamily","rating":5,"text":"韦科就有一处令人叹为观止的冰河时代化石遗址！挖掘大棚里猛犸象骨骼仍埋在泥土中，令人叹为观止。导览讲解节奏恰到好处，内容翔实生动。孩子们惊叹不已。"},
    {"name":"kevan j","rating":3,"text":"有趣，但规模非常小。整个参观就是一栋容纳挖掘遗址的建筑。导览大约三十分钟，看完就没有别的了。室外步道再加十五分钟。适合顺路一停，但不值得专程前来。"},
    {"name":"kleic","rating":2,"text":"不过是一间棚子里的几块埋在地里的骨头。导览是强制性的，内容大多面向学生团体。三十分钟我们就游览完毕。周围的公园是一段不错但平平无奇的河边小径。没有带孩子的成人不值得支付入场费。"}],
  "walnut-canyon-national-monument": [
    {"name":"FlagstaffLocal","rating":5,"text":"岛屿步道让你可以真正走进八百年前的西纳瓜人崖居——你可以透过窗口窥视房间内部，还能触摸到墙壁。峡谷里的黄松林也十分美丽。这是亚利桑那州体验古代居所最棒的地方之一。"},
    {"name":"kevan j","rating":3,"text":"有崖居的岛屿步道很棒，但回来时需要爬两百四十级陡峭台阶。崖缘步道要轻松得多，但只能俯视峡谷。游客中心很小。注意海拔——七千英尺的高度，不少游客爬台阶时会很吃力。"},
    {"name":"Mjchand","rating":2,"text":"如果爬不了台阶（而且台阶非常多），基本上就没有什么可看的了。崖缘观景点距离遥远，崖居几乎看不见。游客中心展览很少。这里应该标明适合哪类体力——对许多游客来说实际上无法无障碍参观。"}],
  "cape-lookout-national-seashore": [
    {"name":"NCbeachlover","rating":5,"text":"连绵数英里未经开发的障壁岛海滩，有野马出没，贝壳品种丰富，还有标志性的卡普洛克特灯塔。渡轮之旅本身就是探险的一部分。记得带齐所有所需物品——岛上什么都没有。"},
    {"name":"hmh717","rating":3,"text":"偏远的美丽海滩，但前往方式复杂且费用不菲。渡轮每人单程超过二十美元，班次有限。岛上没有任何设施——没有厕所、没有饮用水、没有遮阴。请自备一切，包括垃圾袋。"},
    {"name":"ginac3332016","rating":1,"text":"渡轮迟到，渡轮摆渡颠簸，到了之后发现海滩上到处是水母。没有卫生间，没有遮阴，没有地方买水。孩子们叫苦连天。回程渡轮又晚了一小时。我们在等船和坐船上花的时间，比真正在海滩上的时间还多。永远不会再来了。"}],
  "bighorn-canyon-national-recreation-area": [
    {"name":"WYoutdoors","rating":5,"text":"横跨蒙大拿州和怀俄明州的隐藏宝地，拥有壮观的峡谷崖壁、绝佳的垂钓条件，游客极少。沿峡谷边缘驾车前往魔鬼峡谷观景台的景色令人屏息。普赖尔山区有野马出没。"},
    {"name":"Tracy J","rating":3,"text":"峡谷景色不错，但公园实际上被分成了两段，两段之间没有道路相连。从一侧开车到另一侧需要绕行三小时。蒙大拿和怀俄明两侧的设施都十分有限。"},
    {"name":"Queen J","rating":2,"text":"开了好几个小时的车来看一个从观景台几乎都看不到的\"峡谷\"。水面远在山下，观景点就是几个装有护栏的停车场。休闲区一侧有个水库，我们去的时候半干见底，满是淤泥。蚊子多得令人难以忍受。这么偏远，实在不值得。"}],
  "boston-harbor-islands-national-recreation-area": [
    {"name":"BostonLocal22","rating":5,"text":"乔治斯岛和它的南北战争堡垒，是从波士顿市区出发的绝佳一日游。渡轮风景如画，岛上有很棒的野餐区。斯佩克塔克尔岛有最美的海滩和市区天际线视野。"},
    {"name":"Joyce W","rating":4,"text":"适合夏日出游的好选择，可以游览多个岛屿。乔治斯岛和斯佩克塔克尔岛开发最为完善。请仔细查看渡轮时刻表——错过最后一班船就被困在岛上了。记得带好食物，岛上的餐饮选择非常有限。"},
    {"name":"MaineVisitor","rating":3,"text":"我们只有时间游览乔治斯岛。沃伦堡垒很有意思，但状况较差。岛本身很小，除了堡垒和几张野餐桌，没有太多别的可做。渡轮人满为患，而且相对你所得到的而言价格偏高。"},
    {"name":"jennifercr0wley","rating":1,"text":"在多云微风的天气里，渡轮以\"天气原因\"取消。没有退款，只提供另一日期的补偿票。我们是外地游客，根本用不上。整个运营感觉很不靠谱，岛上的体验也不值得这样折腾。"}],
  "george-washington-memorial-parkway": [
    {"name":"DCcommuter","rating":5,"text":"美国最美风景的上下班路。公路沿波托马克河而行，华盛顿特区的纪念碑和河流尽收眼底。弗吉尼亚一侧的大瀑布景区壮观迷人。土耳其跑公园是徒步的隐藏好去处。"},
    {"name":"LSUTraveller","rating":4,"text":"风景优美，沿途有许多值得停留的地方——弗农山庄、大瀑布、罗斯福岛。秋天沿河的枫叶色彩令人叹为观止。只是请不要在早晚高峰期行驶于此。"},
    {"name":"Justacammper","rating":1,"text":"十英里的恐怖之旅。道路狭窄蜿蜒，车速却高达每小时六十英里。并线几乎不可能，路边也没有路肩。鹿随时可能从树丛中跳出来。号称\"风景\"公路，但根本来不及看风景，只能死死抓住方向盘、拼命保命。这是一条伪装成公园的高速公路。"}],
  "lake-meredith-national-recreation-area": [
    {"name":"TXangler","rating":5,"text":"德克萨斯州西部大草原上不错的垂钓和游船去处。湖区周围的峡谷风光，在德克萨斯州这片平坦地区来说出人意料地美丽。全地形车越野区和狩猎季节使这里成为当地人的最爱。"},
    {"name":"WednesdayNightGirl","rating":3,"text":"湖水水位波动剧烈，干旱年份几乎无水可言。我们参观时，所谓的\"湖\"大部分是泥滩，中央只剩一小片水塘。设施老旧，部分船坡道甚至通向干涸的地面。"},
    {"name":"LauraW165","rating":2,"text":"这根本不是什么休闲湖泊——是德克萨斯州中间地带一个干涸的水库。峡谷崖壁还算好看，但没有水可以玩。所谓的\"沙滩\"区域是龟裂的泥地。营地尘土飞扬、风沙弥漫。省省吧，去帕洛杜罗峡谷更值得。"}],
  "obed-wild-and-scenic-river": [
    {"name":"TNpaddler","rating":5,"text":"坎伯兰高原上世界级的攀岩圣地和美丽的划船场所。砂岩峡谷令人叹为观止，游客极少。莉莉布拉夫观景台是必去之处，可以俯瞰河流，垂直落差约二十五米。"},
    {"name":"HikerTN","rating":4,"text":"带有绝佳峡谷俯瞰的一日徒步好去处，\"点步道\"提供了出色的峡谷视野。河流只有在降雨后才可划行，如果你是来划船的，请提前查看水位。游客极少，感觉像是拥有私家峡谷。"},
    {"name":"D V","rating":3,"text":"峡谷景色优美，但进入途径非常有限。大部分河段只有有经验的桨手携带自备装备才能抵达。对于普通游客来说，只有几处观景台和短短的步道。几乎没有任何配套设施。"},
    {"name":"PaddleFail","rating":2,"text":"开了两小时的车来划皮艇，结果发现河流完全无法通行——水位太低。网站上对最低水位要求只字未提。通往河流的徒步小径陡峭，维护也很差。我们参观时，这条\"风景野生河\"不过是泥泞的涓涓细流。"}],
  "ozark-national-scenic-riverways": [
    {"name":"MOcanoer","rating":5,"text":"科伦特河和杰克斯福克河是由泉水汇聚的清澈河流，非常适合划独木舟、乘橡皮圈漂流和游泳。大泉是美国最大的泉水之一。奥扎克的洞穴和峭壁风景绝美。"},
    {"name":"FamilyFloat","rating":4,"text":"适合家庭的温和漂流好去处。沿途有多家运营商提供独木舟和橡皮圈租赁服务。沿途的泉水清凉宜人。工作日前往最佳——周末会有喧嚣的派对人群。"},
    {"name":"Abigale Z","rating":2,"text":"夏季周末简直是混乱的狂欢。喧嚣的橡皮圈漂流队伍大声播放音乐，啤酒罐到处漂浮，河岸上垃圾随处可见。护林员踪影全无。这不是亲近自然的体验——这是河边的嘉年华。"},
    {"name":"Outdoorchick19","rating":1,"text":"砾石滩上铺满了周末派对留下的碎玻璃和垃圾。我们的独木舟在浅滩踩到碎玻璃时破了个洞。租船商毫不在意。这条河正在被派对人群毁掉，国家公园管理局对此不作任何处理。"}],
  "rio-grande-wild-and-scenic-river": [
    {"name":"TXpaddler","rating":5,"text":"在里奥格兰德河上划船穿越圣艾莱娜峡谷是一段永生难忘的经历——一千五百英尺高的石灰岩崖壁在两侧耸立，一边是墨西哥，一边是德克萨斯。真正的荒野，真正的偏远。"},
    {"name":"BigBendFan","rating":4,"text":"穿入圣艾莱娜峡谷的短途徒步是大弯国家公园最精彩的路线之一。涉水过河可能有些棘手，但峡谷窄处景色壮观。记得多带水——地形裸露，烈日难挡。"},
    {"name":"jr","rating":3,"text":"大部分河段水位相当低——我们拖着独木舟在砾石滩上的时间比划行的时间还多。峡谷地段美丽，但短暂。大部分所谓\"风景野生\"的河段，不过是两岸长满灌木的平坦荒漠。"},
    {"name":"DisappointedRafter","rating":2,"text":"花重金报名参加了有导游的漂流，结果因为水位太低，有一半时间在走路拖船。导游承认，上游截水导致现在大部分时间河流都勉强能通行。峡谷风景很美，但\"河流\"体验如今越来越像一条偶尔有水流的干河床了。"}],
  "saint-croix-national-scenic-riverway": [
    {"name":"WIpaddler","rating":5,"text":"中西部最清澈、最美丽的河流之一。上圣克罗伊河是在原始森林中安静独木舟旅行的绝佳之地。沙洲露营体验一流。这是一次真正的荒野划行体验。"},
    {"name":"MNweekender","rating":4,"text":"斯蒂尔沃特附近的下游段更为开发成熟，但仍风景如画。大急流州立公园的地质地貌令人印象深刻。可以将划行与迷人的河边小镇游览相结合。秋叶季节色彩绚烂。"},
    {"name":"FamilyCampers","rating":3,"text":"河流迷人，但夏天独木舟露营营地预订很快就满，而且没有预约制度——先到先得。我们划了好几个小时才在过了几处满员营地后找到一个位置。运营商的接送班车迟到超过一个小时。"},
    {"name":"NotImpressed_WI","rating":2,"text":"就是一条河。一条不错的河，但也只是一条河。\"风景\"的称号让我们期待峡谷或瀑布，结果是穿越树林的平静水流。达勒斯地段是唯一真正令人印象深刻的部分。花了一百五十美元租独木舟，感觉就像在穿越威斯康星州森林的沟渠里划行。"}],
  "adams-national-historical-park": [
    {"name":"HistoryNerd_MA","rating":5,"text":"参观约翰·亚当斯和约翰·昆西·亚当斯两位总统的真实故居——家具、书籍和私人物品全部是原物。藏有一万四千卷典籍的石砌图书馆令人叹为观止。波士顿周边历史爱好者必游之地。"},
    {"name":"NewEnglandTrip","rating":4,"text":"导览精彩，但务必先在游客中心取票，确定参观时间。我们差点因为直接前往故居而错过。景点之间有有轨车接送，十分便利。请留出两至三小时游览时间。"},
    {"name":"Freedom56961780478","rating":3,"text":"故居很有意思，但房间太小，旅游团一涌而入就显得拥挤。导游为了赶上时间表匆匆而过，无法按自己的节奏慢慢参观——一切都需要跟团按时进行。礼品店是唯一可以自由浏览的地方。"},
    {"name":"QuickStopOnly","rating":2,"text":"强制性的有轨车和导览制度让人很沮丧。不能自行前往，需要等候预定时段，乘坐有轨车，随十五人的团队依次参观每栋房屋，再等待下一班有轨车。一次本应简单的故居参观，变成了耗费半天时间的后勤折腾。"}],
  "allegheny-portage-railroad-national-historic-site": [
    {"name":"PArailfan","rating":5,"text":"一段精彩的运输历史——斜面铁路将运河驳船翻越阿利根尼山脉，是工程学的奇迹。柠檬屋酒馆和留存的石制枕木，让人真切感受到1830年代这一成就的时代风貌。"},
    {"name":"HistoryBuff_PA","rating":4,"text":"解说丰富、展览出色的历史遗址，生动呈现了运河和铁路时代。夏季的历史服装演示更让历史跃然眼前。6号引擎房展区是最大亮点。"},
    {"name":"PA_traveler","rating":3,"text":"概念有趣，但留存的物质遗迹并不多——大多是绿草覆盖的斜面小径和石质地基。游客中心的影片是最佳部分。脱离背景知识，你不过是在看一座山坡。"},
    {"name":"RoadTrip2023","rating":2,"text":"面向极为小众受众的历史博物馆。如果你对1830年代运河驳船摆渡系统没有浓厚兴趣，这里会让你昏昏欲睡。所谓的\"斜面\"只是草坡。我们三十分钟就游览完毕，恨不得早点开车离开。"}],
  "andersonville-national-historic-site": [
    {"name":"CivilWarBuff","rating":5,"text":"这是我参观过的最令人揪心的国家公园管理局景点。漫步在一万三千名联邦战俘离世的土地上，令人心碎。国家战俘博物馆内容出色，涵盖了美国所有的武装冲突。国家公墓美丽而令人心疼。"},
    {"name":"GAfamily","rating":4,"text":"重要而保存完好的历史遗址。音频驾车导览非常出色。重建的部分围栏和逃跑隧道，让那段可怕的历史变得真实而触目惊心。请至少留出两小时时间。"},
    {"name":"Harleysis","rating":3,"text":"遗址令人深受震撼，但情绪上令人精疲力竭。战俘博物馆详细覆盖了每一场武装冲突——对于一次参观来说信息量几乎太大。户外监狱遗址大部分是旷野加上标识牌。最适合有特定南北战争或战俘历史兴趣的人。"},
    {"name":"SummerVisitor","rating":2,"text":"令人极度压抑，加上佐治亚州的酷暑，更是雪上加霜。七月在毫无遮阴的露天监狱遗址行走，苦不堪言——也许正是当年的写照，但绝算不上享受。博物馆内容厚重。这绝对不是轻松的家庭出游。如果要来，请选冬季。"}],
  "andrew-johnson-national-historic-site": [
    {"name":"TNhistory","rating":5,"text":"这是了解我们最具争议的19世纪总统的唯一去处。约翰逊从裁缝铺起步的故事令人着迷，故居也保存完好。护林员对他的总统任期和弹劾案的解说客观而深刻，令人回味。"},
    {"name":"USPresidents","rating":4,"text":"一处内容全面的总统历史遗址，包括裁缝铺、两处故居，以及约翰逊裹着美国国旗长眠的墓地。游客中心对重建时期的历史背景介绍得很好。"},
    {"name":"Douglas B","rating":3,"text":"如果你要打卡所有总统遗址，这里必去，否则格林维尔本身并没有什么特别的吸引力。两处故居都很朴素，这段历史也错综复杂。约翰逊并不算令人振奋的历史人物，参观体验难免有些尴尬。"},
    {"name":"JustDriving","rating":2,"text":"从81号州际公路下来休息时顺道拐进来。一间小裁缝铺，一栋朴素的故居，还有山上一座墓地。除非你是总统历史打卡爱好者，没有理由专程开车去田纳西州格林维尔来看这些。"}],
  "appomattox-court-house-national-historical-park": [
    {"name":"CivilWarPilgrim","rating":5,"text":"站在李将军向格兰特将军投降的那个房间里，内心深深震撼。重建的村落非常出色，护林员讲解堪称国家公园管理局中的翘楚。对任何美国历史爱好者而言，这是必游之地。"},
    {"name":"VAweekend","rating":4,"text":"历史村落维护精心，以麦克林故居为核心。书店值得一逛。护林员对投降事件及其历史意义进行了详细的解说。请留出一至两小时。"},
    {"name":"Robin B","rating":3,"text":"重要的历史，但这个村落是复原建筑——原麦克林故居于1893年被拆除，于1948年重建。知道自己身处仿制建筑中，多少削弱了情感上的震撼。周围的建筑都很有趣，但大多是空房间。"},
    {"name":"NotWorthDetour","rating":2,"text":"弗吉尼亚州腹地一座重建的小村落，只有一间著名的房间。走完麦克林故居只需十分钟，其余就是礼品店和空荡荡的建筑。如果你不是铁杆南北战争迷，从林奇堡绕行三十英里并不值得。"}],
  "bents-old-fort-national-historic-site": [
    {"name":"COhistory","rating":5,"text":"一座完整重建的1840年代毛皮贸易驿站，坐落于圣塔菲小径沿线。土坯堡垒令人印象深刻，身着历史服装的讲解员让人仿佛回到一百八十年前。国家公园管理局的精品景点。"},
    {"name":"SantaFeTrailFan","rating":4,"text":"重建细节真实可信——贸易室、厨房和印刷室均按历史原貌陈设。科罗拉多州开阔平原上的地理位置，让人真切感受到边疆生活的孤立与艰辛。"},
    {"name":"RoadTripper_CO","rating":3,"text":"堡垒重建得很好，但地处科罗拉多州东部旷野，周围方圆几英里无任何其他景点。堡垒导览约需一小时。如果你本就在圣塔菲小径路线上，这是一处天然的停留点，否则就是一段大绕路。"},
    {"name":"PlainsBoring","rating":2,"text":"公路旁尘土飞扬的停车场里，一座土坯仿古堡垒。各房间摆放了历史物品，但感觉更像博物馆的沙盘模型，而非真实存在过的地方。身着服装的护林员很友善，但我们三十分钟就看完了。拉洪塔本身也没有别的可去的地方。"}],
  "big-hole-national-battlefield": [
    {"name":"MThistory","rating":5,"text":"美国最令人心痛的战场之一。1877年夜袭睡梦中内兹珀斯族家庭——其中包括妇女和儿童——的历史，在这里得到了有感情、有分量的呈现。战场徒步令人心绪难宁。游客中心的影片会让你落泪。"},
    {"name":"WesternHistory","rating":4,"text":"一处感人而重要的历史遗址，讲述了内兹珀斯族视角的故事。战场保存完好，解说步道出色。极为偏远的比格霍尔山谷环境，更增添了这片土地的肃穆氛围。"},
    {"name":"jimichongaJC","rating":2,"text":"翻越山路开了两小时来到这处极为偏远的战场。游客中心很小，战场是一片平坦的草地加上几块标识牌。如果对内兹珀斯族的历史没有基本了解，这里提供的背景知识远远不够。比格霍尔山谷风景秀丽，但战场本身，就这段路程而言，着实令人失望。"}],
  "boston-african-american-national-historic-site": [
    {"name":"BeanTownHistory","rating":5,"text":"比肯山上的黑人遗产步道是不可错过的波士顿体验。漫步在废奴主义者的故居旁，走进美国现存最古老的黑人教堂建筑——非裔美国人会议厅，令人深受震撼。免费的护林员导览非常精彩。"},
    {"name":"EducatorVisit","rating":4,"text":"设计出色的比肯山步道，展现南北战争前黑人波士顿的历史。非裔美国人会议厅和艾比尔·史密斯学校是最大亮点。建议参加护林员带领的步道导览。"},
    {"name":"BlueDevilOKC","rating":2,"text":"所谓的\"步道\"不过是走在比肯山联排别墅外面看铭牌。大部分建筑不开放参观。非裔美国人会议厅我们去的时候正在装修。没有导览的话，只是在富人区散步，路过一块块铜质标牌。"},
    {"name":"Tammie J","rating":1,"text":"特地赶来参加护林员导览，结果临时取消，毫无预告。游客中心让我们去附近的非裔美国人历史博物馆，那里要收十美元的门票。自行走步道找不着北——标识不清，也没有明确的起点。国家公园管理局体验非常令人失望。"}],
  "brown-v-board-of-education-national-historical-park": [
    {"name":"CivilRightsTrail","rating":5,"text":"这里曾经是标志性最高法院案件的发源地——门罗小学，如今是一座关于学校种族隔离废除的强大博物馆。展览令人动容，建筑本身就是文物。每一位美国人都应该来参观。"},
    {"name":"KSeducator","rating":4,"text":"出色的博物馆，设于原始学校建筑之内。展览不仅涵盖布朗诉教育委员会案，更着眼于争取教育平等的更广泛历程。非常适合学生团体和家庭。护林员热情而博学。"},
    {"name":"AmarilisVos","rating":3,"text":"重要的遗址，但博物馆规模相对较小，大约四十五分钟便可游览完毕。托皮卡本身对游客的吸引力也不大。如果不是顺路经过堪萨斯州，专程绕道来此参观一处规模有限的博物馆，未必值得。"},
    {"name":"JustPassingThru","rating":2,"text":"一间改建成博物馆的单间小学，主题是一个法庭案件。展览文字偏多，互动性不足。孩子十五分钟就坐不住了。建筑本身是最有意思的部分，但不能进入真正的教室。托皮卡也没有别的景点可去。"}],
  "cane-river-creole-national-historical-park": [
    {"name":"LAplantation","rating":5,"text":"奥克兰庄园和玛格诺利亚庄园共同讲述了甘蔗河沿岸克里奥尔文化的复杂历史。建筑、庄园和奴隶住所等附属建筑保存得异常完好。护林员以诚实而有分量的方式呈现了这段沉重的历史。"},
    {"name":"HistoryTraveler","rating":4,"text":"两座美丽的法国克里奥尔庄园，着力讲述包括被奴役者生活在内的完整历史。古橡树成荫的庄园景色如画。比路易斯安那河路的庄园商业气息淡得多。请提前致电确认导览时间。"},
    {"name":"Frances V","rating":1,"text":"两栋庄园主楼均在修缮中，开放状态毫无告知——从什里夫波特开了三小时的车，全白白浪费了。网站上对此只字未提。大门口的护林员递给我们一份宣传册，说可以在庄园内散步，但建筑不对外开放。完全是一趟无功而返的旅程。"}],
  "carl-sandburg-home-national-historic-site": [
    {"name":"NCmountains","rating":5,"text":"科内马拉是卡尔·桑德堡度过生命最后二十二年的美丽山庄。室内导览十分亲切——他的写作桌、书籍和吉他都原封未动地保留着。山羊农场和徒步小径更是额外的惊喜。"},
    {"name":"LiteraryPilgrim","rating":4,"text":"蓝岭山麓一处迷人的文学遗址。就算不熟悉桑德堡的作品，护林员导览也很有意思。山羊棚和山间步道让这里成为愉快的半日游目的地。"},
    {"name":"yesha_phoenix","rating":3,"text":"风景秀丽的老宅，若不了解也不热爱卡尔·桑德堡的诗歌，不过就是一次普通的老宅参观。山羊很可爱，但现在只剩几只了。附近的其他步道入口，其实比这里更适合徒步。"},
    {"name":"larryy2015","rating":2,"text":"山坡上一位诗人的故居。导览不过三十分钟，看着满屋子的书籍和文件。如果你不是桑德堡的信徒，会觉得相当乏味。园区环境适合散步，但弗拉特罗克其他地方有更美的花园和景色。作为旅游目的地，名气大于实际。"}],
};
